def identity_user_id(identity):
    return ((identity or {}).get('user') or {}).get('id')


def identity_workspace_id(identity):
    return ((identity or {}).get('workspace') or {}).get('id') or (identity or {}).get('workspace_id')


def identity_hermes_profile(identity):
    return (identity or {}).get('hermes_profile') or {}


def identity_hermes_profile_name(identity):
    profile = identity_hermes_profile(identity)
    return safe_id(profile.get('profile_name') or '')


def workspace_scope_where(identity, column='workspace_id'):
    if is_admin_identity(identity):
        return '', []
    return f' WHERE {column}=?', [identity_workspace_id(identity)]


def workspace_project_row(r):
    return {'id': r['id'], 'name': r['name'], 'status': r['status'] or 'active', 'description': r['description'] or '', 'summary': r['description'] or '', 'workspace_id': r['workspace_id'], 'owner_user_id': r['owner_user_id'], 'kind': 'workspace', 'source': 'app-db', 'created_at': iso(r['created_at']), 'updated_at': iso(r['updated_at']), 'actions': {'open': 0, 'running': 0, 'blocked': 0, 'done': 0}, 'knowledge': [], 'artifacts': [], 'activity': [], 'risks': [], 'tags': [], 'path': '', 'workspaces': [], 'agents': [], 'automations': [], 'skills': [], 'progress': 0, 'health': 90, 'workspace_count': 0}


def create_workspace_project(identity, payload):
    ensure_auth_tables().close(); wid = identity_workspace_id(identity); uid = identity_user_id(identity)
    if not wid or not uid: return {'ok': False, 'error': 'workspace identity required'}, 401
    now = int(time.time()); pid = safe_id(payload.get('id') or payload.get('name') or f'project-{now}'); name = str(payload.get('name') or pid)
    con = auth_db_connect(); sql = "INSERT OR REPLACE INTO projects (id,workspace_id,owner_user_id,name,status,description,created_at,updated_at) VALUES (?,?,?,?,?,?,coalesce((SELECT created_at FROM projects WHERE workspace_id=? AND id=?),?),?)"
    con.execute(sql, (pid, wid, uid, name, payload.get('status') or 'active', payload.get('description') or payload.get('summary') or '', wid, pid, now, now))
    con.commit(); row = con.execute('SELECT * FROM projects WHERE workspace_id=? AND id=?', (wid, pid)).fetchone(); con.close(); return {'ok': True, 'project': workspace_project_row(row)}, 201


def list_workspace_projects(filters=None, identity=None):
    filters = filters or {}; ensure_auth_tables().close(); con = auth_db_connect(); where, params = workspace_scope_where(identity)
    rows = [workspace_project_row(r) for r in con.execute(f'SELECT * FROM projects{where} ORDER BY updated_at DESC, name', params).fetchall()]
    con.close(); q = (filters.get('q') or [''])[0].strip().lower()
    if q: rows = [r for r in rows if q in text_blob(r.get('id'), r.get('name'), r.get('description'))]
    return {'projects': rows, 'summary': {'total': len(rows), 'active': sum(1 for r in rows if r.get('status') == 'active'), 'open_actions': 0, 'blocked': 0, 'knowledge': 0, 'workspaces': len(rows)}, 'kinds': ['workspace'], 'project_areas': [], 'sources': []}


def workspace_task_row(r):
    return {'id': r['id'], 'workspace_id': r['workspace_id'], 'project_id': r['project_id'], 'title': r['title'], 'body': r['body'] or '', 'status': normalize_task_status(r['status'] or 'todo'), 'assignee': r['assignee'] or '', 'created_by': r['created_by'] or '', 'created_at': iso(r['created_at']), 'updated_at': iso(r['updated_at']), 'tenant': r['project_id'], 'priority': 20, 'comments': [], 'events': [], 'runs': [], 'children': [], 'parents': []}


def create_workspace_task(identity, payload):
    ensure_auth_tables().close(); wid = identity_workspace_id(identity); uid = identity_user_id(identity)
    if not wid: return {'ok': False, 'error': 'workspace identity required'}, 401
    now = int(time.time()); tid = safe_id(payload.get('id') or payload.get('title') or f'task-{now}')
    con = auth_db_connect(); sql = "INSERT OR REPLACE INTO workspace_tasks (id,workspace_id,project_id,title,body,status,assignee,created_by,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,coalesce((SELECT created_at FROM workspace_tasks WHERE workspace_id=? AND id=?),?),?)"
    con.execute(sql, (tid, wid, payload.get('project_id'), payload.get('title') or tid, payload.get('body') or '', normalize_task_status(payload.get('status') or 'todo'), payload.get('assignee') or '', uid or 'user', wid, tid, now, now))
    con.commit(); row = con.execute('SELECT * FROM workspace_tasks WHERE workspace_id=? AND id=?', (wid, tid)).fetchone(); con.close(); return {'ok': True, 'task': workspace_task_row(row)}, 201


def list_workspace_tasks(filters=None, identity=None):
    filters = filters or {}; ensure_auth_tables().close(); con = auth_db_connect(); where, params = workspace_scope_where(identity)
    rows = [workspace_task_row(r) for r in con.execute(f'SELECT * FROM workspace_tasks{where} ORDER BY updated_at DESC, title', params).fetchall()]
    con.close(); q = (filters.get('q') or [''])[0].strip().lower(); project = ((filters.get('project') or filters.get('tenant') or [''])[0]).strip().lower()
    if q: rows = [r for r in rows if q in text_blob(r.get('id'), r.get('title'), r.get('body'), r.get('assignee'))]
    if project: rows = [r for r in rows if project == (r.get('project_id') or '').lower()]
    lanes = {'triage': [], 'todo': [], 'scheduled': [], 'ready': [], 'running': [], 'blocked': [], 'error': [], 'review': [], 'done': []}
    for r in rows: lanes.setdefault(r['status'], []).append(r)
    projects = sorted({r.get('project_id') for r in rows if r.get('project_id')})
    return {'tasks': rows, 'lanes': lanes, 'summary': {'total': len(rows), 'triage': len(lanes.get('triage', [])), 'todo': len(lanes.get('todo', [])), 'scheduled': len(lanes.get('scheduled', [])), 'ready': len(lanes.get('ready', [])), 'running': len(lanes.get('running', [])), 'blocked': len(lanes.get('blocked', [])), 'error': len(lanes.get('error', [])), 'review': len(lanes.get('review', [])), 'done': len(lanes.get('done', [])), 'assignees': sorted({r['assignee'] for r in rows if r.get('assignee')}), 'projects': projects}, 'statuses': ['triage','todo','scheduled','ready','running','blocked','error','review','done'], 'projects': projects}


