def create_workspace_inbox_item(identity, payload):
    ensure_auth_tables().close(); wid = identity_workspace_id(identity)
    if not wid: return {'ok': False, 'error': 'workspace identity required'}, 401
    now = int(time.time()); iid = safe_id(payload.get('id') or payload.get('title') or f'inbox-{now}')
    con = auth_db_connect(); sql = "INSERT OR REPLACE INTO workspace_inbox (id,workspace_id,title,body,status,risk,agent_id,created_at,updated_at) VALUES (?,?,?,?,?,?,?,coalesce((SELECT created_at FROM workspace_inbox WHERE workspace_id=? AND id=?),?),?)"
    con.execute(sql, (iid, wid, payload.get('title') or iid, payload.get('body') or payload.get('description') or '', payload.get('status') or 'drafted', payload.get('risk') or 'medium', payload.get('agent_id'), wid, iid, now, now))
