    return {'sessions': 0, 'cost': 0.0, 'tokens': 0, 'input_tokens': 0, 'output_tokens': 0, 'cache_read_tokens': 0, 'cache_write_tokens': 0, 'reasoning_tokens': 0, 'tool_calls': 0, 'api_calls': 0}


