def workflow_routine_as_automation_record(routine):
    routine = routine or {}
    run_status = routine.get('run_status') or routine.get('status') or 'idle'
    enabled = (routine.get('trigger_status') or 'enabled') in ('enabled', 'ready', 'scheduled') and routine.get('status') == 'active'
    last_run = routine.get('last_run') if isinstance(routine.get('last_run'), dict) else None
    connector_deps = routine.get('connector_dependencies') or []
    approval_dependency = routine.get('approval_policy_dependency') or {}
    quota_policy = routine.get('quota_policy') or {}
    return {
        'id': routine.get('id'),
        'name': routine.get('name') or routine.get('id'),
        'enabled': enabled,
        'state': run_status,
        'status': 'paused' if run_status == 'paused' else 'error' if run_status == 'blocked' else 'enabled' if enabled else 'paused',
        'schedule': routine.get('schedule') or 'policy-gated manual/admin routine',
        'schedule_kind': 'admin-routine',
        'next_run_at': routine.get('next_run_at') or '—',
        'next_run_relative': 'policy gated',
        'last_run_at': (last_run or {}).get('started_at') or '—',
        'last_run_relative': (last_run or {}).get('started_at') or '—',
        'last_status': run_status,
        'last_error': (last_run or {}).get('reason') if run_status in ('blocked', 'paused') else None,
        'deliver': 'mission-control-admin',
        'origin': 'workflow-routine-admin',
        'skills': [],
        'skill_count': 0,
        'enabled_toolsets': [],
        'model': None,
        'provider': None,
        'script': None,
        'no_agent': False,
        'context_from': [],
        'workdir': None,
        'profile': routine.get('agent_id') or 'devops',
        'repeat_times': None,
        'repeat_completed': 0,
        'created_at': routine.get('created_at') or '',
        'prompt_preview': f"{routine.get('routine_type', 'workspace')} routine · connector deps: {len(connector_deps)} · approval: {approval_dependency.get('decision') or approval_dependency.get('mode') or 'policy'} · quota: {'configured' if quota_policy else 'none'}",
        'recent_runs': [],
        'recent_outputs': [],
        'run_count': 1 if last_run else 0,
        'workflow_template_id': 'workflow-routine-admin',
        'workflowName': 'Workflow Routine Admin',
        'sourceOfTruth': 'runtime connector governance database',
        'routine_type': routine.get('routine_type'),
        'workspace_id': routine.get('workspace_id'),
        'owner_user_id': routine.get('owner_user_id'),
        'runtime_id': routine.get('runtime_id'),
        'agent_id': routine.get('agent_id'),
        'agent_class': routine.get('agent_class'),
        'connector_dependencies': connector_deps,
        'approval_policy_dependency': approval_dependency,
        'quota_impact': routine.get('quota_impact') or {},
        'quota_policy': quota_policy,
        'run_status': run_status,
        'last_run': last_run,
        'run_detail_url': routine.get('run_detail_url') or (last_run or {}).get('run_detail_url'),
    }


def list_automations(filters=None, identity=None):
    filters = filters or {}
    rows = []
    error = None
    if CRON_JOBS.exists():
        try:
            data = json.loads(CRON_JOBS.read_text(errors='ignore'))
            jobs = data.get('jobs', [])
            rows.extend(automation_row(j) for j in jobs)
        except Exception as e:
            error = str(e)
    else:
        error = 'cron jobs.json not found'
    routine_payload = list_workflow_routines(identity, filters) if identity else {'routines': []}
    rows.extend(workflow_routine_as_automation_record(r) for r in routine_payload.get('routines') or [])
    q = (filters.get('q') or [''])[0].strip().lower()
    state = (filters.get('state') or [''])[0].strip().lower()
    if q:
        rows = [r for r in rows if q in ' '.join([str(r.get('name','')), str(r.get('id','')), str(r.get('schedule','')), str(r.get('prompt_preview','')), str(r.get('routine_type','')), ' '.join(r.get('skills') or [])]).lower()]
    if state:
        if state == 'enabled':
            rows = [r for r in rows if r['enabled']]
        elif state == 'paused':
            rows = [r for r in rows if not r['enabled'] or r['status'] == 'paused' or r.get('run_status') == 'paused']
        elif state == 'error':
            rows = [r for r in rows if r['status'] == 'error' or r.get('run_status') == 'blocked']
        elif state == 'script':
            rows = [r for r in rows if r['no_agent'] or r['script']]
        elif state in ROUTINE_TYPES:
            rows = [r for r in rows if r.get('routine_type') == state]
    rows.sort(key=lambda r: (r['next_run_at'] == '—', r['next_run_at'], r['name']))
    summary = {
        'total': len(rows),
        'enabled': sum(1 for r in rows if r['enabled']),
        'paused': sum(1 for r in rows if not r['enabled'] or r['status'] == 'paused'),
        'error': sum(1 for r in rows if r['status'] == 'error' or r.get('run_status') == 'blocked'),
        'no_agent': sum(1 for r in rows if r['no_agent']),
        'governed': sum(1 for r in rows if r.get('workflow_template_id') == 'workflow-routine-admin'),
        'platform': sum(1 for r in rows if r.get('routine_type') == 'platform'),
        'workspace': sum(1 for r in rows if r.get('routine_type') == 'workspace'),
        'personal': sum(1 for r in rows if r.get('routine_type') == 'personal'),
    }
    out = {'automations': rows, 'summary': summary, 'states': ['enabled', 'paused', 'error', 'script', 'platform', 'workspace', 'personal'], 'workflow_routines': routine_payload.get('routines') or [], 'routine_summary': routine_payload.get('summary') or {'total': 0}}
    if error:
        out['error'] = error
    return out


def read_cron_jobs_data():
    if not CRON_JOBS.exists():
        return {'jobs': [], 'updated_at': time.time()}
    try:
        data = json.loads(CRON_JOBS.read_text(errors='ignore'))
    except Exception:
        data = {'jobs': []}
    if not isinstance(data, dict):
        data = {'jobs': []}
    if not isinstance(data.get('jobs'), list):
        data['jobs'] = []
    return data


def write_cron_jobs_data(data):
    CRON_JOBS.parent.mkdir(parents=True, exist_ok=True)
    data['updated_at'] = time.time()
    tmp = CRON_JOBS.with_suffix(CRON_JOBS.suffix + '.tmp')
    tmp.write_text(json.dumps(data, indent=2, sort_keys=True))
    tmp.replace(CRON_JOBS)
    return data


def website_funnel_cron_job_from_routine(routine, approval):
    routine = routine or {}
    approval = approval or {}
    jid = safe_id(routine.get('id') or 'website-funnel-check')
    schedule_expr = str(routine.get('schedule') or routine.get('schedule_display') or '0 9 * * 1').strip()
    command = str(routine.get('command') or f"python3 source/scripts/browser_funnel_check_job.py --config {routine.get('configPath') or ''}").strip()
    now = time.time()
    prompt = '\n'.join([
        'Run the scheduled Website Funnel Check routine with NO_SUBMIT enforced.',
        f"Target URL: {routine.get('targetUrl')}",
        f"Schedule: {schedule_expr}",
        f"Command: {command}",
        'Execute only the configured safe public target. Do not submit forms. Preserve Browser Activity, screenshot, final URL, and Task Board evidence. Leave submit/post/send/purchase boundaries blocked for approval.',
    ])
    metadata = dict(routine.get('metadata') or {})
    metadata.update({
        'workflow_template_id': 'website-funnel-check',
        'targetUrl': routine.get('targetUrl'),
        'noSubmit': True,
        'safeTargetRequired': True,
        'command': command,
        'configPath': routine.get('configPath'),
        'latestRunStatus': routine.get('latestRunStatus') or {'status': 'not-run', 'lastRunAt': None},
        'evidenceHistory': routine.get('evidenceHistory') or [],
        'enabledBy': approval.get('approvedBy') or approval.get('operator') or 'operator',
        'enableApproval': {'approved': True, 'approvedBy': approval.get('approvedBy') or approval.get('operator') or 'operator', 'note': approval.get('note'), 'approvedAt': iso(now)},
    })
    return {
        'id': jid,
        'name': routine.get('name') or f"Website Funnel Check · {routine.get('project') or jid}",
        'prompt': prompt,
        'skills': [],
        'skill': None,
        'model': None,
        'provider': None,
        'base_url': None,
        'script': routine.get('script') or 'browser_funnel_check_job.py',
        'no_agent': True,
        'context_from': [],
        'schedule': {'kind': 'cron', 'expr': schedule_expr, 'display': schedule_expr},
        'schedule_display': schedule_expr,
        'repeat': {'times': None, 'completed': 0},
        'enabled': True,
        'state': 'scheduled',
        'paused_at': None,
        'paused_reason': None,
        'created_at': now,
        'next_run_at': None,
        'last_run_at': None,
        'last_status': 'not-run',
        'last_error': None,
        'last_delivery_error': None,
        'deliver': 'local',
        'origin': None,
        'enabled_toolsets': ['browser', 'terminal'],
        'workdir': str(APP_ROOT / 'source'),
        'profile': 'default',
        'metadata': metadata,
    }


def enable_website_funnel_routine(routine, approval=None):
    approval = approval or {}
    if not approval.get('approved'):
        return {'ok': False, 'error': 'explicit operator approval is required before enabling a scheduled Website Funnel Check routine'}, 403
    if not isinstance(routine, dict) or routine.get('workflow_template_id') != 'website-funnel-check':
        return {'ok': False, 'error': 'invalid Website Funnel Check routine binding'}, 400
    if routine.get('noSubmit') is not True or routine.get('safeTargetRequired') is not True:
        return {'ok': False, 'error': 'NO_SUBMIT and safeTargetRequired safeguards are mandatory'}, 400
    job = website_funnel_cron_job_from_routine(routine, approval)
    data = read_cron_jobs_data()
    jobs = data.get('jobs') or []
    replaced = False
    for idx, existing in enumerate(jobs):
        if existing.get('id') == job['id']:
            existing_created = existing.get('created_at')
            job['created_at'] = existing_created or job['created_at']
            jobs[idx] = {**existing, **job}
            replaced = True
            break
    if not replaced:
        jobs.append(job)
    data['jobs'] = jobs
    write_cron_jobs_data(data)
    return {'ok': True, 'action': 'enable_funnel_routine', 'job': job, 'created': not replaced}, 200 if replaced else 201

