def job_for_funnel_target(target_id):
    target_id = safe_id(target_id)
    data = read_cron_jobs_data()
    for job in data.get('jobs') or []:
        metadata = job.get('metadata') if isinstance(job.get('metadata'), dict) else {}
        if metadata.get('targetRegistryId') == target_id:
            return job
    return None


def target_evidence_links(target):
    history = target.get('evidenceHistory') or []
    screenshot = None
    browser_url = None
    task_url = None
    final_url = None
    for item in history:
        if not isinstance(item, dict):
            continue
        title = str(item.get('title') or '').lower()
        url = item.get('url')
        path = item.get('path')
        if not screenshot and (path or url) and ('screenshot' in title or str(path or url).lower().endswith(('.png', '.jpg', '.jpeg', '.webp'))):
            screenshot = {'title': item.get('title') or 'Latest screenshot', 'path': path, 'url': url, 'createdAt': item.get('createdAt')}
        if not browser_url and isinstance(url, str) and ('view=browser-ops' in url or 'session=' in url):
            browser_url = url
        if not task_url and isinstance(url, str) and ('view=board' in url or 'task=' in url or 'task-result' in url):
            task_url = url
        if isinstance(url, str) and re.match(r'^https?://', url):
            final_url = url
    return screenshot, browser_url, task_url, final_url


