def redact_connector_credentials(payload):
    credentials = {}
    nested = payload.get('credentials') if isinstance(payload.get('credentials'), dict) else {}
    for key in ('apiKey', 'token', 'clientSecret', 'password'):
        if payload.get(key) or nested.get(key):
            credentials[key] = '[REDACTED]'
    return credentials or {'apiKey': '[REDACTED]'}


def browser_connector_readiness(connector):
    approved = connector.get('approvalStatus') == 'approved'
    dry = connector.get('dryRun') if isinstance(connector.get('dryRun'), dict) else {}
    dry_ok = dry.get('status') in ('simulated', 'passed')
    last_probe = connector.get('lastProbe') if isinstance(connector.get('lastProbe'), dict) else {}
    phase21_probe_ok = last_probe.get('status') in ('blocked_before_submit', 'completed_no_form_submit_boundary') and last_probe.get('noSubmit') is True
    return [
        {'label': 'Connector type selected', 'status': 'ready' if connector.get('type') else 'blocked', 'detail': connector.get('type') or 'choose Browserbase, desktop-browser, or future Windows gateway'},
        {'label': 'Secrets redacted', 'status': 'ready', 'detail': 'Stored connector payloads expose [REDACTED] only.'},
        {'label': 'Explicit operator approval', 'status': 'ready' if approved else 'blocked', 'detail': (connector.get('approval') or {}).get('approvedBy') or 'approval required before enablement'},
        {'label': 'Dry-run connectivity test', 'status': 'ready' if dry_ok else 'blocked', 'detail': dry.get('summary') or 'dry-run probe required before production connector enablement'},
        {'label': 'Desktop-browser dry-run probe', 'status': 'ready' if phase21_probe_ok else ('warning' if connector.get('type') != 'desktop-browser' else 'blocked'), 'detail': last_probe.get('summary') or 'Run a safe public NO_SUBMIT probe before connector enablement.'},
        {'label': 'NO_SUBMIT locked', 'status': 'ready' if connector.get('noSubmit') is True else 'blocked', 'detail': 'Website Funnel Check remains no-submit by default.'},
        {'label': 'Connector enabled', 'status': 'ready' if connector.get('enabled') is True else 'blocked', 'detail': 'No real connector is enabled yet.'},
    ]


def normalize_browser_connector(payload, existing=None):
    existing = existing or {}
    ctype = str(payload.get('type') or existing.get('type') or '').strip().lower()
    allowed = {'browserbase', 'desktop-browser', 'windows-gateway'}
    if ctype not in allowed:
        return None, 'connector type must be browserbase, desktop-browser, or windows-gateway'
    cid = safe_id(payload.get('id') or existing.get('id') or f'{ctype}-{payload.get("label") or ctype}')
    label = str(payload.get('label') or existing.get('label') or ctype.replace('-', ' ').title())[:120]
    approved = bool(payload.get('approved') or existing.get('approvalStatus') == 'approved')
    connector = dict(existing)
    connector.update({
        'id': cid,
        'type': ctype,
        'label': label,
        'baseUrl': str(payload.get('baseUrl') or existing.get('baseUrl') or '').strip(),
        'enabled': False,
        'approvalStatus': 'approved' if approved else 'needs-approval',
        'approval': existing.get('approval') or ({'status': 'approved', 'approvedBy': payload.get('approvedBy') or 'operator', 'approvedAt': iso(time.time())} if approved else {}),
        'credentials': redact_connector_credentials(payload),
        'projectId': payload.get('projectId') or existing.get('projectId'),
        'noSubmit': True,
        'safeTargetRequired': True,
        'accountSensitiveAllowed': False,
        'updatedAt': iso(time.time()),
    })
    if payload.get('dryRun') or existing.get('dryRun'):
        connector['dryRun'] = payload.get('dryRun') or existing.get('dryRun')
    connector['readinessChecklist'] = browser_connector_readiness(connector)
    return connector, None


