def enrich_browser_connector(connector):
    connector = dict(connector)
    connector['credentials'] = {k: '[REDACTED]' for k in (connector.get('credentials') or {'apiKey': '[REDACTED]'})}
    connector['enabled'] = False if connector.get('enabled') is not True else True
    connector['probeHistory'] = [dict(item) for item in (connector.get('probeHistory') or []) if isinstance(item, dict)]
    connector['readinessChecklist'] = browser_connector_readiness(connector)
    return connector


def upsert_browser_connector_config(payload):
    data = read_browser_connectors_data()
    connectors = [c for c in data.get('connectors', []) if isinstance(c, dict)]
    existing = next((c for c in connectors if c.get('id') == safe_id(payload.get('id') or '')), None)
    connector, error = normalize_browser_connector(payload, existing)
    if error:
        return {'ok': False, 'error': error}, 400
    replaced = False
    for idx, item in enumerate(connectors):
        if item.get('id') == connector.get('id'):
            connectors[idx] = connector
            replaced = True
            break
    if not replaced:
        connectors.append(connector)
    data['connectors'] = connectors
    write_browser_connectors_data(data)
    return {'ok': True, 'connector': enrich_browser_connector(connector), 'created': not replaced}, 200 if replaced else 201


