    connectors = [enrich_browser_connector(c) for c in read_browser_connectors_data().get('connectors', []) if isinstance(c, dict)]
    return {
        'connectors': connectors,
        'summary': {'total': len(connectors), 'approved': sum(1 for c in connectors if c.get('approvalStatus') == 'approved'), 'enabled': sum(1 for c in connectors if c.get('enabled') is True), 'needs_approval': sum(1 for c in connectors if c.get('approvalStatus') != 'approved')},
        'productionPolicy': browser_production_policy_payload(),
        'browserTrackCompletion': browser_track_completion_payload(),
    }


