    if q:
        targets = [t for t in targets if q in ' '.join([t.get('id',''), t.get('label',''), t.get('url',''), t.get('project',''), t.get('approvalStatus','')]).lower()]
    targets.sort(key=lambda t: (t.get('approvalStatus') != 'needs-review', t.get('label') or t.get('id')))
    return {'targets': targets, 'summary': {'total': len(targets), 'approved': sum(1 for t in targets if t.get('approvalStatus') == 'approved'), 'enabled': sum(1 for t in targets if t.get('routineEnabled')), 'needs_review': sum(1 for t in targets if t.get('approvalStatus') != 'approved')}}


