def set_cron_job_enabled(job_id, enabled):
    data = read_cron_jobs_data()
    changed = False
    for job in data.get('jobs') or []:
        if job.get('id') == job_id:
            job['enabled'] = bool(enabled)
            job['state'] = 'scheduled' if enabled else 'paused'
            job['paused_at'] = None if enabled else time.time()
            changed = True
            break
    if changed:
        write_cron_jobs_data(data)
    return changed


def funnel_target_action(target_id, payload):
    target_id = safe_id(target_id)
    targets = read_funnel_targets_index()
    target = targets.get(target_id)
    if not target:
        return {'ok': False, 'error': 'funnel target not found'}, 404
    action = str(payload.get('action') or '').strip().lower()
    if action == 'enable':
        if target.get('approvalStatus') != 'approved' and not payload.get('approved'):
            return {'ok': False, 'error': 'target approval is required before enabling routine'}, 403
        routine = funnel_target_to_routine_binding(target)
        result, status = enable_website_funnel_routine(routine, {'approved': True, 'approvedBy': payload.get('approvedBy') or target.get('approval', {}).get('approvedBy') or 'operator', 'note': payload.get('note')})
        if result.get('ok'):
            target['routineEnabled'] = True
            target['latestRunStatus'] = {'status': 'enabled', 'lastRunAt': None, 'summary': 'Routine enabled; waiting for next run.'}
            save_funnel_target(target)
            result['target'] = enrich_funnel_target(target)
        return result, status
    if action == 'pause':
        changed = set_cron_job_enabled(target.get('routineId'), False)
        target['routineEnabled'] = False
        target['latestRunStatus'] = {'status': 'paused', 'lastRunAt': None, 'summary': 'Routine paused by operator.'}
        save_funnel_target(target)
        return {'ok': True, 'action': 'pause', 'changed': changed, 'target': enrich_funnel_target(target)}, 200
    if action == 'run_now':
        if not payload.get('dryRunConfirmed'):
            return {'ok': False, 'error': 'run_now requires dry-run confirmation before queueing a no-submit browser check'}, 403
        target['latestRunStatus'] = {'status': 'queued-manual-run', 'lastRunAt': iso(time.time()), 'summary': 'Manual dry-run requested; NO_SUBMIT remains mandatory.'}
        target['runNowConfirmation'] = {'dryRunConfirmed': True, 'confirmedBy': payload.get('approvedBy') or payload.get('confirmedBy') or 'operator', 'confirmedAt': iso(time.time()), 'mode': 'Dry-run only / NO_SUBMIT'}
        target['evidenceHistory'] = [{'title': 'Manual dry-run requested', 'summary': 'Operator requested run-now from target registry. The no-submit browser job remains approval-gated.', 'createdAt': iso(time.time())}] + (target.get('evidenceHistory') or [])
        save_funnel_target(target)
        return {'ok': True, 'action': 'run_now', 'target': enrich_funnel_target(target)}, 200
    return {'ok': False, 'error': 'invalid funnel target action'}, 400



def approvals_connect():
    APPROVALS_DB.parent.mkdir(parents=True, exist_ok=True)
    con = sqlite3.connect(APPROVALS_DB, timeout=5)
    con.row_factory = sqlite3.Row
    return con


def ensure_approvals_tables():
    con = approvals_connect()
    con.executescript("""
    CREATE TABLE IF NOT EXISTS approvals (
        id TEXT PRIMARY KEY,
        title TEXT NOT NULL,
        description TEXT,
        body TEXT,
        kind TEXT NOT NULL DEFAULT 'draft',
        status TEXT NOT NULL DEFAULT 'drafted',
        risk TEXT NOT NULL DEFAULT 'medium',
        source TEXT,
        source_id TEXT,
        source_path TEXT,
        destination TEXT,
        agent_id TEXT,
        agent_name TEXT,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL,
        reviewed_at INTEGER,
        decision_note TEXT,
        metadata TEXT
    );
    """)
    con.commit()
    return con


def load_cron_jobs_map():
    if not CRON_JOBS.exists():
        return {}
    try:
        data = json.loads(CRON_JOBS.read_text(errors='ignore'))
        return {j.get('id'): j for j in data.get('jobs', []) if j.get('id')}
    except Exception:
        return {}


def cron_output_requires_human_review(raw, job):
    """Return (requires_review, risk, reason) for a cron output.

    Mission Control should not turn every routine transcript or silent
    watchdog tick into a human approval. Only create approval cards when the
    output asks for a decision, proposes an external action, or reports a
    blocking/error state that needs intervention.
    """
    raw_text = raw or ''
    # Cron markdown includes the original prompt/skill text; do not classify
    # that as an approval request. Prefer the agent's final response/output.
    review_text = raw_text
    for marker in ('\n## Response\n', '\n## Final Response\n', '\n## Output\n'):
        if marker in raw_text:
            review_text = raw_text.split(marker, 1)[1]
            break
    text = review_text.lower()
    name = (job.get('name') or '').lower()
    prompt = (job.get('prompt') or '').lower()
    destination = job.get('deliver') or job.get('origin') or 'origin'
    metadata = job.get('metadata') if isinstance(job.get('metadata'), dict) else {}

    if metadata.get('approval_required') is True or job.get('approval_required') is True:
        return True, 'high', 'job marked approval_required'

    # Cron writes wrapper files even for no-agent scripts with empty stdout.
    # These are health/audit records, not human decisions.
    if '**status:** silent (empty output)' in text or 'status: silent (empty output)' in text:
        return False, 'low', 'silent cron tick'

    explicit_markers = [
        'approval required', 'needs approval', 'awaiting approval', 'requires approval',
        'review required', 'please approve', 'approve before', 'human approval',
    ]
    if any(marker in text for marker in explicit_markers):
        return True, 'high', 'explicit approval marker'

    blocking_markers = [
        'status: blocked', 'blocked by', 'blocked on', 'blocked because',
        'failed', 'failure', 'error:', 'exception', 'traceback',
        'auth required', 'login required', 'permission denied', 'rate limit',
    ]
    if any(marker in text for marker in blocking_markers):
        return True, 'high', 'blocked/error output'

    outbound_markers = [
        'proposed outbound', 'draft message', 'draft email', 'draft reply',
        'draft comment', 'draft dm', 'proposed post', 'ready to publish',
        'ready to send', 'send this', 'publish this', 'post this', 'schedule this',
    ]
    if any(marker in text for marker in outbound_markers):
        return True, 'high', 'proposed external action'

    # Jobs delivered to the current chat/origin/local are usually operator
    # reports. Jobs delivered externally are still only approvals if the
    # content asks for a decision; otherwise they are just notifications.
    if destination not in ('local', 'origin', None, '') and any(word in name or word in prompt for word in ('publish', 'autopublish', 'send email', 'outbound')):
        return True, 'high', 'external publishing workflow'

    return False, 'low', 'routine output'


def cron_output_is_attention_task(raw, job, review_reason):
    """Human attention is not the same as approval.

    Approval cards are for decisions that unblock an agent from doing an
    external/irreversible action. Alerts, emails to review, failures, and access
    issues should land on the task board as operator attention items instead of
    presenting an Approve/Reject choice.
    """
    raw_text = (raw or '').lower()
    name = (job.get('name') or '').lower()
    prompt = (job.get('prompt') or '').lower()
    text = ' '.join([raw_text, name, prompt, review_reason or ''])
    attention_markers = [
        'email-immediate-attention', 'immediate-attention email', 'email alert',
        'review email', 'unread', 'inbox monitoring', 'needs attention',
        'money / payment risk', 'payment failed', 'card payment failed',
        'blocked/error output', 'auth required', 'login required', 'permission denied',
        'rate limit', 'traceback', 'exception', 'status: blocked',
    ]
    return any(marker in text for marker in attention_markers)


def create_attention_task_from_cron_output(path, raw, job, risk, review_reason):
    ensure_kanban_tables().close()
    job_id = path.parent.name
    digest = hashlib.sha1(str(path).encode('utf-8')).hexdigest()[:16]
    task_id = f'attention-cron-output-{digest}'
    created_at = int(path.stat().st_mtime)
    now = int(time.time())
    name = job.get('name') or job_id
    priority = 85 if risk in ('high', 'critical') else 60
    title = f'Attention needed: {name}'
    tenant = f'cron:{job_id}'
    idempotency_key = f'attention-cron-output:{job_id}'
    body = (
        'This item was routed to the Task Board because it needs operator attention, '
        'not an Approve/Reject decision.\n\n'
        f'Why: {review_reason}\n'
        f'Source job: {name} ({job_id})\n'
        f'Cron output: {path}\n\n'
        f'{preview_content(raw, 5000)}'
    )
    con = kanban_connect(False)
    try:
        if con.execute('SELECT 1 FROM tasks WHERE id=?', (task_id,)).fetchone():
            return False
        open_existing = con.execute('''
            SELECT id FROM tasks
            WHERE (idempotency_key=? OR (tenant=? AND title=?))
              AND lower(coalesce(status, '')) NOT IN ('done', 'archived')
            ORDER BY created_at DESC
            LIMIT 1
        ''', (idempotency_key, tenant, title)).fetchone()
        if open_existing:
            existing_id = open_existing['id']
            con.execute('''UPDATE tasks
                SET body=?, priority=max(coalesce(priority, 0), ?), idempotency_key=coalesce(idempotency_key, ?)
                WHERE id=?''', (body, priority, idempotency_key, existing_id))
            con.execute('INSERT INTO task_comments(task_id,author,body,created_at) VALUES (?,?,?,?)', (
                existing_id, 'mission-control-attention-router',
                f'Deduped repeated cron attention output for {name} ({job_id}); latest output: {path}; reason: {review_reason}',
                now,
            ))
            con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                        (existing_id, None, 'deduped_cron_attention_output', json.dumps({'source':'cron-output-attention-router', 'cron_output': str(path), 'review_reason': review_reason, 'job_id': job_id}), now))
            con.commit()
            return False
        con.execute('''INSERT INTO tasks
            (id,title,body,assignee,status,priority,created_by,created_at,started_at,completed_at,workspace_kind,workspace_path,tenant,skills,model_override,session_id,idempotency_key)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)''', (
            task_id, title, body, 'Melverick', 'queued', priority,
            'mission-control-attention-router', created_at, None, None, 'scratch', None,
            tenant, json.dumps([]), None, None, idempotency_key
        ))
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                    (task_id, None, 'created', json.dumps({'source':'cron-output-attention-router', 'cron_output': str(path), 'review_reason': review_reason, 'job_id': job_id}), now))
        con.commit()
        return True
    finally:
        con.close()


def sync_cron_outputs_to_inbox(con):
    output_root = HERMES_HOME / 'cron' / 'output'
    if not output_root.exists():
        return 0
    jobs = load_cron_jobs_map()
    files = sorted(output_root.glob('*/*.md'), key=lambda p: p.stat().st_mtime if p.exists() else 0, reverse=True)[:60]
    created = 0
    now = int(time.time())
    for path in files:
        try:
            raw = path.read_text(errors='ignore').strip()
        except Exception:
            continue
        if not raw:
            continue
        job_id = path.parent.name
        digest = hashlib.sha1(str(path).encode('utf-8')).hexdigest()[:16]
        item_id = f'cron-output-{digest}'
        if con.execute('SELECT 1 FROM approvals WHERE id=?', (item_id,)).fetchone():
            continue
        job = jobs.get(job_id, {})
        name = job.get('name') or job_id
        requires_review, risk, review_reason = cron_output_requires_human_review(raw, job)
        if not requires_review:
            continue
        if cron_output_is_attention_task(raw, job, review_reason):
            if create_attention_task_from_cron_output(path, raw, job, risk, review_reason):
                created += 1
            continue
        created_at = int(path.stat().st_mtime)
        title = f'Review routine output: {name}'
        destination = job.get('deliver') or job.get('origin') or 'origin'
        description = (
            f'You are approving routine output from "{name}" for {destination}. '
            f'Reason this needs a decision: {review_reason}. '
            f'Output preview: {preview_content(raw, 240)}'
        )
        metadata = {'job_id': job_id, 'job_name': name, 'schedule': job.get('schedule_display') or (job.get('schedule') or {}).get('display'), 'file': str(path), 'derived_from': 'cron_output', 'review_reason': review_reason}
        con.execute("""
            INSERT INTO approvals (id,title,description,body,kind,status,risk,source,source_id,source_path,destination,agent_id,agent_name,created_at,updated_at,metadata)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        """, (item_id, title, description, preview_content(raw, 5000), 'automation_output', 'drafted', risk, 'cron', job_id, str(path), destination, 'cron', name, created_at, now, json.dumps(metadata)))
        created += 1
    if created:
        con.commit()
    return created


def inbox_row(r):
    meta = {}
    try:
        meta = json.loads(r['metadata'] or '{}')
    except Exception:
        meta = {}
    return {
        'id': r['id'], 'title': r['title'], 'description': r['description'] or '', 'body': r['body'] or '',
        'kind': r['kind'] or 'draft', 'status': r['status'] or 'drafted', 'risk': r['risk'] or 'medium',
        'source': r['source'] or 'manual', 'source_id': r['source_id'], 'source_path': r['source_path'],
        'destination': r['destination'] or '—', 'agent_id': r['agent_id'] or 'system', 'agent_name': r['agent_name'] or 'Mission Control',
        'created_at': iso(r['created_at']), 'updated_at': iso(r['updated_at']), 'reviewed_at': iso(r['reviewed_at']) if r['reviewed_at'] else None,
        'decision_note': r['decision_note'], 'metadata': meta, 'provenance': f"{r['source'] or 'manual'} · {r['source_id'] or r['agent_name'] or 'Mission Control'}",
    }


def list_inbox(filters=None, identity=None):
    if identity and not is_admin_identity(identity):
        return list_workspace_inbox(filters, identity)
    filters = filters or {}
    con = ensure_approvals_tables()
    sync_cron_outputs_to_inbox(con)
    q = (filters.get('q') or [''])[0].strip()
    status = (filters.get('status') or [''])[0].strip()
    where, params = [], []
    if status and status != 'all':
        where.append('status = ?')
        params.append(status)
    if q:
        like = f'%{q}%'
        where.append('(title LIKE ? OR description LIKE ? OR body LIKE ? OR source LIKE ? OR destination LIKE ? OR agent_name LIKE ?)')
        params.extend([like, like, like, like, like, like])
    where_sql = (' WHERE ' + ' AND '.join(where)) if where else ''
    rows = con.execute(f'SELECT * FROM approvals {where_sql} ORDER BY created_at DESC LIMIT 200', params).fetchall()
    summary_rows = con.execute('SELECT status, count(*) c FROM approvals GROUP BY status').fetchall()
    summary = {'drafted': 0, 'ready': 0, 'sent': 0, 'rejected': 0, 'total': 0, 'high_risk': 0}
    for sr in summary_rows:
        key = sr['status'] or 'drafted'
        if key not in summary:
            summary[key] = 0
        summary[key] = sr['c']
        summary['total'] += sr['c']
    summary['high_risk'] = con.execute("SELECT count(*) FROM approvals WHERE risk in ('high','critical') AND status in ('drafted','ready')").fetchone()[0]
    sources = [r[0] for r in con.execute('SELECT DISTINCT source FROM approvals WHERE source IS NOT NULL ORDER BY source').fetchall()]
    out = {'items': [inbox_row(r) for r in rows], 'summary': summary, 'sources': sources, 'statuses': ['drafted', 'ready', 'sent', 'rejected']}
    con.close()
    return out


def update_inbox_item(item_id, payload):
    con = ensure_approvals_tables()
    existing = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    if not existing:
        con.close(); return {'error': 'inbox item not found'}, 404
    allowed = ['title', 'description', 'body', 'risk', 'destination']
    fields, params = [], []
    for key in allowed:
        if key in payload:
            fields.append(f'{key}=?'); params.append(str(payload.get(key) or ''))
    if not fields:
        con.close(); return {'error': 'no editable fields provided'}, 400
    fields.append('updated_at=?'); params.append(int(time.time())); params.append(item_id)
    con.execute(f'UPDATE approvals SET {", ".join(fields)} WHERE id=?', params)
    con.commit()
    row = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    out = inbox_row(row); con.close()
    return {'ok': True, 'item': out}, 200


def inbox_action(item_id, action, payload=None):
    payload = payload or {}
    allowed = {'approve': 'sent', 'reject': 'rejected', 'ready': 'ready', 'draft': 'drafted'}
    if action not in allowed:
        return {'error': 'invalid inbox action'}, 400
    con = ensure_approvals_tables()
    row = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    if not row:
        con.close(); return {'error': 'inbox item not found'}, 404
    now = int(time.time())
    note = payload.get('note') or payload.get('decision_note')
    con.execute('UPDATE approvals SET status=?, reviewed_at=?, updated_at=?, decision_note=coalesce(?, decision_note) WHERE id=?', (allowed[action], now, now, note, item_id))
    con.commit()
    row = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    out = inbox_row(row); con.close()
    metadata = out.get('metadata') if isinstance(out.get('metadata'), dict) else {}
    if metadata.get('derived_from') == 'approval_policy' and action in ('approve', 'reject'):
        audit_identity = identity_from_approval_metadata(metadata)
        if audit_identity:
            audit_action = 'approval_policy.request_approved' if action == 'approve' else 'approval_policy.request_denied'
            record_approval_policy_audit(audit_identity, audit_action, metadata, {'approval_id': item_id, 'decision': action, 'note': note})
    return {'ok': True, 'action': action, 'item': out}, 200


