def create_reflection_approval(identity=None, payload=None):
    payload = payload or {}
    proposal_id = safe_id(str(payload.get('proposal_id') or payload.get('proposalId') or 'workforce-alignment-weekly')) or 'workforce-alignment-weekly'
    kind = str(payload.get('kind') or 'workforce_alignment')[:80]
    title = str(payload.get('title') or 'Approve Agent Reflection & Workforce Review operating model')[:240]
    target = str(payload.get('target') or payload.get('agentName') or 'AI Workforce')[:160]
    effect = str(payload.get('effect') or 'Future reflection runs may propose memory, skill, and workforce-map updates, but applying them remains approval-gated.')[:600]
    reason = str(payload.get('reason') or 'Melverick approved implementing Agent Sharpening plus Workforce Alignment as the reflection model.')[:600]
    body = str(payload.get('body') or '')[:8000]
    now = int(time.time())
    item_id = f"reflection-{proposal_id}-{hashlib.sha1((proposal_id + title).encode('utf-8')).hexdigest()[:10]}"
    description = (
        f'You are approving the {kind.replace("_", " ")} proposal for {target}. '
        f'If approved: {effect} '
        f'Reason this needs approval: {reason}'
    )
    metadata = {
        'derived_from': 'agent_reflection_workflow',
        'proposal_id': proposal_id,
        'kind': kind,
        'target': target,
        'effect': effect,
        'reason': reason,
        'identity_email': (identity or {}).get('email') if isinstance(identity, dict) else None,
    }
    con = ensure_approvals_tables()
    con.execute("""
        INSERT OR REPLACE INTO approvals (id,title,description,body,kind,status,risk,source,source_id,source_path,destination,agent_id,agent_name,created_at,updated_at,metadata)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    """, (item_id, title, description, body or description, 'reflection_update', 'drafted', 'medium', 'agent-reflection', proposal_id, None, 'HMC Memory/Skills/Workforce Map', 'default', 'Melkizac', now, now, json.dumps(metadata)))
    con.commit()
    row = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    out = inbox_row(row)
    con.close()
    return {'ok': True, 'item': out}, 200


def automation_action(job_id, action, payload=None, identity=None):
    payload = payload or {}
    jid = safe_id(job_id)
    allowed = {'pause', 'resume', 'run', 'enable_funnel_routine'}
    if not jid or action not in allowed:
        return {'ok': False, 'error': 'invalid automation action'}, 400
    if action == 'run' and identity:
        conn = runtime_connector_db()
        routine_row = conn.execute('SELECT 1 FROM workflow_routines WHERE id=?', (jid,)).fetchone()
        conn.close()
        if routine_row:
            return execute_workflow_routine(identity, jid, {
                'browser_evidence': payload.get('browser_evidence') or payload.get('browserEvidence') or {'source': 'Mission Control Workflow Routine Admin', 'operator_initiated': True},
                'research_run': payload.get('research_run') or payload.get('researchRun') or {'source': 'Mission Control Workflow Routine Admin', 'operator_initiated': True},
                'operator_note': payload.get('note') or 'Operator clicked Run now in Workflow Routine Admin.',
            })
    if action == 'enable_funnel_routine':
        routine = payload.get('routine') if isinstance(payload.get('routine'), dict) else {}
        if not routine.get('id'):
            routine['id'] = jid
        result, status = enable_website_funnel_routine(routine, payload)
        if result.get('ok'):
            result['action'] = 'enable_funnel_routine'
            result['job_id'] = result.get('job', {}).get('id') or jid
        return result, status
    hermes_bin = os.environ.get('HMC_HERMES_BIN') or shutil.which('hermes') or '/root/hermes-agent/venv/bin/hermes'
    if not Path(hermes_bin).exists():
        return {'ok': False, 'error': f'hermes CLI not found at {hermes_bin}', 'action': action, 'job_id': jid}, 500
    cmd = [hermes_bin, 'cron', action, jid]
    env = os.environ.copy()
    env['HERMES_HOME'] = str(HERMES_HOME)
    env['PATH'] = f"{Path(hermes_bin).parent}:{env.get('PATH', '')}"
    try:
        result = subprocess.run(cmd, text=True, capture_output=True, timeout=45, env=env)
        ok = result.returncode == 0
        return {
            'ok': ok,
            'action': action,
            'job_id': jid,
            'stdout': preview_content(result.stdout, 1200),
            'stderr': preview_content(result.stderr, 1200),
            'returncode': result.returncode,
        }, 200 if ok else 500
    except Exception as e:
        return {'ok': False, 'error': str(e), 'action': action, 'job_id': jid}, 500

def kanban_connect(readonly=False):
    KANBAN_DB.parent.mkdir(parents=True, exist_ok=True)
    if readonly and KANBAN_DB.exists():
        con = sqlite3.connect(f'file:{KANBAN_DB}?mode=ro', uri=True, timeout=max(1, SQLITE_BUSY_TIMEOUT_MS / 1000))
    else:
        con = sqlite3.connect(KANBAN_DB, timeout=max(1, SQLITE_BUSY_TIMEOUT_MS / 1000))
        try:
            con.execute('PRAGMA journal_mode=WAL')
        except sqlite3.DatabaseError:
            pass
    con.row_factory = sqlite3.Row
    con.execute(f'PRAGMA busy_timeout={SQLITE_BUSY_TIMEOUT_MS}')
    return con


def kanban_board_connect(path, readonly=True):
    target = Path(path)
    if readonly:
        con = sqlite3.connect(f'file:{target}?mode=ro', uri=True, timeout=max(1, SQLITE_BUSY_TIMEOUT_MS / 1000))
    else:
        con = sqlite3.connect(target, timeout=max(1, SQLITE_BUSY_TIMEOUT_MS / 1000))
        try:
            con.execute('PRAGMA journal_mode=WAL')
        except sqlite3.DatabaseError:
            pass
    con.row_factory = sqlite3.Row
    con.execute(f'PRAGMA busy_timeout={SQLITE_BUSY_TIMEOUT_MS}')
    return con


def kanban_uses_live_default_board_root():
    try:
        return Path(KANBAN_DB).expanduser().resolve() == (HERMES_HOME / 'kanban.db').expanduser().resolve()
    except Exception:
        return Path(KANBAN_DB).expanduser().absolute() == (HERMES_HOME / 'kanban.db').expanduser().absolute()


def kanban_board_sources():
    sources = [{
        'id': 'default',
        'slug': 'default',
        'label': 'Default board',
        'path': KANBAN_DB,
        'is_default': True,
        'source_kind': 'default',
    }]
    if not kanban_uses_live_default_board_root():
        return sources
    try:
        profiles_root = HERMES_HOME / 'profiles'
        if profiles_root.exists():
            for profile_dir in sorted(profiles_root.iterdir(), key=lambda x: x.name):
                db_path = profile_dir / 'kanban.db'
                if not profile_dir.is_dir() or not db_path.exists():
                    continue
                # Profile-local Kanban DB files can be touched by profile setup or
                # cron bootstrap before the Kanban schema is initialized. Treat a
                # zero-byte profile DB as absent so HMC does not show noisy
                # "missing tasks table" warnings for profiles with no board yet.
                try:
                    if db_path.stat().st_size == 0:
                        continue
                except OSError:
                    continue
                slug = safe_id(profile_dir.name) or profile_dir.name
                sources.append({
                    'id': f'profile:{slug}',
                    'slug': f'profile:{slug}',
                    'label': f'Profile · {profile_dir.name}',
                    'path': db_path,
                    'is_default': False,
                    'source_kind': 'profile',
                })
        if KANBAN_BOARDS_ROOT.exists():
            for board_dir in sorted(KANBAN_BOARDS_ROOT.iterdir(), key=lambda x: x.name):
                db_path = board_dir / 'kanban.db'
                if not board_dir.is_dir() or not db_path.exists():
                    continue
                slug = safe_id(board_dir.name) or board_dir.name
                sources.append({
                    'id': f'board:{slug}',
                    'slug': f'board:{slug}',
                    'label': board_dir.name.replace('-', ' ').title(),
                    'path': db_path,
                    'is_default': False,
                    'source_kind': 'named_board',
                })
    except Exception:
        pass
    return sources


def public_kanban_board_source(source):
    return {
        'id': source.get('id') or source.get('slug') or 'default',
        'slug': source.get('slug') or source.get('id') or 'default',
        'label': source.get('label') or source.get('slug') or 'Default board',
        'is_default': bool(source.get('is_default')),
        'source_kind': source.get('source_kind') or ('default' if source.get('is_default') else 'board'),
    }


def task_board_filter_values(filters, *names):
    values = []
    for name in names:
        for raw in filters.get(name) or []:
            for value in str(raw or '').split(','):
                value = value.strip()
                if value:
                    values.append(value)
    return values


def normalize_task_board_filter_value(value):
    return safe_id(str(value or '').strip().lower().replace(':', '-'))


def task_board_source_aliases(source):
    public = public_kanban_board_source(source)
    raw_aliases = {
        public.get('id'),
        public.get('slug'),
        public.get('label'),
        public.get('source_kind'),
        source.get('id'),
        source.get('slug'),
        source.get('source_kind'),
    }
    aliases = {str(a).strip().lower() for a in raw_aliases if a}
    aliases |= {normalize_task_board_filter_value(a) for a in raw_aliases if a}
    return aliases


def filter_kanban_board_sources(sources, selectors):
    if not selectors:
        return list(sources), []
    all_values = {'all', '*', 'all_boards', 'all-boards', 'all boards', 'all board sources', 'all_sources', 'all-sources'}
    wanted = [s for s in selectors if str(s or '').strip().lower() not in all_values]
    if not wanted:
        return list(sources), []
    wanted_aliases = {
        str(value).strip().lower()
        for value in wanted
        if str(value).strip()
    } | {normalize_task_board_filter_value(value) for value in wanted}
    selected = []
    for source in sources:
        aliases = task_board_source_aliases(source)
        matches = aliases & wanted_aliases
        if matches:
            selected.append(source)
    unmatched = []
    selected_aliases = set()
    for source in selected:
        selected_aliases |= task_board_source_aliases(source)
    for value in wanted:
        value_aliases = {str(value).strip().lower(), normalize_task_board_filter_value(value)}
        if not (value_aliases & selected_aliases):
            unmatched.append(value)
    warnings = [{'board': value, 'status': 'skipped', 'reason': 'unknown board/source filter'} for value in unmatched]
    return selected, warnings


def kanban_board_has_tasks_table(con):
    try:
        row = con.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='tasks'").fetchone()
        return bool(row)
    except Exception:
        return False


def read_task_comments(con, limit=600):
    out = {}
    if not kanban_board_has_table(con, 'task_comments'):
        return out
    for r in con.execute('SELECT * FROM task_comments ORDER BY created_at DESC LIMIT ?', (limit,)):
        out.setdefault(r['task_id'], []).append({
            'id': r['id'], 'author': r['author'], 'body': preview_content(r['body'], 700), 'created_at': iso(r['created_at'])
        })
    return out


def read_task_events(con, limit=900):
    out = {}
    if not kanban_board_has_table(con, 'task_events'):
        return out
    for r in con.execute('SELECT * FROM task_events ORDER BY created_at DESC LIMIT ?', (limit,)):
        payload = None
        try:
            payload = json.loads(r['payload']) if r['payload'] else None
        except Exception:
            payload = preview_content(r['payload'], 500)
        out.setdefault(r['task_id'], []).append({
            'id': r['id'], 'kind': r['kind'], 'payload': payload, 'created_at': iso(r['created_at']), 'run_id': r['run_id']
        })
    return out


def normalize_async_run_status(value, run_status=None, outcome=None):
    raw = safe_id(value or outcome or run_status or '').lower()
    mapping = {
        'detached': 'detached', 'background': 'detached', 'async': 'detached',
        'queued': 'queued', 'pending': 'queued', 'scheduled': 'queued',
        'running': 'running', 'in_progress': 'running', 'active': 'running',
        'completed': 'completed', 'complete': 'completed', 'done': 'completed', 'success': 'completed', 'succeeded': 'completed',
        'failed': 'failed', 'error': 'failed', 'crashed': 'failed',
        'cancelled': 'cancelled', 'canceled': 'cancelled', 'stopped': 'cancelled',
        'timed_out': 'timed_out', 'timeout': 'timed_out',
        'reclaimed': 'reclaimed', 'blocked': 'blocked',
    }
    return mapping.get(raw, mapping.get(safe_id(run_status or '').lower(), 'unknown'))


def normalize_completion_cause(value, status=None, outcome=None, ended_at=None):
    raw = safe_id(value or outcome or '').lower()
    mapping = {
        'success': 'completed', 'succeeded': 'completed', 'done': 'completed', 'completed': 'completed', 'complete': 'completed',
        'failed': 'failed', 'failure': 'failed', 'error': 'failed', 'crashed': 'failed', 'exception': 'failed',
        'cancelled': 'cancelled', 'canceled': 'cancelled', 'stopped': 'cancelled', 'interrupted': 'cancelled',
        'timeout': 'timed_out', 'timed_out': 'timed_out', 'deadline': 'timed_out',
        'runtime_lost': 'runtime_lost', 'runtime-lost': 'runtime_lost', 'worker_lost': 'runtime_lost', 'lost': 'runtime_lost',
        'detached': 'detached', 'background': 'detached', 'async': 'detached',
        'reclaimed': 'reclaimed', 'blocked': 'blocked', 'approval_required': 'approval_required', 'approval': 'approval_required',
    }
    if raw in mapping:
        return mapping[raw]
    status_value = safe_id(status or '').lower()
    if status_value in ('running', 'queued', 'pending') and not ended_at:
        return None
    return mapping.get(status_value, 'unknown') if status_value else None


def task_run_record(row):
    metadata = parse_json_field(row['metadata'], {}) if 'metadata' in row.keys() else {}
    runtime_id = safe_id(metadata.get('runtime_id') or metadata.get('runtimeId') or '') or None
    profile_id = safe_id(metadata.get('profile_id') or metadata.get('profileId') or row['profile'] or '') or None
    completion_cause = normalize_completion_cause(metadata.get('completion_cause') or metadata.get('completionCause'), row['status'], row['outcome'], row['ended_at'])
    async_status = normalize_async_run_status(metadata.get('async_status') or metadata.get('asyncStatus'), row['status'], row['outcome'])
    return {
        'id': row['id'], 'run_id': row['id'], 'task_id': row['task_id'], 'profile': row['profile'], 'agent': row['profile'], 'step_key': row['step_key'],
        'status': row['status'], 'started_at': iso(row['started_at']), 'ended_at': iso(row['ended_at']) if row['ended_at'] else None,
        'outcome': row['outcome'], 'summary': preview_content(row['summary'] or '', 700), 'error': preview_content(row['error'] or '', 500),
        'metadata': metadata,
        'async_status': async_status,
        'completion_cause': completion_cause,
        'runtime_id': runtime_id,
        'profile_id': profile_id,
        'spawned_by': safe_id(metadata.get('spawned_by') or metadata.get('spawnedBy') or '') or None,
    }


def read_task_runs(con, limit=500):
    out = {}
    if not kanban_board_has_table(con, 'task_runs'):
        return out
    for r in con.execute('SELECT * FROM task_runs ORDER BY started_at DESC LIMIT ?', (limit,)):
        out.setdefault(r['task_id'], []).append(task_run_record(r))
    return out


def read_task_links(con):
    child_map, parent_map = {}, {}
    if not kanban_board_has_table(con, 'task_links'):
        return child_map, parent_map
    for r in con.execute('SELECT parent_id, child_id FROM task_links'):
        child_map.setdefault(r['parent_id'], []).append(r['child_id'])
        parent_map.setdefault(r['child_id'], []).append(r['parent_id'])
    return child_map, parent_map


def kanban_board_has_table(con, table_name):
    try:
        row = con.execute("SELECT name FROM sqlite_master WHERE type='table' AND name=?", (table_name,)).fetchone()
        return bool(row)
    except Exception:
        return False


def with_task_board_identity(task, source):
    board = public_kanban_board_source(source)
    task['board_id'] = board['id']
    task['board_slug'] = board['slug']
    task['board_label'] = board['label']
    task['board_is_default'] = board['is_default']
    return task


