def canonical_task_evidence_type(value):
    raw = str(value or '').strip().lower().replace(' ', '_')
    dashed = raw.replace('_', '-')
    return TASK_EVIDENCE_ALIASES.get(raw) or TASK_EVIDENCE_ALIASES.get(dashed) or raw


def parse_task_evidence_required(value):
    if isinstance(value, bool):
        return value
    if value is None:
        return False
    if isinstance(value, (int, float)):
        return bool(value)
    text = str(value).strip().lower()
    if text in {'true', 'yes', 'y', '1', 'required', 'require', 'on'}:
        return True
    if text in {'false', 'no', 'n', '0', 'none', 'not-required', 'not_required', 'off', ''}:
        return False
    return False


def task_evidence_value_present(value):
    if value is None:
        return False
    if isinstance(value, str):
        return bool(value.strip())
    return True


def normalized_task_evidence_checklist(items):
    if isinstance(items, str):
        items = [x.strip() for x in re.split(r'[,\n]+', items) if x.strip()]
    if not isinstance(items, list):
        return []
    out = []
    for item in items:
        canonical = canonical_task_evidence_type(item)
        if canonical in DEFAULT_TASK_EVIDENCE_TYPES and canonical not in out:
            out.append(canonical)
    return out


def task_result_details(result):
    if not result:
        return None
    try:
        data = json.loads(result) if isinstance(result, str) else result
    except Exception:
        return None
    if not isinstance(data, dict):
        return None
    blockers = data.get('blockers') or data.get('blocked_on') or []
    if isinstance(blockers, str):
        blockers = [blockers]
    verification = data.get('verification') or {}
    if not isinstance(verification, dict):
        verification = {}
    raw_summary = data.get('summary')
    if isinstance(raw_summary, dict):
        summary_value = raw_summary
    else:
        summary_value = preview_content(raw_summary or '', 900)
    sources = data.get('sources') or data.get('source_materials') or data.get('sourceMaterials') or []
    outputs = data.get('outputs') or data.get('deliverables') or []
    stages = data.get('stages') or data.get('workflow_stages') or data.get('workflowStages') or []
    settings = data.get('settings') or data.get('requirements') or {}
    guard_policy = data.get('guard_policy') or data.get('guardPolicy') or (settings.get('guard_policy') if isinstance(settings, dict) else None) or (settings.get('guardPolicy') if isinstance(settings, dict) else None)
    guard_policy = sanitize_task_result_value(guard_policy) if isinstance(guard_policy, dict) else {}
    artifacts = data.get('artifacts') if isinstance(data.get('artifacts'), list) else []
    task_stub = {'id': data.get('task_id') or data.get('taskId') or 'result', 'updated_at': data.get('updated_at') or data.get('updatedAt') or data.get('created_at') or data.get('createdAt')}
    safe_evidence = []
    raw_evidence = data.get('evidence') if isinstance(data.get('evidence'), list) else []
    for idx, item in enumerate(raw_evidence):
        safe_evidence.append(normalize_task_evidence(task_stub, item, idx, 'log'))
    for idx, (key, value) in enumerate(verification.items()):
        safe_evidence.append(normalize_task_evidence(task_stub, {
            'id': f"verification-{safe_id(str(key)) or idx}",
            'type': 'verification_log',
            'title': f"Verification · {key}",
            'summary': value,
            'source': 'Task result verification',
            'reference': key,
            'verification': {'status': 'recorded'},
        }, len(safe_evidence), 'log'))
    source_rows = sanitize_task_result_rows(sources) if isinstance(sources, list) else []
    for idx, source in enumerate(source_rows):
        if not isinstance(source, dict):
            continue
        citation = source.get('citation') if isinstance(source.get('citation'), dict) else {}
        processing = source.get('processing') if isinstance(source.get('processing'), dict) else {}
        title = source.get('title') or source.get('name') or source.get('filename') or source.get('uri') or f"Source {idx + 1}"
        if citation or processing:
            safe_evidence.append(normalize_task_evidence(task_stub, {
                'id': f"source-{safe_id(str(source.get('id') or source.get('source_id') or idx))}",
                'type': 'source_processing_log',
                'title': f"Source status · {title}",
                'summary': f"processing={processing.get('status') or source.get('status') or 'pending'}; citation={citation.get('health') or citation.get('coverage') or source.get('citation_health') or 'pending'}",
                'source': 'Project source record',
                'sourceId': source.get('source_id') or source.get('sourceId') or source.get('id'),
                'reference': source.get('citation_label') or citation.get('citation_label') or source.get('uri') or source.get('url') or title,
                'verification': {'status': 'recorded'},
            }, len(safe_evidence), 'source'))
    output_rows = sanitize_task_result_rows(outputs) if isinstance(outputs, list) else []
    artifact_rows = sanitize_task_result_rows(artifacts)
    for idx, output in enumerate(artifact_rows + output_rows):
        if not isinstance(output, dict):
            continue
        qa = output.get('qaStatus') or output.get('qa_status') or output.get('verification_status') or output.get('status')
        preview = output.get('previewUrl') or output.get('preview_url') or output.get('render_preview') or output.get('renderPreview')
        readback = output.get('api_readback') or output.get('apiReadback') or output.get('readback')
        if qa or preview or readback:
            safe_evidence.append(normalize_task_evidence(task_stub, {
                'id': f"artifact-qa-{safe_id(str(output.get('id') or output.get('artifact_id') or output.get('output_id') or idx))}",
                'type': 'artifact_validation',
                'title': f"Artifact QA · {output.get('title') or output.get('filename') or output.get('type') or 'output'}",
                'summary': readback or f"QA status {qa or 'recorded'}; render preview {'available' if preview else 'not attached'}.",
                'source': 'Artifact verification',
                'artifactId': output.get('artifact_id') or output.get('artifactId') or output.get('id') or output.get('output_id'),
                'url': preview,
                'verification': {'status': qa or 'recorded', 'checks': output.get('checks') or []},
            }, len(safe_evidence), 'file'))
    evidence_checklist = data.get('evidence_checklist') or data.get('evidenceChecklist') or data.get('required_evidence') or data.get('requiredEvidence') or []
    evidence_checklist = normalized_task_evidence_checklist(evidence_checklist)
    evidence_required = data.get('evidence_required')
    if evidence_required is None:
        evidence_required = data.get('evidenceRequired')
    if evidence_required is None and isinstance(data.get('requirements'), dict):
        evidence_required = data['requirements'].get('evidence_required')
        if evidence_required is None:
            evidence_required = data['requirements'].get('evidenceRequired')
    evidence_required = parse_task_evidence_required(evidence_required)
    return {
        'status': data.get('status'),
        'summary': summary_value,
        'objective': preview_content(data.get('objective') or '', 1200),
        'workflow_type': data.get('workflow_type') or data.get('workflowType'),
        'artifact': data.get('artifact'),
        'blockers': [preview_content(str(item), 700) for item in blockers if item],
        'verification': {str(k): preview_content(str(v), 700) for k, v in verification.items() if v is not None},
        'access_needed': preview_content(data.get('access_needed') or '', 900),
        'sources': source_rows,
        'outputs': output_rows,
        'stages': sanitize_task_result_rows(stages) if isinstance(stages, list) else [],
        'settings': sanitize_task_result_value(settings) if isinstance(settings, dict) else {},
        'requirements': sanitize_task_result_value(data.get('requirements')) if isinstance(data.get('requirements'), dict) else {},
        'artifacts': artifact_rows,
        'evidence': safe_evidence,
        'evidence_required': evidence_required,
        'evidence_checklist': evidence_checklist,
        'approval_gates': sanitize_task_result_rows(data.get('approval_gates') or data.get('approvalGates')) if isinstance(data.get('approval_gates') or data.get('approvalGates'), list) else [],
        'next_actions': sanitize_task_result_rows(data.get('next_actions') or data.get('nextActions')) if isinstance(data.get('next_actions') or data.get('nextActions'), list) else [],
        'needs_human': bool(data.get('needs_human') or data.get('needsHuman') or data.get('human_decision_required') or data.get('humanDecisionRequired')),
        'approval_policy': sanitize_task_result_value(data.get('approval_policy') or data.get('approvalPolicy')) if isinstance(data.get('approval_policy') or data.get('approvalPolicy'), dict) else {},
        'guard_policy': guard_policy,
    }



def hmc_guard_policy(project_id='', task=None, result_details=None):
    """Return advisory guard-mode metadata for the HMC governed software factory."""
    details = result_details if isinstance(result_details, dict) else {}
    explicit = details.get('guard_policy') or details.get('guardPolicy')
    if isinstance(explicit, dict):
        safe = sanitize_task_result_value(explicit)
        if isinstance(safe, dict):
            return safe

    def task_get(key, default=''):
        if not task:
            return default
        if isinstance(task, dict):
            return task.get(key, default)
        try:
            return task[key]
        except Exception:
            return default

    hay = text_blob(project_id, task_get('tenant'), task_get('workspace_path'), task_get('workflow_template_id'), task_get('title'))

    is_hmc = any(token in hay for token in ('hmc-governed-software-factory', 'mission-control', 'hermes-mission-control', '/opt/hermes-mission-control'))
    if not is_hmc:
        return None
    return {
        'mode': 'advisory',
        'scope': 'project-task',
        'allowed_edit_paths': [
            '/opt/hermes-mission-control/source/src',
            '/opt/hermes-mission-control/source/docs',
            '/opt/hermes-mission-control/source/tests',
            '/opt/hermes-mission-control/app.py',
            '/opt/hermes-mission-control/dist (deploy/update only after build + explicit release evidence)',
        ],
        'destructive_command_warning_level': 'high',
        'checkpoint_mode': 'git-diff + build proof before review; commit/backup before deploy',
        'rollback_artifact_path': '/opt/hermes-mission-control/source/docs/HMC_SOFTWARE_FACTORY_WORKFLOW.md#rollback--safety',
        'freeze': False,
        'advisory_enforcement': True,
        'safe_start_required': True,
        'dirty_repo_policy': 'Record a safe-start comment before dispatching workers into dirty repo state; do not silently mutate worker/global config.',
        'evidence_required': ['allowed edit paths', 'checkpoint/build proof', 'rollback note'],
    }

def task_artifact_format(ref='', mime=''):
    value = str(ref or '').lower()
    mt = str(mime or '').lower()
    if value.endswith('.pptx') or 'powerpoint' in mt or 'presentation' in mt:
        return 'pptx'
    if value.endswith('.docx') or 'wordprocessingml' in mt or 'msword' in mt:
        return 'docx'
    if value.endswith('.pdf') or mt == 'application/pdf':
        return 'pdf'
    if value.endswith(('.md', '.markdown')) or mt == 'text/markdown':
        return 'markdown'
    if value.startswith('http') and 'drive.google.com' in value:
        return 'drive'
    return ''


def task_artifact_mime(path_or_name='', fallback=''):
    guessed = mimetypes.guess_type(str(path_or_name or ''))[0]
    return fallback or guessed or 'application/octet-stream'


def task_artifact_kind(path_or_name='', explicit=''):
    value = str(path_or_name or '').lower()
    kind = str(explicit or '').lower()
    if kind in {'file', 'link', 'screenshot', 'report', 'diff', 'message', 'dataset', 'note'}:
        return kind
    if value.startswith('http'):
        return 'link'
    if value.endswith(('.png', '.jpg', '.jpeg', '.gif', '.webp')):
        return 'screenshot'
    if value.endswith(('.pptx', '.docx', '.pdf', '.md', '.markdown')):
        return 'report'
    if value.endswith(('.csv', '.json', '.xlsx')):
        return 'dataset'
    if '/' in value or '.' in value:
        return 'file'
    return 'note'


def task_artifact_public_url(task_id, artifact_id, disposition='inline'):
    base = f"/api/tasks/{quote(safe_id(task_id) or str(task_id))}/artifacts/{quote(str(artifact_id))}"
    return base + ("?download=1" if disposition == 'download' else '')


def safe_evidence_url(value):
    raw = str(value or '').strip()
    if not raw:
        return None
    if not (raw.startswith('http://') or raw.startswith('https://') or raw.startswith('/')):
        return None
    try:
        if raw.startswith('http'):
            parsed = urlsplit(raw)
            candidate = urlunsplit((parsed.scheme, parsed.netloc, parsed.path, '', '')) if parsed.query else raw
            redacted = redact_text(candidate)
            if '[REDACTED]' in redacted:
                return None
            return redacted
    except Exception:
        return None
    redacted = redact_text(raw)
    if '[REDACTED]' in redacted:
        return None
    return raw


def sanitize_task_result_value(value, depth=0):
    """Return a UI-safe result value with secrets redacted and signed/query URLs stripped."""
    if depth > 4:
        return preview_content(str(value), 500)
    if isinstance(value, dict):
        out = {}
        for key, nested in value.items():
            key_str = str(key)
            lowered = key_str.lower()
            if lowered in {'url', 'uri', 'href', 'previewurl', 'preview_url', 'driveurl', 'drive_url', 'renderpreview', 'render_preview'}:
                safe_url = safe_evidence_url(nested)
                if safe_url:
                    out[key_str] = safe_url
                continue
            out[key_str] = sanitize_task_result_value(nested, depth + 1)
        return {k: v for k, v in out.items() if v not in (None, '', [])}
    if isinstance(value, list):
        return [sanitize_task_result_value(item, depth + 1) for item in value]
    if isinstance(value, str):
        if value.startswith(('http://', 'https://')):
            return safe_evidence_url(value) or '[REDACTED]'
        return preview_content(value, 1200)
    return value


def sanitize_task_result_rows(rows):
    if not isinstance(rows, list):
        return []
    return [sanitize_task_result_value(row) for row in rows]


def evidence_reference(item, task=None):
    item = item if isinstance(item, dict) else {}
    for key in ('reference', 'ref', 'task_id', 'taskId', 'run_id', 'runId', 'api_request_id', 'apiRequestId', 'source_id', 'sourceId', 'artifact_id', 'artifactId', 'session_id', 'sessionId'):
        value = item.get(key)
        if value:
            text = str(value)
            if text.startswith(('http://', 'https://')):
                text = safe_evidence_url(text) or '[REDACTED]'
            return preview_content(text, 180)
    source_ids = item.get('source_ids') or item.get('sourceIds')
    if isinstance(source_ids, list) and source_ids:
        return preview_content(', '.join(str(x) for x in source_ids[:3]), 180)
    if task and task.get('id'):
        return preview_content(str(task.get('id')), 180)
    return 'mission-control'


def evidence_kind(value):
    raw = str(value or 'log').strip().lower().replace(' ', '_').replace('-', '_')
    mapping = {
        'source_processing_log': 'source', 'source_added': 'source', 'citation_map': 'source',
        'router_decision': 'session', 'project_created': 'session',
        'artifact_generation_log': 'file', 'artifact_validation': 'file', 'qa_render': 'screenshot', 'qa_screenshot': 'screenshot',
        'api_response': 'log', 'api_readback': 'log', 'verification_log': 'log', 'qa_result': 'log',
        'approval_decision': 'approval', 'delivery_record': 'log', 'error_log': 'log', 'blocker': 'log',
    }
    return mapping.get(raw, raw if raw in {'source','tool-call','session','screenshot','file','log','approval','human-note'} else 'log')


def normalize_task_evidence(task, item, index=0, default_kind='log', now_iso=None):
    now_iso = now_iso or task.get('updated_at') or task.get('created_at') or iso(time.time())
    if isinstance(item, str):
        item = {'summary': item}
    if not isinstance(item, dict):
        item = {'summary': str(item)}
    raw_kind = item.get('type') or item.get('kind') or default_kind
    ev_id = safe_id(item.get('id') or item.get('evidence_id') or item.get('evidenceId') or '') or hashlib.sha256(f"{task.get('id')}|evidence|{index}|{item.get('title')}|{item.get('summary')}".encode()).hexdigest()[:12]
    title = item.get('title') or item.get('label') or str(raw_kind).replace('_', ' ').title()
    summary = item.get('summary') or item.get('description') or item.get('body') or item.get('result') or ''
    created = item.get('createdAt') or item.get('created_at') or item.get('timestamp') or item.get('ts') or now_iso
    reference = evidence_reference(item, task)
    source = item.get('source') or item.get('actor') or item.get('worker') or item.get('endpoint') or 'Mission Control evidence'
    verification = item.get('verification') if isinstance(item.get('verification'), dict) else {}
    checks = verification.get('checks') or item.get('checks') or []
    out = {
        'id': ev_id,
        'kind': evidence_kind(raw_kind),
        'type': preview_content(str(raw_kind), 80),
        'title': preview_content(title, 180),
        'summary': preview_content(summary, 900),
        'source': preview_content(source, 180),
        'sourceId': preview_content(item.get('sourceId') or item.get('source_id') or item.get('api_request_id') or item.get('apiRequestId') or '', 180) or None,
        'path': None,
        'url': safe_evidence_url(item.get('url') or item.get('uri') or item.get('href')),
        'createdAt': created,
        'redacted': bool(item.get('redacted') or item.get('redaction_status') or '[REDACTED]' in redact_text(json.dumps(item, default=str))),
        'confidence': item.get('confidence') or ('high' if verification.get('status') == 'passed' else 'medium'),
        'reference': reference,
        'taskId': preview_content(item.get('task_id') or item.get('taskId') or task.get('id') or '', 180) or None,
        'runId': preview_content(item.get('run_id') or item.get('runId') or '', 180) or None,
        'artifactId': preview_content(item.get('artifact_id') or item.get('artifactId') or '', 180) or None,
        'verificationStatus': preview_content(verification.get('status') or item.get('verification_status') or item.get('status') or '', 80) or None,
        'checks': [preview_content(str(x), 120) for x in checks[:6]] if isinstance(checks, list) else [],
    }
    # Local filesystem paths can be sensitive; only expose explicit Mission Control artifact routes/URLs.
    return {k: v for k, v in out.items() if v not in (None, '', [])}


def normalize_task_artifact(task, item, index=0, now_iso=None):
    now_iso = now_iso or task.get('updated_at') or task.get('created_at') or iso(time.time())
    if isinstance(item, str):
        item = {'path': item}
    if not isinstance(item, dict):
        item = {'summary': preview_content(str(item), 500)}
    raw_path = str(item.get('path') or item.get('uri') or item.get('url') or item.get('driveUrl') or item.get('drive_url') or '')
    title = str(item.get('title') or item.get('filename') or (Path(raw_path).name if raw_path and not raw_path.startswith('http') else '') or raw_path or f"Artifact {index + 1}")
    artifact_id = safe_id(item.get('id') or item.get('artifact_id') or item.get('artifactId') or '') or hashlib.sha256(f"{task.get('id')}|{index}|{raw_path}|{title}".encode()).hexdigest()[:12]
    mime = task_artifact_mime(raw_path or title, str(item.get('mime') or ''))
    fmt = str(item.get('format') or task_artifact_format(raw_path or title, mime) or '').lower()
    out = {
        'id': artifact_id,
        'kind': task_artifact_kind(raw_path or title, item.get('kind')),
        'title': preview_content(title, 180),
        'summary': preview_content(item.get('summary') or item.get('description') or '', 700),
        'filename': sanitize_filename(item.get('filename') or (Path(raw_path).name if raw_path and not raw_path.startswith('http') else title)),
        'path': raw_path or None,
        'url': safe_evidence_url(item.get('url')) if item.get('url') else None,
        'driveUrl': safe_evidence_url(item.get('driveUrl') or item.get('drive_url') or (raw_path if raw_path.startswith('http') and 'drive.google.com' in raw_path else None)),
        'mime': mime,
        'sizeBytes': item.get('sizeBytes') or item.get('size_bytes') or item.get('size') or None,
        'preview': preview_content(item.get('preview') or '', 1200),
        'version': str(item.get('version') or item.get('revision') or 'v1'),
        'qaStatus': str(item.get('qaStatus') or item.get('qa_status') or item.get('verification_status') or 'not-run'),
        'format': fmt or None,
        'createdAt': item.get('createdAt') or item.get('created_at') or now_iso,
        'createdBy': item.get('createdBy') or item.get('created_by') or task.get('assignee') or 'mission-control',
        'evidenceIds': item.get('evidenceIds') or item.get('evidence_ids') or [],
    }
    if raw_path and raw_path.startswith('http'):
        out['url'] = out['url'] or safe_evidence_url(raw_path)
        if out.get('driveUrl'):
            out['driveUrl'] = safe_evidence_url(out.get('driveUrl'))
        out['path'] = safe_evidence_url(raw_path)
    elif raw_path:
        out['previewUrl'] = task_artifact_public_url(task.get('id'), artifact_id, 'inline')
        out['downloadUrl'] = task_artifact_public_url(task.get('id'), artifact_id, 'download')
    return {k: v for k, v in out.items() if v not in (None, '')}


def task_evidence_gate_state(task, details=None, comments=None, events=None, runs=None):
    """Return an operator-safe evidence completion gate for Task Board results."""
    details = details or {}
    comments = comments or []
    events = events or []
    runs = runs or []
    required = parse_task_evidence_required(details.get('evidence_required') if details.get('evidence_required') is not None else details.get('evidenceRequired'))
    raw_required_types = details.get('evidence_checklist') or details.get('evidenceChecklist') or []
    requirements = details.get('requirements') if isinstance(details.get('requirements'), dict) else {}
    if not raw_required_types:
        raw_required_types = requirements.get('evidence_checklist') or requirements.get('evidenceChecklist') or requirements.get('required_evidence') or requirements.get('requiredEvidence') or []
    required_types = normalized_task_evidence_checklist(raw_required_types)
    if required and not required_types:
        required_types = list(DEFAULT_TASK_EVIDENCE_TYPES)

    satisfied = set()
    evidence_items = []
    for item in details.get('evidence') or []:
        if isinstance(item, dict):
            evidence_items.append(item)
    for artifact in details.get('artifacts') or []:
        if isinstance(artifact, dict):
            evidence_items.append({'type': 'file_artifact', 'title': artifact.get('title') or artifact.get('filename'), 'summary': artifact.get('summary') or artifact.get('path') or artifact.get('url'), 'reference': artifact.get('id') or artifact.get('path') or artifact.get('url')})
    if task.get('session_id'):
        evidence_items.append({'type': 'session_link', 'summary': task.get('session_id'), 'reference': task.get('session_id')})
    for run in runs[:5]:
        if run.get('id') or run.get('run_id'):
            evidence_items.append({'type': 'session_link', 'summary': run.get('summary') or run.get('outcome') or run.get('status'), 'reference': run.get('id') or run.get('run_id')})
    for comment in comments[:10]:
        body = str(comment.get('body') or '') if isinstance(comment, dict) else ''
        if 'approved' in body.lower() or 'approval' in body.lower() or 'review-required handoff' in body.lower():
            evidence_items.append({'type': 'approval_note', 'summary': body, 'reference': comment.get('author') if isinstance(comment, dict) else 'comment'})
    for event in events[:20]:
        if not isinstance(event, dict):
            continue
        kind = canonical_task_evidence_type(event.get('kind'))
        payload = event.get('payload') if isinstance(event.get('payload'), dict) else {}
        if kind in DEFAULT_TASK_EVIDENCE_TYPES:
            evidence_items.append({'type': kind, 'summary': payload.get('summary') or event.get('kind'), 'reference': event.get('id') or event.get('kind')})

    for item in evidence_items:
        canonical = canonical_task_evidence_type(item.get('type') or item.get('kind'))
        reference = item.get('reference')
        reference_present = task_evidence_value_present(reference) and str(reference).strip() not in {'result', str(task.get('id') or '').strip()}
        has_proof_value = any(task_evidence_value_present(item.get(key)) for key in ('summary', 'url', 'path')) or (canonical == 'session_link' and task_evidence_value_present(reference)) or reference_present
        if canonical in DEFAULT_TASK_EVIDENCE_TYPES and has_proof_value:
            satisfied.add(canonical)
    checklist = [{
        'type': ev_type,
        'label': TASK_EVIDENCE_TYPE_LABELS.get(ev_type, str(ev_type).replace('_', ' ').title()),
        'satisfied': ev_type in satisfied,
    } for ev_type in required_types]
    missing = [item['type'] for item in checklist if not item['satisfied']]
    status = 'not-required' if not required else 'passed' if not missing else 'blocked'
    return {
        'required': required,
        'requiredTypes': required_types,
        'satisfiedTypes': [ev_type for ev_type in required_types if ev_type in satisfied],
        'missingTypes': missing,
        'status': status,
        'completionBlocked': bool(required and missing),
        'checklist': checklist,
        'acceptedTypes': list(DEFAULT_TASK_EVIDENCE_TYPES),
        'summary': 'Evidence gate passed.' if required and not missing else 'Attach required evidence before marking complete.' if required else 'Evidence gate is not required for this task.',
    }



def task_mission_result_payload(task, details=None, comments=None, events=None, runs=None):
    details = details or {}
    comments = comments or []
    events = events or []
    runs = runs or []
    now_iso = task.get('updated_at') or task.get('created_at') or iso(time.time())
    status = task.get('status') or 'queued'
    mission_status = 'completed' if status == 'done' else 'failed' if status == 'error' else 'blocked' if status == 'blocked' else 'draft'
    work_item = {
        'id': task.get('id'),
        'kind': 'task',
        'title': task.get('title') or 'Mission Control task',
        'projectId': task.get('tenant'),
        'projectName': task.get('tenant'),
        'agentId': task.get('assignee'),
        'agentName': task.get('assignee'),
        'status': status,
    }
    summary = details.get('summary') or task.get('result') or task.get('body') or 'No result summary has been recorded yet.'
    artifacts = [normalize_task_artifact(task, item, idx, now_iso) for idx, item in enumerate(list(details.get('artifacts') or []))]
    if details.get('artifact') and not artifacts:
        artifact_ref = str(details.get('artifact'))
        artifacts.append(normalize_task_artifact(task, {
            'id': f"{task.get('id')}-artifact",
            'title': artifact_ref.split('/')[-1] or 'Result artifact',
            'summary': 'Proof-of-work artifact recorded in the task result.',
            'path': artifact_ref,
            'createdAt': now_iso,
            'createdBy': task.get('assignee') or 'mission-control',
        }, 0, now_iso))
    evidence = [normalize_task_evidence(task, item, idx, 'log', now_iso) for idx, item in enumerate(list(details.get('evidence') or []))]
    evidence_gate = task_evidence_gate_state(task, details, comments, events, runs)
    evidence_label = 'run evidence'
    if task.get('session_id'):
        evidence.append(normalize_task_evidence(task, {'id': f"{task.get('id')}-session", 'kind': 'session', 'type': 'session', 'title': 'Agent session', 'summary': f'{evidence_label} linked from the delegated work session.', 'source': 'Hermes session', 'sourceId': task.get('session_id'), 'sessionId': task.get('session_id'), 'createdAt': now_iso, 'confidence': 'high'}, len(evidence), 'session', now_iso))
    for run in runs[:5]:
        evidence.append(normalize_task_evidence(task, {'id': f"{task.get('id')}-run-{run.get('id')}", 'kind': 'tool-call', 'type': 'run', 'title': f"Run evidence · {run.get('status')}", 'summary': run.get('summary') or run.get('error') or run.get('outcome') or 'Worker run recorded.', 'source': 'Mission Control task run', 'sourceId': str(run.get('id')), 'runId': str(run.get('id')), 'createdAt': run.get('started_at') or now_iso, 'confidence': 'high'}, len(evidence), 'tool-call', now_iso))
    for event in events[:5]:
        evidence.append(normalize_task_evidence(task, {'id': f"{task.get('id')}-event-{event.get('id') or event.get('created_at')}", 'kind': 'log', 'type': 'task_event', 'title': f"Task event · {event.get('kind')}", 'summary': preview_content(json.dumps(event.get('payload'), default=str), 240) if event.get('payload') is not None else 'Task lifecycle event.', 'source': 'Mission Control task event', 'sourceId': str(event.get('id') or ''), 'reference': event.get('kind'), 'createdAt': event.get('created_at') or now_iso, 'confidence': 'medium'}, len(evidence), 'log', now_iso))
    for comment in comments[:5]:
        evidence.append(normalize_task_evidence(task, {'id': f"{task.get('id')}-comment-{comment.get('id') or comment.get('created_at')}", 'kind': 'human-note', 'type': 'human_note', 'title': f"Operator note · {comment.get('author')}", 'summary': comment.get('body'), 'source': 'Mission Control comment', 'sourceId': str(comment.get('id') or ''), 'reference': comment.get('author'), 'createdAt': comment.get('created_at') or now_iso, 'confidence': 'medium'}, len(evidence), 'human-note', now_iso))
    approval_gates = list(details.get('approval_gates') or [])
    approval_policy = agent_os_approval_policy({
        'title': task.get('title'),
        'body': task.get('body'),
        'result': task.get('result'),
        'approval_required': bool(details.get('approval_policy', {}).get('required')) if isinstance(details.get('approval_policy'), dict) else False,
    })
    approval_status = 'pending' if approval_policy.get('required') and task.get('status') != 'done' else 'approved' if approval_policy.get('required') else 'not-required'
    if not approval_gates and approval_policy.get('required'):
        approval_gates.append({'id': f"{task.get('id')}-approval_gate", 'title': 'Approval Gate', 'risk': approval_policy.get('risk') or 'approval-required', 'status': approval_status, 'reason': ' '.join(approval_policy.get('reasons') or ['Approval gate required by Mission Control policy.']), 'requestedBy': task.get('assignee') or 'mission-control', 'sourceRef': work_item})
    next_actions = list(details.get('next_actions') or [])
    if not next_actions:
        if evidence_gate.get('completionBlocked'):
            next_actions = ['Attach required evidence before completion', 'Re-run proof checks for missing evidence types', 'Update result summary and evidence']
        elif task.get('status') == 'done':
            next_actions = ['Review proof of work', 'Archive or reuse the artifact', 'Record any follow-up task']
        elif approval_status == 'pending':
            next_actions = ['Review Approval Gate', 'Approve, reject, or request changes', 'Attach final proof once complete']
        else:
            next_actions = ['Run the delegated task', 'Attach proof of work', 'Update result summary and evidence']
    return {
        'id': f"result-{task.get('id')}",
        'workItem': work_item,
        'summary': preview_content(str(summary), 1000),
        'status': mission_status,
        'artifacts': artifacts,
        'evidence': evidence,
        'evidenceGate': evidence_gate,
        'approvalGates': approval_gates,
        'nextActions': next_actions,
        'startedAt': task.get('started_at'),
        'completedAt': task.get('completed_at'),
    }


def task_run_verification_state(task, events=None, runs=None, child_states=None, root=False):
    """Compute verification state for a task/subagent subtree without exposing raw payloads.

    Failed/blocked verification signals are completion blockers. Normal historical run crashes are
    shown in the run tree but do not by themselves block completion unless a verification/self-check
    event or result payload marks the work failed.
    """
    events = events or []
    runs = runs or []
    child_states = child_states or []
    blockers = []
    passed = False
    details = task.get('result_details') if isinstance(task, dict) else None
    if isinstance(details, dict):
        verification = details.get('verification') or details.get('verification_result') or details.get('verificationResult')
        if isinstance(verification, dict):
            status = str(verification.get('status') or verification.get('result') or verification.get('outcome') or '').lower()
            if status in ('failed', 'fail', 'error', 'blocked', 'rejected'):
                blockers.append(preview_content(str(verification.get('reason') or verification.get('summary') or 'Result verification failed'), 260))
            elif status in ('passed', 'pass', 'success', 'verified'):
                passed = True
        for gate in details.get('approval_gates') or details.get('approvalGates') or []:
            if isinstance(gate, dict) and str(gate.get('status') or '').lower() in ('pending', 'rejected', 'changes-requested'):
                blockers.append(preview_content(str(gate.get('reason') or gate.get('title') or 'Approval gate not cleared'), 260))
    for event in events:
        kind = str(event.get('kind') or '').lower()
        payload = event.get('payload') if isinstance(event, dict) else None
        if not any(marker in kind for marker in ('verification', 'self_check', 'self-check', 'qa', 'review_required')):
            continue
        payload = payload if isinstance(payload, dict) else {}
        status = str(payload.get('status') or payload.get('result') or payload.get('outcome') or payload.get('verification_status') or '').lower()
        if status in ('failed', 'fail', 'error', 'blocked', 'rejected', 'changes-requested'):
            blockers.append(preview_content(str(payload.get('reason') or payload.get('summary') or payload.get('message') or f'{kind} failed'), 260))
        elif status in ('passed', 'pass', 'success', 'verified', 'approved'):
            passed = True
    for state in child_states:
        if state.get('blocked'):
            blockers.extend(preview_content(str(reason), 260) for reason in (state.get('blockers') or [state.get('reason') or 'Child subtask verification is blocking completion']))
    # A child task that is explicitly blocked/error blocks its parent. The root can be moved out of
    # blocked after the human/agent resolves it, so its current status alone is not a hard blocker.
    if not root and task.get('status') in ('blocked', 'error'):
        blockers.append(f"Subtask {task.get('id')} is {task.get('status')}")
    blockers = [b for b in dict.fromkeys([b for b in blockers if b])]
    if blockers:
        status = 'blocked' if any('blocked' in b.lower() or 'approval' in b.lower() for b in blockers) else 'failed'
    elif passed or task.get('status') == 'done':
        status = 'passed'
    elif task.get('status') == 'running' or any(str(r.get('status') or '').lower() == 'running' for r in runs):
        status = 'running'
    else:
        status = 'pending'
    return {
        'status': status,
        'blocked': bool(blockers),
        'blockers': blockers,
        'reason': blockers[0] if blockers else ('Verification passed' if status == 'passed' else 'Verification pending'),
        'required_for_completion': True,
    }


def task_run_tree_response(task_id, identity=None):
    tid = safe_id(task_id)
    if not tid:
        return {'ok': False, 'error': 'invalid task id'}, 400
    if identity and not is_admin_identity(identity):
        board = list_workspace_tasks({'q': [tid]}, identity)
        if not any(t.get('id') == tid for t in board.get('tasks') or []):
            return {'ok': False, 'error': 'task not found'}, 404
    con = ensure_kanban_tables()
    try:
        rows = {r['id']: r for r in con.execute("SELECT * FROM tasks WHERE lower(coalesce(status,'')) != 'archived'")}
        if tid not in rows:
            return {'ok': False, 'error': 'task not found'}, 404
        comments_by_task, events_by_task, runs_by_task = {}, {}, {}
        for r in con.execute('SELECT * FROM task_events ORDER BY created_at DESC LIMIT 1400'):
            try:
                payload = json.loads(r['payload']) if r['payload'] else None
            except Exception:
                payload = preview_content(r['payload'], 500)
            events_by_task.setdefault(r['task_id'], []).append({'id': r['id'], 'kind': r['kind'], 'payload': payload, 'created_at': iso(r['created_at']), 'run_id': r['run_id']})
        for r in con.execute('SELECT * FROM task_comments ORDER BY created_at DESC LIMIT 800'):
            comments_by_task.setdefault(r['task_id'], []).append({'id': r['id'], 'author': r['author'], 'body': preview_content(r['body'], 700), 'created_at': iso(r['created_at'])})
        for r in con.execute('SELECT * FROM task_runs ORDER BY started_at DESC LIMIT 1000'):
            runs_by_task.setdefault(r['task_id'], []).append(task_run_record(r))
        child_map, parent_map = {}, {}
        for r in con.execute('SELECT parent_id, child_id FROM task_links'):
            child_map.setdefault(r['parent_id'], []).append(r['child_id'])
            parent_map.setdefault(r['child_id'], []).append(r['parent_id'])
    finally:
        con.close()

    visited = set()
    def build_node(node_id, depth=0):
        if node_id in visited or node_id not in rows or depth > 12:
            return None
        visited.add(node_id)
        task = task_row(rows[node_id], comments_by_task.get(node_id, [])[:5], events_by_task.get(node_id, [])[:10], runs_by_task.get(node_id, [])[:8], child_map.get(node_id, []), parent_map.get(node_id, []))
        children = [child for cid in child_map.get(node_id, []) for child in [build_node(cid, depth + 1)] if child]
        child_states = [c.get('verification') or {} for c in children]
        verification = task_run_verification_state(task, task.get('events'), task.get('runs'), child_states, root=(node_id == tid))
        run_nodes = []
        for run in task.get('runs') or []:
            run_events = [event for event in task.get('events') or [] if event.get('run_id') == run.get('id')]
            run_verification = task_run_verification_state({**task, 'status': task.get('status')}, run_events, [run], [], root=True)
            run_nodes.append({
                'id': f"run:{run.get('id')}", 'run_id': run.get('id'), 'task_id': node_id, 'parent_id': f"task:{node_id}",
                'agent': run.get('profile') or task.get('assignee'), 'model': task.get('model_override'), 'toolsets': task.get('skills') or [],
                'step_key': run.get('step_key') or task.get('current_step_key'), 'status': run.get('status'), 'outcome': run.get('outcome'),
                'async_status': run.get('async_status'), 'completion_cause': run.get('completion_cause'),
                'runtime_id': run.get('runtime_id'), 'profile_id': run.get('profile_id'), 'spawned_by': run.get('spawned_by'),
                'metadata': run.get('metadata') or {},
                'started_at': run.get('started_at'), 'ended_at': run.get('ended_at'), 'output': run.get('summary') or run.get('error') or '',
                'verification': run_verification,
            })
        return {
            'id': f"task:{node_id}", 'task_id': node_id, 'title': task.get('title'), 'subtask': node_id != tid,
            'agent': task.get('assignee'), 'parent_task_ids': task.get('parents') or [], 'child_task_ids': task.get('children') or [],
            'model': task.get('model_override'), 'toolsets': task.get('skills') or [], 'step_key': task.get('current_step_key'),
            'status': task.get('status'), 'output': task.get('result') or (task.get('result_details') or {}).get('summary') or '',
            'verification': verification, 'runs': run_nodes, 'children': children,
        }
    root = build_node(tid)
    all_nodes = []
    def collect(node):
        if not node: return
        all_nodes.append(node)
        for child in node.get('children') or []:
            collect(child)
    collect(root)
    blocking = [node for node in all_nodes if (node.get('verification') or {}).get('blocked')]
    summary = {
        'total_tasks': len(all_nodes),
        'total_runs': sum(len(node.get('runs') or []) for node in all_nodes),
        'blocked_nodes': len(blocking),
        'status': 'blocked' if blocking else ((root or {}).get('verification') or {}).get('status', 'pending'),
        'completion_blocked': bool(blocking),
        'blocking_reasons': [reason for node in blocking for reason in ((node.get('verification') or {}).get('blockers') or [])][:8],
    }
    return {'ok': True, 'task_id': tid, 'run_tree': {'root': root, 'summary': summary, 'verification': (root or {}).get('verification') or {}}}, 200


def task_row(row, comments=None, events=None, runs=None, children=None, parents=None):
    started = row['started_at']
    completed = row['completed_at']
    updated_ts = completed or row['last_heartbeat_at'] or started or row['created_at']
    status = normalize_task_status(row['status'])
    result_text = row['result'] or ''
    result_details = task_result_details(result_text)
    skills = []
    if row['skills']:
        try:
            skills = json.loads(row['skills']) if isinstance(row['skills'], str) else row['skills']
            if not isinstance(skills, list):
                skills = []
        except Exception:
            skills = []
    return {
        'id': row['id'],
        'title': row['title'],
        'body': preview_content(row['body'] or '', 1400),
        'assignee': row['assignee'] or 'unassigned',
        'status': status,
        'raw_status': row['status'],
        'priority': int(row['priority'] or 0),
        'priority_label': task_priority_label(row['priority']),
        'created_by': row['created_by'] or 'mission-control',
        'created_at': iso(row['created_at']),
        'updated_at': iso(updated_ts),
        'started_at': iso(started) if started else None,
        'completed_at': iso(completed) if completed else None,
        'workspace_kind': row['workspace_kind'] or 'scratch',
        'workspace_path': row['workspace_path'],
        'branch_name': row['branch_name'],
        'tenant': row['tenant'],
        'result': preview_content(result_text, 1600),
        'result_details': result_details,
        'guard_policy': hmc_guard_policy(row['tenant'], row, result_details),
        'mission_result': None,
        'run_tree': None,
        'session_id': row['session_id'],
        'current_run_id': row['current_run_id'],
        'workflow_template_id': row['workflow_template_id'],
        'current_step_key': row['current_step_key'],
        'skills': skills,
        'model_override': row['model_override'],
        'consecutive_failures': row['consecutive_failures'] or 0,
        'last_failure_error': preview_content(row['last_failure_error'] or '', 500),
        'comments': comments or [],
        'events': events or [],
        'runs': runs or [],
        'children': children or [],
        'parents': parents or [],
    }


def list_task_board(filters=None, identity=None):
    if identity and not is_admin_identity(identity):
        return list_workspace_tasks(filters, identity)
    filters = filters or {}
    ensure_kanban_tables().close()
    q = (filters.get('q') or [''])[0].strip().lower()
    status_filter = normalize_task_status((filters.get('status') or [''])[0]) if (filters.get('status') or [''])[0] else ''
    assignee = (filters.get('assignee') or [''])[0].strip().lower()
    project = ((filters.get('project') or filters.get('tenant') or [''])[0]).strip().lower()
    all_sources = kanban_board_sources()
    board_selectors = task_board_filter_values(filters, 'board', 'board_id', 'board_slug', 'source', 'source_id', 'source_slug')
    sources, selector_warnings = filter_kanban_board_sources(all_sources, board_selectors)
    # Mission Control aggregates HMC-relevant Kanban task sources: the live
    # default board, profile-local Kanban DBs, and named project boards. Tenant
    # remains the user-facing Project dimension; board/source filters are an
    # advanced provenance selector and are applied separately from project.
    tasks = []
    warnings = list(selector_warnings)
    seen_ids = set()

    for source in sources:
        con = None
        try:
            if source.get('is_default') and not Path(source['path']).exists():
                continue
            con = kanban_board_connect(source['path'], readonly=True)
            if not kanban_board_has_tasks_table(con):
                warnings.append({'board': source.get('slug'), 'status': 'skipped', 'reason': 'missing tasks table'})
                continue
            rows = con.execute("""
                SELECT * FROM tasks
                WHERE lower(coalesce(status, '')) != 'archived'
                ORDER BY COALESCE(last_heartbeat_at, started_at, completed_at, created_at) DESC, created_at DESC
                LIMIT 3000
            """).fetchall()
            # Board loads must stay lightweight: cards only need task summaries,
            # counts, and relationship ids. Comments/events/runs are fetched on
            # demand via /api/tasks/<id>/result when the drawer opens. Preserve
            # comment search only when the operator provides a text query.
            include_activity = bool(q)
            comments_by_task = read_task_comments(con, 600) if include_activity else {}
            events_by_task = read_task_events(con, 900) if include_activity else {}
            runs_by_task = read_task_runs(con, 500) if include_activity else {}
            child_map, parent_map = read_task_links(con)
            for r in rows:
                tid = r['id']
                # Keep all sources until after cross-source sorting. If a task
                # exists in more than one DB, the freshest copy wins so HMC
                # reflects the latest worker/profile status instead of a stale
                # synced default-board row.
                task = task_row(r, comments_by_task.get(tid, [])[:5], events_by_task.get(tid, [])[:8], runs_by_task.get(tid, [])[:5], child_map.get(tid, []), parent_map.get(tid, []))
                if not include_activity:
                    task['body'] = preview_content(task.get('body') or '', 520)
                    task['result'] = preview_content(task.get('result') or '', 260)
                    task['result_details'] = {}
                    task['comments'] = []
                    task['events'] = []
                    task['runs'] = []
                task['_sort_ts'] = sortable_time_value(r['last_heartbeat_at'] or r['started_at'] or r['completed_at'] or r['created_at'] or 0)
                task['_created_sort_ts'] = sortable_time_value(r['created_at'] or 0)
                task['_active_rank'] = 0 if task.get('status') == 'done' else 1
                tasks.append(with_task_board_identity(task, source))
        except sqlite3.DatabaseError as e:
            warnings.append({'board': source.get('slug'), 'status': 'skipped', 'reason': 'sqlite error'})
        except Exception:
            warnings.append({'board': source.get('slug'), 'status': 'skipped', 'reason': 'read error'})
        finally:
            if con:
                con.close()

    tasks.sort(key=lambda t: (t.get('_active_rank') or 0, t.get('_sort_ts') or 0, t.get('_created_sort_ts') or 0), reverse=True)
    deduped_tasks = []
    seen_ids = set()
    for t in tasks:
        tid = t.get('id')
        if tid in seen_ids:
            continue
        seen_ids.add(tid)
        deduped_tasks.append(t)
    tasks = deduped_tasks
    for t in tasks:
        t.pop('_sort_ts', None)
        t.pop('_created_sort_ts', None)
        t.pop('_active_rank', None)
    # Cron watchdog/automation attention rows use synthetic tenants like
    # `cron:<job_id>`. They are task provenance, not user-facing Projects, so
    # keep the tasks visible but remove those synthetic tenants from the
    # Project filter/summary.
    projects = sorted({
        t['tenant'] for t in tasks
        if t.get('tenant') and not str(t.get('tenant') or '').lower().startswith('cron')
    })
    boards = [public_kanban_board_source(s) for s in all_sources]
    active_boards = sorted({t.get('board_slug') for t in tasks if t.get('board_slug')})
    if q:
        tasks = [t for t in tasks if q in ' '.join([
            t['id'], t['title'], t['body'], t['assignee'], t['created_by'], t.get('tenant') or '',
            t.get('workspace_path') or '', t.get('result') or '', ' '.join(t.get('skills') or []),
            t.get('board_slug') or '', t.get('board_label') or '',
            ' '.join(c.get('body') or '' for c in t.get('comments') or []),
        ]).lower()]
    if status_filter:
        tasks = [t for t in tasks if t['status'] == status_filter]
    if assignee:
        tasks = [t for t in tasks if assignee in (t['assignee'] or '').lower()]
    if project:
        tasks = [t for t in tasks if project == (t.get('tenant') or '').lower()]
    lanes = {'triage': [], 'todo': [], 'scheduled': [], 'ready': [], 'running': [], 'blocked': [], 'error': [], 'review': [], 'done': []}
    def lane_task_summary(t):
        return {
            'id': t.get('id'),
            'title': t.get('title'),
            'status': t.get('status'),
            'assignee': t.get('assignee'),
            'priority': t.get('priority'),
            'tenant': t.get('tenant'),
            'updated_at': t.get('updated_at'),
            'board_slug': t.get('board_slug'),
            'board_label': t.get('board_label'),
        }
    for t in tasks:
        lanes.setdefault(t['status'], []).append(lane_task_summary(t))
    summary = {
        'total': len(tasks),
        'triage': len(lanes.get('triage', [])),
        'todo': len(lanes.get('todo', [])),
        'scheduled': len(lanes.get('scheduled', [])),
        'ready': len(lanes.get('ready', [])),
        'running': len(lanes.get('running', [])),
        'blocked': len(lanes.get('blocked', [])),
        'error': len(lanes.get('error', [])),
        'review': len(lanes.get('review', [])),
        'done': len(lanes.get('done', [])),
        'assignees': sorted({t['assignee'] for t in tasks if t['assignee']}),
        'projects': projects,
        'boards': active_boards,
    }
    return {'tasks': tasks, 'lanes': lanes, 'summary': summary, 'statuses': ['triage','todo','scheduled','ready','running','blocked','error','review','done'], 'projects': projects, 'boards': boards, 'sources': boards, 'board_errors': warnings, 'warnings': warnings}

def normalize_agent_handoff_status(status):
    value = str(status or 'requested').strip().lower().replace(' ', '_').replace('-', '_')
    mapping = {
        'draft': 'requested', 'request': 'requested', 'requested': 'requested', 'queued': 'requested',
        'accepted': 'accepted', 'acknowledged': 'accepted', 'running': 'in_progress', 'in_progress': 'in_progress',
        'blocked': 'blocked', 'waiting': 'blocked', 'done': 'completed', 'complete': 'completed', 'completed': 'completed',
        'failed': 'failed', 'error': 'failed', 'cancelled': 'cancelled', 'canceled': 'cancelled',
    }
    return mapping.get(value, 'requested')


def normalize_agent_handoff_risk(risk):
    value = str(risk or 'medium').strip().lower()
    if value in ('low', 'medium', 'high', 'critical'):
        return value
    return 'medium'


def agent_handoff_row(row):
    evidence = []
    try:
        parsed = json.loads(row['evidence']) if row['evidence'] else []
        evidence = parsed if isinstance(parsed, list) else [parsed]
    except Exception:
        evidence = [{'kind': 'note', 'summary': preview_content(row['evidence'] or '', 500)}] if row['evidence'] else []
    return {
        'id': row['id'],
        'from_agent': row['from_agent'],
        'to_agent': row['to_agent'],
        'task_id': row['task_id'],
        'objective': preview_content(row['objective'] or '', 700),
        'context': preview_content(row['context'] or '', 1200),
        'requested_output': preview_content(row['requested_output'] or '', 700),
        'risk': normalize_agent_handoff_risk(row['risk']),
        'status': normalize_agent_handoff_status(row['status']),
        'evidence': evidence,
        'created_by': row['created_by'] or 'mission-control',
        'created_at': iso(row['created_at']),
        'updated_at': iso(row['updated_at']),
    }


def list_agent_handoffs(filters=None, identity=None):
    filters = filters or {}
    ensure_kanban_tables().close()
    con = kanban_connect(True)
    try:
        rows = con.execute('SELECT * FROM agent_handoffs ORDER BY updated_at DESC, created_at DESC LIMIT 300').fetchall()
    finally:
        con.close()
    handoffs = [agent_handoff_row(row) for row in rows]
    agent = ((filters.get('agent') or [''])[0] if isinstance(filters.get('agent'), list) else (filters.get('agent') or '')).strip().lower()
    task_id = safe_id((filters.get('task_id') or filters.get('task') or [''])[0] if isinstance(filters.get('task_id') or filters.get('task'), list) else (filters.get('task_id') or filters.get('task') or ''))
    raw_status = (filters.get('status') or [''])[0] if isinstance(filters.get('status'), list) else (filters.get('status') or '')
    status = normalize_agent_handoff_status(raw_status) if raw_status else ''
    if agent:
        handoffs = [h for h in handoffs if agent in (h.get('from_agent') or '').lower() or agent in (h.get('to_agent') or '').lower()]
    if task_id:
        handoffs = [h for h in handoffs if h.get('task_id') == task_id]
    if status:
        handoffs = [h for h in handoffs if h.get('status') == status]
    summary = {
        'total': len(handoffs),
        'open': sum(1 for h in handoffs if h.get('status') in ('requested', 'accepted', 'in_progress', 'blocked')),
        'completed': sum(1 for h in handoffs if h.get('status') == 'completed'),
        'blocked': sum(1 for h in handoffs if h.get('status') == 'blocked'),
        'high_risk': sum(1 for h in handoffs if h.get('risk') in ('high', 'critical')),
    }
    return {'ok': True, 'handoffs': handoffs, 'summary': summary, 'statuses': ['requested','accepted','in_progress','blocked','completed','failed','cancelled']}


def create_agent_handoff(payload, identity=None):
    from_agent = safe_id(payload.get('from_agent') or payload.get('fromAgent') or payload.get('source_agent') or payload.get('sourceAgent') or '')
    to_agent = safe_id(payload.get('to_agent') or payload.get('toAgent') or payload.get('target_agent') or payload.get('targetAgent') or '')
    objective = str(payload.get('objective') or '').strip()
    requested_output = str(payload.get('requested_output') or payload.get('requestedOutput') or '').strip()
    if not from_agent or not to_agent:
        return {'ok': False, 'error': 'from_agent and to_agent are required'}, 400
    if not objective:
        return {'ok': False, 'error': 'objective required'}, 400
    if not requested_output:
        return {'ok': False, 'error': 'requested_output required'}, 400
    now = int(time.time())
    handoff_id = safe_id(payload.get('id') or f"handoff-{now}-{from_agent[:18]}-{to_agent[:18]}")
    task_id = safe_id(payload.get('task_id') or payload.get('taskId') or '') or None
    evidence = payload.get('evidence') or []
    if isinstance(evidence, str):
        evidence_value = evidence
    else:
        evidence_value = json.dumps(evidence if isinstance(evidence, list) else [evidence])
    con = ensure_kanban_tables()
    try:
        if task_id and not con.execute('SELECT id FROM tasks WHERE id=?', (task_id,)).fetchone():
            return {'ok': False, 'error': 'task not found'}, 404
        con.execute('''INSERT INTO agent_handoffs
            (id,from_agent,to_agent,task_id,objective,context,requested_output,risk,status,evidence,created_by,created_at,updated_at)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)''', (
            handoff_id, from_agent, to_agent, task_id, objective, str(payload.get('context') or ''), requested_output,
            normalize_agent_handoff_risk(payload.get('risk')), normalize_agent_handoff_status(payload.get('status')), evidence_value,
            payload.get('created_by') or payload.get('createdBy') or (identity or {}).get('username') or 'mission-control', now, now,
        ))
        if task_id:
            con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                        (task_id, None, 'agent_handoff_created', json.dumps({'handoff_id': handoff_id, 'from_agent': from_agent, 'to_agent': to_agent, 'risk': normalize_agent_handoff_risk(payload.get('risk')), 'status': normalize_agent_handoff_status(payload.get('status'))}), now))
        con.commit()
        row = con.execute('SELECT * FROM agent_handoffs WHERE id=?', (handoff_id,)).fetchone()
        return {'ok': True, 'handoff': agent_handoff_row(row)}, 201
    except sqlite3.IntegrityError:
        return {'ok': False, 'error': 'handoff id already exists'}, 409
    finally:
        con.close()


def update_agent_handoff(handoff_id, payload, identity=None):
    hid = safe_id(handoff_id)
    if not hid:
        return {'ok': False, 'error': 'invalid handoff id'}, 400
    con = ensure_kanban_tables()
    row = con.execute('SELECT * FROM agent_handoffs WHERE id=?', (hid,)).fetchone()
    if not row:
        con.close(); return {'ok': False, 'error': 'handoff not found'}, 404
    allowed = {'objective','context','requested_output','risk','status','evidence'}
    updates, values, event_payload = [], [], {}
    now = int(time.time())
    for key in allowed:
        camel = ''.join([key.split('_')[0], *[part.title() for part in key.split('_')[1:]]])
        if key in payload or camel in payload:
            val = payload.get(key, payload.get(camel))
            if key == 'status': val = normalize_agent_handoff_status(val)
            if key == 'risk': val = normalize_agent_handoff_risk(val)
            if key == 'evidence' and not isinstance(val, str): val = json.dumps(val if isinstance(val, list) else [val])
            updates.append(f'{key}=?'); values.append(val); event_payload[key] = val
    if not updates:
        con.close(); return {'ok': False, 'error': 'no editable fields provided'}, 400
    updates.append('updated_at=?'); values.append(now); values.append(hid)
    con.execute(f"UPDATE agent_handoffs SET {', '.join(updates)} WHERE id=?", values)
    if row['task_id']:
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                    (row['task_id'], None, 'agent_handoff_updated', json.dumps({'handoff_id': hid, **event_payload}), now))
    con.commit()
    next_row = con.execute('SELECT * FROM agent_handoffs WHERE id=?', (hid,)).fetchone()
    result = {'ok': True, 'handoff': agent_handoff_row(next_row)}
    con.close()
    return result, 200




def spec_kit_intake_artifacts(title, intent, project_id, acceptance, assumptions, created_by='mission-control'):
    """Build Spec Kit-inspired requirement artifacts before MC task execution.

    This is intentionally local/deterministic: it captures the structured
    artifact layer Mission Control needs before workers execute. It does not
    run external generators or mutate production systems.
    """
    now_iso = iso(time.time())
    title = str(title or 'Untitled requirement').strip()[:180]
    intent = str(intent or '').strip()
    acceptance_items = [str(x).strip() for x in (acceptance or []) if str(x).strip()]
    assumption_items = [str(x).strip() for x in (assumptions or []) if str(x).strip()]
    if not acceptance_items:
        acceptance_items = ['Define measurable acceptance criteria before implementation starts.']
    if not assumption_items:
        assumption_items = ['No assumptions captured yet; unresolved requirements must be clarified before execution.']
    spec_md = (
        f"# Feature Spec: {title}\n\n"
        "## User / business intent\n"
        f"{intent or 'Intent not provided.'}\n\n"
        "## User stories / journeys\n"
        f"- As an operator, I need {title} so that the work can be executed through Mission Control with evidence and auditability.\n\n"
        "## Acceptance criteria\n" + ''.join(f"- {item}\n" for item in acceptance_items) + "\n"
        "## Edge cases / risks\n"
        "- External-facing, destructive, credential, DNS, database, and publish actions stay approval-gated.\n"
        "- Any [NEEDS CLARIFICATION] item blocks worker execution until resolved.\n\n"
        "## Assumptions\n" + ''.join(f"- {item}\n" for item in assumption_items)
    )
    plan_md = (
        f"# Implementation Plan: {title}\n\n"
        f"Project: `{project_id or 'mission-control'}`\n\n"
        "## Standard path\n"
        "1. Clarify unresolved requirements and acceptance criteria.\n"
        "2. Confirm affected systems, data, credentials, and approval boundaries.\n"
        "3. Create narrow Mission Control tasks from the approved spec.\n"
        "4. Execute via assigned agent/worker with real evidence.\n"
        "5. Attach tests/build logs/browser checks/deploy proof before marking done.\n\n"
        "## Guardrails\n"
        "- Do not mutate production databases, DNS, cloud resources, or externally visible content without explicit approval.\n"
        "- Prefer small reversible changes and preserve rollback/provenance.\n"
    )
    tasks_md = (
        f"# Task Breakdown: {title}\n\n"
        "- Clarify requirement gaps and explicit non-goals.\n"
        "- Draft/approve feature spec and acceptance checks.\n"
        "- Convert approved plan into execution cards.\n"
        "- Run implementation with evidence gates.\n"
        "- Review output, attach verification, and close only when evidence is complete.\n"
    )
    artifacts = [
        {'id': 'spec-kit-feature-spec', 'kind': 'note', 'title': 'Feature spec', 'summary': spec_md, 'createdAt': now_iso, 'createdBy': created_by},
        {'id': 'spec-kit-implementation-plan', 'kind': 'note', 'title': 'Implementation plan', 'summary': plan_md, 'createdAt': now_iso, 'createdBy': created_by},
        {'id': 'spec-kit-task-breakdown', 'kind': 'note', 'title': 'Task breakdown', 'summary': tasks_md, 'createdAt': now_iso, 'createdBy': created_by},
    ]
    evidence = [
        {'id': 'spec-kit-intake-created', 'kind': 'source', 'title': 'Structured requirements intake created', 'summary': 'Mission Control captured Spec Kit-style artifacts before worker execution.', 'source': 'Mission Control Spec Kit intake', 'createdAt': now_iso, 'created_at': now_iso, 'confidence': 'high'},
        {'id': 'spec-kit-acceptance-captured', 'kind': 'human-note', 'title': 'Acceptance criteria captured', 'summary': '; '.join(acceptance_items), 'source': 'operator-input', 'createdAt': now_iso, 'created_at': now_iso, 'confidence': 'medium'},
    ]
    return artifacts, evidence


def create_spec_kit_intake(payload, identity=None):
    title = str(payload.get('title') or payload.get('name') or '').strip()[:180]
    intent = str(payload.get('intent') or payload.get('request') or payload.get('body') or '').strip()
    if not title:
        return {'ok': False, 'error': 'title required'}, 400
    if not intent:
        return {'ok': False, 'error': 'intent/request required'}, 400
    project_id = safe_id(payload.get('projectId') or payload.get('project_id') or payload.get('tenant') or 'mission-control') or 'mission-control'
    assignee = safe_id(payload.get('assignee') or 'project-task') or 'project-task'
    created_by = (identity or {}).get('username') or payload.get('created_by') or 'mission-control-spec-kit-intake'
    acceptance_raw = payload.get('acceptance') or payload.get('acceptanceCriteria') or payload.get('acceptance_criteria') or []
    if isinstance(acceptance_raw, str):
        acceptance = [line.strip(' -') for line in acceptance_raw.splitlines() if line.strip(' -')]
    elif isinstance(acceptance_raw, list):
        acceptance = acceptance_raw
    else:
        acceptance = []
    assumptions_raw = payload.get('assumptions') or []
    if isinstance(assumptions_raw, str):
        assumptions = [line.strip(' -') for line in assumptions_raw.splitlines() if line.strip(' -')]
    elif isinstance(assumptions_raw, list):
        assumptions = assumptions_raw
    else:
        assumptions = []
    artifacts, evidence = spec_kit_intake_artifacts(title, intent, project_id, acceptance, assumptions, created_by)
    result_payload = {
        'status': 'draft',
        'summary': 'Spec Kit-style requirements artifacts captured before Mission Control execution. Review/clarify this intake before assigning implementation workers.',
        'artifacts': artifacts,
        'evidence': evidence,
        'approval_gates': [{
            'id': 'spec-kit-requirements-approval',
            'title': 'Approve structured requirements before execution',
            'risk': 'approval-required',
            'status': 'pending',
            'reason': 'Feature/product work should not move into worker execution until spec, plan, tasks, and acceptance criteria are reviewed.',
            'requestedBy': created_by,
        }],
        'next_actions': ['Review Feature Spec artifact', 'Resolve [NEEDS CLARIFICATION] items', 'Approve plan and materialize execution tasks', 'Assign implementation workers only after evidence requirements are clear'],
    }
    parent_id = safe_id(payload.get('id') or f"spec-kit-{int(time.time())}-{title[:48]}") or f"spec-kit-{int(time.time())}"
    body = (
        "Spec Kit structured intake before Mission Control task execution.\n\n"
        f"Intent / business ask:\n{intent}\n\n"
        "Acceptance criteria:\n" + ('\n'.join(f"- {x}" for x in (acceptance or [])) or '- [NEEDS CLARIFICATION] measurable acceptance criteria') + "\n\n"
        "Artifacts are attached in the task result: Feature Spec, Implementation Plan, Task Breakdown."
    )
    parent_resp, parent_status = create_task({
        'id': parent_id,
        'title': f"Spec Kit intake: {title}",
        'body': body,
        'assignee': assignee,
        'status': 'blocked',
        'priority': int(payload.get('priority') or 50),
        'tenant': project_id,
        'project_id': project_id,
        'created_by': created_by,
        'result': result_payload,
        'skills': ['writing-plans', 'test-driven-development', 'agent-mission-control-ui'],
        'workflow_template_id': 'spec-kit-requirements-intake',
        'current_step_key': 'requirements-artifacts',
    })
    if parent_status >= 400:
        return parent_resp, parent_status
    child_specs = [
        ('clarify-requirements', 'Clarify requirements and non-goals', 'Resolve [NEEDS CLARIFICATION] items, risks, approval boundaries, and missing acceptance criteria.'),
        ('feature-spec', 'Review feature spec artifact', 'Review the Feature Spec artifact and edit/add comments until business intent and user journeys are clear.'),
        ('implementation-plan', 'Review implementation plan artifact', 'Confirm technical approach, affected systems, rollback/evidence requirements, and approval gates.'),
        ('task-breakdown', 'Materialize execution tasks', 'Convert the approved task breakdown into narrow Mission Control execution cards with owners and required evidence.'),
    ]
    child_tasks = []
    for key, child_title, child_body in child_specs:
        child_id = safe_id(f'{parent_id}-{key}')
        child_resp, child_status = create_task({
            'id': child_id,
            'title': f"{title} · {child_title}",
            'body': child_body + f"\n\nParent intake: {parent_id}",
            'assignee': assignee,
            'status': 'todo' if key == 'clarify-requirements' else 'blocked',
            'priority': int(payload.get('priority') or 45),
            'tenant': project_id,
            'created_by': created_by,
            'parents': [parent_id],
            'skills': ['writing-plans'],
            'workflow_template_id': 'spec-kit-requirements-intake-step',
            'current_step_key': key,
        })
        if child_status < 400:
            child_tasks.append(child_resp.get('task'))
    con = ensure_kanban_tables()
    now = int(time.time())
    try:
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)', (parent_id, None, 'spec_kit_intake_created', json.dumps({'project_id': project_id, 'child_task_ids': [t.get('id') for t in child_tasks if t]}), now))
        con.commit()
    finally:
        con.close()
    return {'ok': True, 'intake': {'id': parent_id, 'projectId': project_id, 'artifactCount': len(artifacts), 'childTaskIds': [t.get('id') for t in child_tasks if t]}, 'task': parent_resp.get('task'), 'child_tasks': child_tasks}, 201
def create_task(payload):
    title = (payload.get('title') or '').strip()
    if not title:
        return {'ok': False, 'error': 'title required'}, 400
    now = int(time.time())
    task_id = safe_id(payload.get('id') or f"hmc-{now}-{title[:32]}")
    status = normalize_task_status(payload.get('status'))
    priority = int(payload.get('priority') or 20)
    skills = payload.get('skills') or []
    if isinstance(skills, str):
        skills = [x.strip() for x in skills.split(',') if x.strip()]
    result_value = payload.get('result')
    if isinstance(result_value, (dict, list)):
        result_value = json.dumps(result_value)
    con = ensure_kanban_tables()
    try:
        con.execute('''INSERT INTO tasks
            (id,title,body,assignee,status,priority,created_by,created_at,started_at,completed_at,workspace_kind,workspace_path,tenant,result,skills,model_override,session_id,workflow_template_id,current_step_key)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)''', (
            task_id, title, payload.get('body') or '', payload.get('assignee') or '', status, priority,
            payload.get('created_by') or 'mission-control', now, now if status == 'running' else None,
            now if status == 'done' else None, payload.get('workspace_kind') or 'scratch', payload.get('workspace_path'),
            payload.get('tenant'), result_value, json.dumps(skills), payload.get('model_override'), payload.get('session_id'),
            payload.get('workflow_template_id'), payload.get('current_step_key')
        ))
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                    (task_id, None, 'created', json.dumps({'source':'hermes-mission-control'}), now))
        parent_ids = []
        raw_parents = payload.get('parents') or payload.get('parent_ids') or []
        if isinstance(raw_parents, str):
            raw_parents = [raw_parents]
        for parent_id in raw_parents:
            parent_id = safe_id(parent_id)
            if parent_id and parent_id != task_id:
                parent_ids.append(parent_id)
        parent_ids = sorted(set(parent_ids))
        for parent_id in parent_ids:
            con.execute('INSERT OR IGNORE INTO task_links(parent_id, child_id) VALUES (?,?)', (parent_id, task_id))
            con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                        (task_id, None, 'linked_parent', json.dumps({'parent_id': parent_id}), now))
        con.commit()
        row = con.execute('SELECT * FROM tasks WHERE id=?', (task_id,)).fetchone()
        event_payloads = [{'id': None, 'kind': 'created', 'payload': {'source':'hermes-mission-control'}, 'created_at': iso(now), 'run_id': None}]
        event_payloads.extend({'id': None, 'kind': 'linked_parent', 'payload': {'parent_id': parent_id}, 'created_at': iso(now), 'run_id': None} for parent_id in parent_ids)
        result = task_row(row, events=event_payloads, parents=parent_ids)
        return {'ok': True, 'task': result}, 201
    except sqlite3.IntegrityError:
        return {'ok': False, 'error': 'task id already exists'}, 409
    finally:
        con.close()


def update_task(task_id, payload):
    tid = safe_id(task_id)
    if not tid:
        return {'ok': False, 'error': 'invalid task id'}, 400
    con = ensure_kanban_tables()
    row = con.execute('SELECT * FROM tasks WHERE id=?', (tid,)).fetchone()
    if not row:
        con.close(); return {'ok': False, 'error': 'task not found'}, 404
    now = int(time.time())
    allowed = {'title','body','assignee','status','priority','workspace_path','tenant','result','model_override','session_id'}
    updates, values, event_payload = [], [], {}
    for key in allowed:
        if key in payload:
            val = payload[key]
            if key == 'status':
                val = normalize_task_status(val)
                if val == 'done':
                    candidate_result = payload.get('result') if 'result' in payload else row['result']
                    if isinstance(candidate_result, (dict, list)):
                        candidate_result = json.dumps(candidate_result)
                    candidate_details = task_result_details(candidate_result) or {}
                    candidate_task = task_row(row)
                    candidate_task['status'] = 'done'
                    candidate_task['result_details'] = candidate_details
                    gate_comments = [{'id': r['id'], 'author': r['author'], 'body': preview_content(r['body'], 700), 'created_at': iso(r['created_at'])} for r in con.execute('SELECT * FROM task_comments WHERE task_id=? ORDER BY created_at DESC LIMIT 10', (tid,))]
                    gate_events = []
                    for r in con.execute('SELECT * FROM task_events WHERE task_id=? ORDER BY created_at DESC LIMIT 20', (tid,)):
                        try:
                            event_payload = json.loads(r['payload']) if r['payload'] else None
                        except Exception:
                            event_payload = preview_content(r['payload'], 500)
                        gate_events.append({'id': r['id'], 'kind': r['kind'], 'payload': event_payload, 'created_at': iso(r['created_at']), 'run_id': r['run_id']})
                    gate_runs = [{'id': r['id'], 'run_id': r['id'], 'profile': r['profile'], 'step_key': r['step_key'], 'status': r['status'], 'started_at': iso(r['started_at']), 'ended_at': iso(r['ended_at']) if r['ended_at'] else None, 'outcome': r['outcome'], 'summary': preview_content(r['summary'] or '', 900), 'error': preview_content(r['error'] or '', 900)} for r in con.execute('SELECT * FROM task_runs WHERE task_id=? ORDER BY started_at DESC LIMIT 5', (tid,))]
                    evidence_gate = task_evidence_gate_state(candidate_task, candidate_details, gate_comments, gate_events, gate_runs)
                    if evidence_gate.get('completionBlocked'):
                        con.close()
                        return {
                            'ok': False,
                            'error': 'completion blocked by missing required evidence',
                            'evidence_gate': evidence_gate,
                            'blocking_reasons': [f"Missing evidence: {', '.join(evidence_gate.get('missingTypes') or [])}"],
                        }, 409
                    tree_payload, tree_status = task_run_tree_response(tid)
                    tree_summary = ((tree_payload.get('run_tree') or {}).get('summary') or {}) if tree_status == 200 else {}
                    if tree_summary.get('completion_blocked'):
                        con.close()
                        return {
                            'ok': False,
                            'error': 'completion blocked by failed verification in subagent run tree',
                            'run_tree': tree_payload.get('run_tree'),
                            'blocking_reasons': tree_summary.get('blocking_reasons') or [],
                        }, 409
                if val == 'running' and not row['started_at']:
                    updates.append('started_at=?'); values.append(now)
                if val == 'done' and not row['completed_at']:
                    updates.append('completed_at=?'); values.append(now)
                if val != 'done' and row['completed_at']:
                    updates.append('completed_at=?'); values.append(None)
            if key == 'priority':
                val = int(val or 0)
            updates.append(f'{key}=?'); values.append(val); event_payload[key] = val
    if 'skills' in payload:
        skills = payload.get('skills') or []
        if isinstance(skills, str):
            skills = [x.strip() for x in skills.split(',') if x.strip()]
        updates.append('skills=?'); values.append(json.dumps(skills)); event_payload['skills'] = skills
    if not updates:
        con.close(); return {'ok': False, 'error': 'no editable fields provided'}, 400
    values.append(tid)
    con.execute(f"UPDATE tasks SET {', '.join(updates)} WHERE id=?", values)
    con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                (tid, None, 'updated', json.dumps(event_payload), now))
    con.commit()
    row = con.execute('SELECT * FROM tasks WHERE id=?', (tid,)).fetchone()
    result = task_row(row)
    con.close()
    return {'ok': True, 'task': result}, 200


def task_artifact_response(task_id, artifact_id, identity=None, download=False):
    payload, status = task_result_response(task_id, identity)
    if status != 200:
        return None, payload, status
    result = payload.get('mission_result') or {}
    artifact = next((a for a in result.get('artifacts') or [] if str(a.get('id')) == str(artifact_id)), None)
    if not artifact:
        return None, {'ok': False, 'error': 'artifact not found'}, 404
    raw = str(artifact.get('path') or '')
    if raw.startswith('http'):
        return None, {'ok': False, 'error': 'artifact is an external link', 'url': raw}, 400
    try:
        target = Path(raw).resolve()
    except Exception:
        return None, {'ok': False, 'error': 'invalid artifact path'}, 400
    allowed_roots = [APP_ROOT.resolve(), HERMES_HOME.resolve(), (HOME / '.openclaw' / 'workspace').resolve()]
    if not any(target == root or target.is_relative_to(root) for root in allowed_roots):
        return None, {'ok': False, 'error': 'artifact path is outside allowed Mission Control roots'}, 403
    if not target.exists() or not target.is_file():
        return None, {'ok': False, 'error': 'artifact file not found'}, 404
    return {'path': target, 'artifact': artifact, 'download': download}, None, 200


def task_result_response(task_id, identity=None):
    tid = safe_id(task_id)
    if not tid:
        return {'ok': False, 'error': 'invalid task id'}, 400
    if identity and not is_admin_identity(identity):
        board = list_workspace_tasks({'q': [tid]}, identity)
        task = next((t for t in board.get('tasks') or [] if t.get('id') == tid), None)
        if not task:
            return {'ok': False, 'error': 'task not found'}, 404
        mission_result = task_mission_result_payload(task, task.get('result_details'), task.get('comments'), task.get('events'), task.get('runs'))
        tree_payload, tree_status = task_run_tree_response(tid, identity)
        run_tree = (tree_payload.get('run_tree') if tree_status == 200 else None)
        handoff_payload = list_agent_handoffs({'task_id': [tid]}, identity)
        task['mission_result'] = mission_result
        task['run_tree'] = run_tree
        task['agent_handoffs'] = handoff_payload.get('handoffs', [])
        return {'ok': True, 'task': task, 'mission_result': mission_result, 'run_tree': run_tree, 'agent_handoffs': task['agent_handoffs']}, 200
    selected = None
    for source in [s for s in kanban_board_sources() if not s.get('is_default')] + [s for s in kanban_board_sources() if s.get('is_default')]:
        con = None
        try:
            if source.get('is_default'):
                ensure_kanban_tables().close()
            if source.get('is_default') and not Path(source['path']).exists():
                continue
            con = kanban_board_connect(source['path'], readonly=True)
            if not kanban_board_has_tasks_table(con):
                continue
            row = con.execute('SELECT * FROM tasks WHERE id=?', (tid,)).fetchone()
            if not row:
                continue
            comments = []
            if kanban_board_has_table(con, 'task_comments'):
                comments = [{'id': r['id'], 'author': r['author'], 'body': preview_content(r['body'], 700), 'created_at': iso(r['created_at'])} for r in con.execute('SELECT * FROM task_comments WHERE task_id=? ORDER BY created_at DESC', (tid,))]
            events = []
            if kanban_board_has_table(con, 'task_events'):
                for r in con.execute('SELECT * FROM task_events WHERE task_id=? ORDER BY created_at DESC', (tid,)):
                    try:
                        payload = json.loads(r['payload']) if r['payload'] else None
                    except Exception:
                        payload = preview_content(r['payload'], 500)
                    events.append({'id': r['id'], 'kind': r['kind'], 'payload': payload, 'created_at': iso(r['created_at']), 'run_id': r['run_id']})
            runs = []
            if kanban_board_has_table(con, 'task_runs'):
                runs = [{'id': r['id'], 'profile': r['profile'], 'step_key': r['step_key'], 'status': r['status'], 'started_at': iso(r['started_at']), 'ended_at': iso(r['ended_at']) if r['ended_at'] else None, 'outcome': r['outcome'], 'summary': preview_content(r['summary'] or '', 900), 'error': preview_content(r['error'] or '', 900)} for r in con.execute('SELECT * FROM task_runs WHERE task_id=? ORDER BY started_at DESC', (tid,))]
            selected = (source, task_row(row, comments=comments, events=events, runs=runs), comments, events, runs)
            break
        except sqlite3.DatabaseError:
            continue
        finally:
            if con:
                con.close()
    if not selected:
        return {'ok': False, 'error': 'task not found'}, 404
    source, task, comments, events, runs = selected
    with_task_board_identity(task, source)
    mission_result = task_mission_result_payload(task, task.get('result_details'), comments, events, runs)
    if source.get('is_default'):
        tree_payload, tree_status = task_run_tree_response(tid, identity)
        run_tree = (tree_payload.get('run_tree') if tree_status == 200 else None)
        handoff_payload = list_agent_handoffs({'task_id': [tid]}, identity)
    else:
        run_tree = None
        handoff_payload = {'handoffs': []}
    task['mission_result'] = mission_result
    task['run_tree'] = run_tree
    task['agent_handoffs'] = handoff_payload.get('handoffs', [])
    return {'ok': True, 'task': task, 'mission_result': mission_result, 'run_tree': run_tree, 'agent_handoffs': task['agent_handoffs']}, 200


def mission_control_action_link(headers=None, view='mission', task=None, approval=None, agent=None):
    params = []
    params.append(('view', view or 'mission'))
    if approval:
        params.append(('approval', safe_id(approval) or str(approval)))
    if task:
        params.append(('task', safe_id(task) or str(task)))
    if agent:
        params.append(('agent', safe_id(agent) or str(agent)))
    query = urlencode(params)
    return f"{connector_public_origin(headers).rstrip('/')}/app?{query}"


def operator_alert_payload(kind, record, headers=None):
    kind = kind or 'task'
    title = record.get('title') or record.get('name') or 'Mission Control item'
    risk = record.get('risk') or record.get('priority_label') or record.get('status') or 'medium'
    agent = record.get('agent_name') or record.get('assignee') or record.get('id') or 'Mission Control'
    if kind == 'approval':
        open_url = mission_control_action_link(headers, 'approvals', approval=record.get('id'))
        action = 'Review, edit if needed, then Approve or Reject.'
        prefix = 'Approval needed'
    elif kind == 'agent':
        open_url = mission_control_action_link(headers, 'agents', agent=record.get('id'))
        action = 'Open the agent chat and send the next operator instruction.'
        prefix = 'Agent handoff'
    else:
        open_url = mission_control_action_link(headers, 'board', task=record.get('id'))
        action = 'Open the task, review proof/blockers, then comment, reassign, or mark reviewed.'
        prefix = 'Task attention needed'
    text = f"{prefix}: {title}\nRisk: {risk}\nAgent: {agent}\nAction: {action}\nOpen: {open_url}"
    return {'title': title, 'risk': str(risk), 'agent': str(agent), 'action': action, 'open': open_url, 'text': text}


def operator_links_preview_payload(query=None, headers=None, identity=None):
    query = query or {}
    examples = []
    task_id = (query.get('task') or [''])[0]
    approval_id = (query.get('approval') or [''])[0]
    agent_id = (query.get('agent') or [''])[0]
    out = {'ok': True, 'examples': examples}
    if task_id:
        result, status = task_result_response(task_id, identity)
        if status == 200 and result.get('task'):
            out['task'] = operator_alert_payload('task', result['task'], headers); examples.append(out['task'])
    if approval_id:
        inbox = list_inbox({'status': ['all']}, identity)
        item = next((i for i in inbox.get('items') or [] if i.get('id') == approval_id), None)
        if item:
            out['approval'] = operator_alert_payload('approval', item, headers); examples.append(out['approval'])
    if agent_id:
        agent_list = list_agents_payload(identity) if identity else list_agents_payload()
        agents = agent_list if isinstance(agent_list, list) else agent_list.get('agents') or []
        item = next((a for a in agents if a.get('id') == agent_id), {'id': agent_id, 'name': agent_id})
        out['agent'] = operator_alert_payload('agent', item, headers); examples.append(out['agent'])
    if not examples:
        # Deep-link examples used by Telegram payload tests/docs: view=approvals&approval=, view=board&task=, view=agents&agent=
        out['examples'] = [
            operator_alert_payload('approval', {'id': 'example-approval', 'title': 'LinkedIn post pack', 'risk': 'medium', 'agent_name': 'Content Ops'}, headers),
            operator_alert_payload('task', {'id': 'example-task', 'title': 'Review blocker evidence', 'priority_label': 'high', 'assignee': 'Melkizac'}, headers),
            operator_alert_payload('agent', {'id': 'melkizac', 'name': 'Melkizac'}, headers),
        ]
    return out


def add_task_comment(task_id, payload):
    tid = safe_id(task_id)
    body = (payload.get('body') or '').strip()
    if not tid or not body:
        return {'ok': False, 'error': 'task id and body required'}, 400
    con = ensure_kanban_tables()
    if not con.execute('SELECT 1 FROM tasks WHERE id=?', (tid,)).fetchone():
        con.close(); return {'ok': False, 'error': 'task not found'}, 404
    now = int(time.time())
    cur = con.execute('INSERT INTO task_comments(task_id,author,body,created_at) VALUES (?,?,?,?)',
                      (tid, payload.get('author') or 'mission-control', body, now))
    con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                (tid, None, 'commented', json.dumps({'comment_id': cur.lastrowid}), now))
    con.commit(); con.close()
    return {'ok': True, 'comment': {'id': cur.lastrowid, 'task_id': tid, 'author': payload.get('author') or 'mission-control', 'body': preview_content(body,700), 'created_at': iso(now)}}, 201


def delete_task(task_id):
    tid = safe_id(task_id)
    if not tid:
        return {'ok': False, 'error': 'invalid task id'}, 400
    con = ensure_kanban_tables()
    con.execute('DELETE FROM task_links WHERE parent_id=? OR child_id=?', (tid, tid))
    con.execute('DELETE FROM task_comments WHERE task_id=?', (tid,))
    con.execute('DELETE FROM task_events WHERE task_id=?', (tid,))
    con.execute('DELETE FROM task_runs WHERE task_id=?', (tid,))
    cur = con.execute('DELETE FROM tasks WHERE id=?', (tid,))
    con.commit(); con.close()
    return {'ok': cur.rowcount > 0}, 200 if cur.rowcount > 0 else 404



def md_title_and_summary(path):
    try:
        content = path.read_text(errors='replace')
    except Exception:
        return path.stem.replace('-', ' ').title(), ''
    default_title = path.stem.replace('-', ' ').title()
    title = default_title
    summary_lines = []
    seen_h1 = False
    for line in content.splitlines()[:80]:
        s = line.strip()
        if not s:
            continue
        if s.startswith('# '):
            if not seen_h1 and title == default_title:
                title = s.lstrip('#').strip() or title
                seen_h1 = True
            continue
        if s.startswith('##'):
            continue
        if not s.startswith('---') and not s.startswith('['):
            summary_lines.append(s.lstrip('- ').strip())
        if len(' '.join(summary_lines)) > 240:
            break
    return trim(title, 100), preview_content(' '.join(summary_lines), 260)


def project_slug(name):
    return safe_id((name or 'project').lower()) or 'project'


def empty_project(slug, name, kind='workspace', path='', source='filesystem'):
    return {
        'id': slug, 'name': name, 'kind': kind, 'status': 'active', 'health': 72, 'progress': 0,
        'summary': '', 'path': path, 'source': source, 'updated_at': '—',
        'actions': {'open': 0, 'running': 0, 'blocked': 0, 'done': 0},
        'risks': [], 'knowledge': [], 'sessions': [], 'artifacts': [], 'workspaces': [], 'activity': [], 'tags': [],
        'portfolio_group': 'Operations',
    }


def project_source_context(project):
    return {
        'id': project.get('id') or project_slug(project.get('name')),
        'kind': project.get('kind') or 'workspace',
        'source': project.get('source') or 'unknown',
        'name': project.get('name') or 'Untitled',
        'path': project.get('path') or '',
    }


def merge_project_record(existing, project):
    existing.setdefault('source_contexts', [])
    seen_ctx = {json.dumps(x, sort_keys=True) for x in existing.get('source_contexts') or []}
    for ctx in (project.get('source_contexts') or [project_source_context(project)]):
        sig = json.dumps(ctx, sort_keys=True)
        if sig not in seen_ctx:
            existing['source_contexts'].append(ctx); seen_ctx.add(sig)
    for key in ('knowledge','sessions','artifacts','workspaces','activity','risks','tags'):
        existing.setdefault(key, [])
        seen = {json.dumps(x, sort_keys=True) if isinstance(x, dict) else str(x) for x in existing[key]}
        for item in project.get(key, []) or []:
            sig = json.dumps(item, sort_keys=True) if isinstance(item, dict) else str(item)
            if sig not in seen:
                existing[key].append(item); seen.add(sig)
    if project.get('path') and project.get('path') != existing.get('path'):
        workspace = {'name': project.get('name') or Path(project.get('path')).name, 'path': project.get('path'), 'kind': project.get('kind'), 'source': project.get('source')}
        seen_ws = {json.dumps(x, sort_keys=True) for x in existing.get('workspaces') or []}
        sig = json.dumps(workspace, sort_keys=True)
        if sig not in seen_ws:
            existing.setdefault('workspaces', []).append(workspace)
    for key in ('open','running','blocked','done'):
        existing.setdefault('actions', {}).setdefault(key, 0)
        existing['actions'][key] += project.get('actions', {}).get(key, 0)
    if project.get('summary') and (not existing.get('summary') or existing.get('source') == 'filesystem'):
        existing['summary'] = project['summary']
    if project.get('updated_at') and (existing.get('updated_at') == '—' or project.get('updated_at') > existing.get('updated_at', '')):
        existing['updated_at'] = project['updated_at']
    priority = {'product': 4, 'knowledge-base': 3, 'knowledge': 2, 'workspace': 1}
    if priority.get(project.get('kind'), 0) > priority.get(existing.get('kind'), 0):
        existing['kind'] = project.get('kind')
    sources = sorted({ctx.get('source') for ctx in existing.get('source_contexts') or [] if ctx.get('source')})
    existing['source'] = ' + '.join(sources) if len(sources) <= 3 else f"{len(sources)} sources"
    return existing


def find_project_merge_target(projects, project, pid):
    path = project.get('path') or ''
    if path:
        for key, existing in projects.items():
            if existing.get('path') == path:
                return key
            if any(w.get('path') == path for w in existing.get('workspaces') or [] if isinstance(w, dict)):
                return key
    if (project.get('source') == 'kanban' or pid.startswith('goal-')) and projects:
        hay = text_blob(project.get('id'), project.get('name'), project.get('summary'), *(a.get('title') for a in project.get('activity') or [] if isinstance(a, dict)))
        candidates = []
        for key, existing in projects.items():
            if existing.get('source') == 'kanban':
                continue
            name_slug = project_slug(existing.get('name'))
            needles = {key, name_slug}
            score = sum(1 for n in needles if n and len(n) > 5 and n in hay)
            if score:
                candidates.append((score, key))
        if candidates:
            return sorted(candidates, reverse=True)[0][1]
    return pid


def add_project(projects, project):
    pid = project.get('id') or project_slug(project.get('name'))
    project.setdefault('source_contexts', [project_source_context(project)])
    pid = find_project_merge_target(projects, project, pid)
    if pid in projects:
        return merge_project_record(projects[pid], project)
    project['id'] = pid
    projects[pid] = project
    return project


def is_temp_workspace_name(name):
    value = (name or '').strip().lower()
    return (
        value.startswith(('tmp-', 'temp-', 'scratch-', 'test-', 'demo-'))
        or value in {'tmp', 'temp', 'scratch', 'untitled', 'playground'}
    )


def is_filesystem_only_project(project):
    contexts = project.get('source_contexts') or []
    if contexts:
        return all((ctx.get('source') or '') == 'filesystem' for ctx in contexts)
    return (project.get('source') or '') == 'filesystem'


def has_project_signal(project):
    actions = project.get('actions') or {}
    active_actions = sum(int(actions.get(k) or 0) for k in ('open', 'running', 'blocked', 'done'))
    # For filesystem-only folders, count only explicit project evidence that exists
    # before fuzzy operating-link enrichment. Generic folders like "skills" can
    # otherwise match every task/automation that merely lists a skill name.
    return active_actions > 0 or len(project.get('knowledge') or []) > 0


def should_show_project(project):
    if is_temp_workspace_name(Path(project.get('path') or project.get('id') or project.get('name') or '').name):
        return False
    pid = project_slug(project.get('id') or project.get('name') or '')
    if is_support_artifact_project(pid):
        return False
    if pid == 'research-to-deliverable-chat-workflow':
        actions = project.get('actions') or {}
        active_actions = sum(int(actions.get(k) or 0) for k in ('open', 'running', 'blocked'))
        return active_actions > 0
    if is_filesystem_only_project(project) and not has_project_signal(project):
        return False
    return True


def is_support_artifact_project(slug):
    value = project_slug(slug)
    return (
        value.startswith(('cron-', 'cron_', 'attention-cron-output-', 'attention_cron_output_', 'approval-reclass-', 'approval_reclass-', 'phase16-', 'phase16_', 'phase17-', 'phase17_', 'phase-', 'phase_', 't-', 't_'))
        or value in {'cron', 'approval-reclass', 'approval_reclass', 'attention-cron-output', 'attention_cron_output', 'test', 'phase16-test', 'phase16_test', 'phase17-test', 'phase17_test', '.hermes', 'hermes', 'linkedin-daily-operating-workflow'}
    )


