def workflow_library_payload(filters=None, identity=None):
    filters = filters or {}
    q = (filters.get('q') or [''])[0].strip().lower()
    category = (filters.get('category') or [''])[0].strip().lower()
    all_workflows = packaged_sme_workflows(identity)
    workflows = all_workflows
    if q:
        workflows = [w for w in workflows if q in ' '.join([w.get('id', ''), w.get('name', ''), w.get('category', ''), w.get('summary', ''), ' '.join(w.get('skills') or [])]).lower()]
    if category:
        workflows = [w for w in workflows if (w.get('category') or '').lower() == category]
    return {
        'workflows': workflows,
        'categories': sorted({w.get('category') or 'Uncategorized' for w in all_workflows}),
        'summary': {
            'total': len(workflows),
            'approval_required': sum(1 for w in workflows if w.get('approvalGates')),
            'skills_linked': sum(len(w.get('skills') or []) for w in workflows),
            'evidence_ready': sum(1 for w in workflows if w.get('evidence') and w.get('artifacts')),
        },
    }


def agent_os_workflow_keywords(text):
    return set(re.findall(r'[a-z0-9]{3,}', str(text or '').lower())) - {
        'the', 'and', 'for', 'with', 'from', 'this', 'that', 'into', 'workflow', 'routine',
        'please', 'safe', 'run', 'launch', 'create', 'make', 'prepare', 'report', 'every',
    }


def agent_os_selected_project_id(route):
    context = (route or {}).get('context') if isinstance((route or {}).get('context'), dict) else {}
    return (route or {}).get('suggested_project_id') or context.get('selected_project_id') or context.get('project_id')


def agent_os_workflow_match_text(workflow):
    parts = [
        workflow.get('id'), workflow.get('name'), workflow.get('category'), workflow.get('summary'),
        workflow.get('idealFor'), workflow.get('projectId'), workflow.get('projectName'),
        workflow.get('agentId'), workflow.get('agentName'), workflow.get('launchPrompt'),
        ' '.join(workflow.get('skills') or []),
        ' '.join(workflow.get('nextActions') or []),
    ]
    for step in workflow.get('steps') or []:
        parts.extend([step.get('id'), step.get('title'), step.get('summary'), step.get('owner')])
    return ' '.join(str(p or '') for p in parts)


def agent_os_score_workflow_template(prompt, workflow, project_id=None):
    prompt_tokens = agent_os_workflow_keywords(prompt)
    workflow_text = agent_os_workflow_match_text(workflow).lower()
    workflow_tokens = agent_os_workflow_keywords(workflow_text)
    overlap = sorted(prompt_tokens & workflow_tokens)
    score = 0.0
    if prompt_tokens:
        score += min(0.55, len(overlap) / max(len(prompt_tokens), 1))
    strong_signals = []
    checks = [
        ('website-funnel-check', ('website', 'funnel', 'check', 'form', 'no-submit', 'nosubmit', 'browser')),
        ('nexius-academy-lead-intake', ('lead', 'academy', 'course', 'signup', 'funnel')),
        ('linkedin-daily-operating-workflow', ('linkedin', 'post', 'publish', 'content', 'engagement')),
    ]
    workflow_id = workflow.get('id') or ''
    lower = str(prompt or '').lower()
    for template_id, terms in checks:
        term_hits = [term for term in terms if term in lower]
        if workflow_id == template_id and len(term_hits) >= 2:
            score += 0.45
            strong_signals.extend(term_hits[:4])
    if project_id:
        project_text = str(project_id).lower()
        if workflow.get('projectId') and str(workflow.get('projectId')).lower() in project_text:
            score += 0.18
            strong_signals.append('selected_project_match')
        elif any(token in workflow_text for token in agent_os_workflow_keywords(project_text)):
            score += 0.08
            strong_signals.append('project_context_overlap')
    if workflow.get('approvalGates'):
        score += 0.03
    return min(round(score, 3), 0.99), agent_os_unique_strings(overlap[:8] + strong_signals)


def agent_os_workflow_reference(workflow, fit_score=None, fit_signals=None):
    return {
        'id': workflow.get('id'),
        'name': workflow.get('name'),
        'category': workflow.get('category'),
        'summary': workflow.get('summary'),
        'projectId': workflow.get('projectId'),
        'projectName': workflow.get('projectName'),
        'agentId': workflow.get('agentId'),
        'agentName': workflow.get('agentName'),
        'risk': workflow.get('risk'),
        'approvalRequired': bool(workflow.get('approvalGates')),
        'launchPrompt': workflow.get('launchPrompt'),
        'fit_score': fit_score,
        'fit_signals': fit_signals or [],
    }


def agent_os_workflow_draft(prompt, route=None):
    route = route or {}
    project_id = agent_os_selected_project_id(route)
    compact = re.sub(r'\s+', ' ', str(prompt or '').strip(' .'))
    if len(compact) > 96:
        compact = compact[:93].rstrip() + '…'
    draft_id = safe_id(f"workflow-draft-{compact[:72]}") or 'workflow-draft-main-chat-request'
    return {
        'id': draft_id,
        'name': compact or 'New workflow draft',
        'status': 'draft',
        'category': 'Operator-defined workflow',
        'summary': 'No packaged /api/workflows template was a high-confidence fit; create a draft workflow from the main-chat request before enabling routines or external actions.',
        'projectId': project_id,
        'agentId': route.get('agent_id') or 'melkizac',
        'risk': 'approval-required',
        'approvalRequired': True,
        'steps': [
            {'id': 'scope', 'title': 'Confirm workflow scope', 'owner': 'Agent', 'summary': 'Turn the request into success criteria, inputs, cadence, and expected evidence.'},
            {'id': 'template', 'title': 'Create workflow template', 'owner': 'Mission Control', 'summary': 'Save reusable steps, owners, tools, skills, approvals, and output artifacts.'},
            {'id': 'review', 'title': 'Review before enablement', 'owner': 'Human review', 'summary': 'Approve the workflow/routine draft before any scheduled or external-facing action runs.'},
        ],
        'nextActions': ['Create workflow draft', 'Review tools/skills/access needs', 'Enable only after approval'],
    }


def agent_os_workflow_advisor(route, identity=None):
    route = route or {}
    prompt = str(route.get('prompt') or '').strip()
    project_id = agent_os_selected_project_id(route)
    candidates = []
    for workflow in packaged_sme_workflows(identity):
        score, signals = agent_os_score_workflow_template(prompt, workflow, project_id)
        candidates.append((score, signals, workflow))
    candidates.sort(key=lambda item: item[0], reverse=True)
    best_score, best_signals, best = candidates[0] if candidates else (0.0, [], None)
    high_fit = bool(best and best_score >= 0.7)
    base = {
        'source': 'api_workflows',
        'project_context': {'selected_project_id': project_id},
        'fit_threshold': 0.7,
        'top_candidates': [agent_os_workflow_reference(w, s, sig) for s, sig, w in candidates[:3]],
    }
    if high_fit:
        return {
            **base,
            'recommendation': 'use_existing_workflow',
            'confidence': 'high',
            'reason': 'A packaged /api/workflows template matches the request and selected Project context with high confidence.',
            'matched_workflow': agent_os_workflow_reference(best, best_score, best_signals),
            'next_actions': ['Show existing workflow recommendation', 'Queue launch task with approval gates', 'Capture workflow evidence in Task Board / Audit Log'],
        }
    return {
        **base,
        'recommendation': 'create_workflow_draft',
        'confidence': 'medium',
        'reason': 'No packaged /api/workflows template crossed the high-confidence fit threshold, so Mission Control should draft a reusable workflow before scheduling or launching it.',
        'draft_workflow': agent_os_workflow_draft(prompt, route),
        'next_actions': ['Generate missing workflow draft', 'Ask only for missing access/business constraints', 'Attach approval gate before enablement'],
    }


def website_funnel_check_launch_config(workflow, payload):
    target_url = str(payload.get('targetUrl') or payload.get('target_url') or payload.get('url') or (workflow.get('launchDefaults') or {}).get('targetUrl') or '').strip()
    if not re.match(r'^https?://', target_url):
        return None, {'ok': False, 'error': 'safe public targetUrl required for Website Funnel Check'}, 400
    blocked_hosts = ('localhost', '127.', '10.', '192.168.', '172.16.', '172.17.', '172.18.', '172.19.', '172.20.', '172.21.', '172.22.', '172.23.', '172.24.', '172.25.', '172.26.', '172.27.', '172.28.', '172.29.', '172.30.', '172.31.')
    host = urlparse(target_url).hostname or ''
    if host.lower().startswith(blocked_hosts):
        return None, {'ok': False, 'error': 'private/local targetUrl is not allowed for Website Funnel Check'}, 400
    label = str(payload.get('label') or payload.get('title') or workflow.get('name') or 'Website Funnel Check')[:180]
    project = str(payload.get('project') or payload.get('tenant') or payload.get('projectId') or workflow.get('projectId') or 'browser-funnel-checks')[:180]
    expected = str(payload.get('expected') or 'lead capture / funnel form')[:500]
    batch_id = safe_id(str(payload.get('batchId') or f"workflow-funnel-{int(time.time())}")) or f"workflow-funnel-{int(time.time())}"
    config = {'targets': [{'label': label, 'url': target_url, 'project': project, 'expected': expected}]}
    config_path = f"/tmp/hmc-funnel-workflow-{batch_id}.json"
    command = f"python3 source/scripts/browser_funnel_check_job.py --config {config_path} --batch-id {batch_id} --screenshot-dir /tmp/hmc-funnel-workflow --timeout-ms 30000"
    return {
        'runMode': str(payload.get('runMode') or payload.get('run_mode') or 'create-task'),
        'noSubmit': True,
        'safeTargetRequired': True,
        'targetUrl': target_url,
        'batchId': batch_id,
        'config': config,
        'configPath': config_path,
        'command': command,
    }, None, 200


