            {'id': f"{funnel_job['batchId']}-target-url", 'kind': 'source', 'title': 'Safe target URL configured', 'summary': funnel_job['targetUrl'], 'source': 'workflow-launch-payload', 'sourceId': funnel_job['batchId'], 'url': funnel_job['targetUrl'], 'createdAt': now, 'created_at': now, 'confidence': 'high'},
