def website_funnel_routine_binding_payload(workflow, funnel_job, schedule_expr):
    schedule_expr = str(schedule_expr or (workflow.get('launchDefaults') or {}).get('schedule') or '0 9 * * 1').strip()
    target = funnel_job['config']['targets'][0]
    routine_id = safe_id(f"website-funnel-check-{target.get('project')}-{funnel_job['batchId']}")[:96] or funnel_job['batchId']
    script = 'browser_funnel_check_job.py'
    prompt_preview = (
        f"NO_SUBMIT routine for Website Funnel Check. Target: {funnel_job['targetUrl']}. "
        f"Schedule: {schedule_expr}. Command: {funnel_job['command']}"
    )
    return {
        'id': routine_id,
        'name': f"Website Funnel Check · {target.get('label') or target.get('project')}",
        'workflow_template_id': 'website-funnel-check',
        'enabled': False,
        'state': 'paused',
        'status': 'draft',
        'schedule': schedule_expr,
        'schedule_kind': 'cron',
        'schedule_display': schedule_expr,
        'targetUrl': funnel_job['targetUrl'],
        'project': target.get('project'),
        'noSubmit': True,
        'safeTargetRequired': True,
        'script': script,
        'configPath': funnel_job['configPath'],
        'command': funnel_job['command'],
        'prompt_preview': prompt_preview,
        'latestRunStatus': {'status': 'not-run', 'lastRunAt': None, 'summary': 'Routine binding created; not enabled or run yet.'},
        'evidenceHistory': [],
        'metadata': {
            'workflow_template_id': 'website-funnel-check',
            'targetUrl': funnel_job['targetUrl'],
            'noSubmit': True,
            'safeTargetRequired': True,
            'latestRunStatus': {'status': 'not-run', 'lastRunAt': None},
            'evidenceHistory': [],
        },
    }


def website_funnel_schedule_result_payload(workflow, funnel_job, routine):
    result = website_funnel_workflow_result_payload(workflow, funnel_job)
    result['status'] = 'draft'
    result['summary'] = 'Scheduled Website Funnel Check routine binding is prepared. It remains paused until the operator enables the routine; NO_SUBMIT and submit approval gates remain mandatory.'
    result['artifacts'].append({'id': f"{funnel_job['batchId']}-routine-binding", 'kind': 'note', 'title': 'Scheduled Funnel Check routine binding', 'summary': f"Routine {routine['id']} is prepared on schedule {routine['schedule']} and starts paused.", 'path': None, 'createdAt': iso(time.time()), 'createdBy': 'workflow-template'})
    result['evidence'].append({'id': f"{funnel_job['batchId']}-schedule", 'kind': 'source', 'title': 'Routine schedule configured', 'summary': routine['schedule'], 'source': 'workflow-launch-payload', 'sourceId': routine['id'], 'createdAt': iso(time.time()), 'created_at': iso(time.time()), 'confidence': 'high'})
    result['next_actions'] = ['Review the scheduled routine binding and target URL.', 'Enable the routine only when the operator wants recurring checks to run.', 'Review latest Browser Activity and Task Board evidence after each run; approve/reject any submit boundary.']
    result['verification']['schedule'] = routine['schedule']
    result['verification']['routineId'] = routine['id']
    return result


def launch_website_funnel_schedule(workflow, payload, identity=None):
    funnel_job, error, status = website_funnel_check_launch_config(workflow, payload)
    if error:
        return error, status
    routine = website_funnel_routine_binding_payload(workflow, funnel_job, payload.get('schedule') or payload.get('cron'))
    result_details = website_funnel_schedule_result_payload(workflow, funnel_job, routine)
    target = funnel_job['config']['targets'][0]
    task_payload = {
        'title': payload.get('title') or f"Schedule Website Funnel Check: {target.get('label')}",
        'body': '\n\n'.join(['Scheduled Website Funnel Check routine binding prepared from Mission Control.', f"Target: {funnel_job['targetUrl']}", f"Schedule: {routine['schedule']}", 'Safety: routine starts paused; NO_SUBMIT is enforced; submit controls remain blocked for operator approval.', f"Run command: {funnel_job['command']}"]),
        'assignee': workflow.get('agentId') or 'melkizac',
        'status': 'queued',
        'priority': 42,
        'tenant': target.get('project'),
        'project_id': target.get('project'),
        'skills': workflow.get('skills') or [],
        'created_by': 'workflow-template',
        'workflow_template_id': workflow.get('id'),
        'result': json.dumps(result_details),
    }
    if identity and not is_admin_identity(identity):
        task_result, task_status = create_workspace_task(identity, task_payload)
    else:
        task_result, task_status = create_task(task_payload)
    if task_status >= 400:
        return {'ok': False, 'workflow': workflow, 'routine': routine, 'funnel_job': funnel_job, 'error': task_result.get('error') or 'Unable to create scheduled Website Funnel Check task'}, task_status
    task = task_result.get('task')
    mission_details = task.get('result_details') if task else None
    if isinstance(mission_details, str):
        try:
            mission_details = json.loads(mission_details)
        except Exception:
            mission_details = {}
    mission = task_mission_result_payload(task, mission_details) if task else None
    return {'ok': True, 'workflow': workflow, 'routine': routine, 'funnel_job': funnel_job, 'task': task, 'mission_result': mission}, task_status


def launch_website_funnel_workflow(workflow, payload, identity=None):
    funnel_job, error, status = website_funnel_check_launch_config(workflow, payload)
    if error:
        return error, status
    result_details = website_funnel_workflow_result_payload(workflow, funnel_job)
    label = funnel_job['config']['targets'][0]['label']
    project = funnel_job['config']['targets'][0]['project']
    task_payload = {
        'title': payload.get('title') or f"Website Funnel Check: {label}",
        'body': '\n\n'.join(['Packaged Website Funnel Check workflow launched from Mission Control.', f"Target: {funnel_job['targetUrl']}", 'Safety: NO_SUBMIT is enforced; detected submit controls remain blocked for operator approval.', f"Config path: {funnel_job['configPath']}", f"Run command: {funnel_job['command']}"]),
        'assignee': workflow.get('agentId') or 'melkizac',
        'status': 'queued',
        'priority': 45,
        'tenant': project,
        'project_id': project,
        'skills': workflow.get('skills') or [],
        'created_by': 'workflow-template',
        'workflow_template_id': workflow.get('id'),
        'result': json.dumps(result_details),
    }
    if identity and not is_admin_identity(identity):
        task_result, task_status = create_workspace_task(identity, task_payload)
    else:
        task_result, task_status = create_task(task_payload)
    if task_status >= 400:
        return {'ok': False, 'workflow': workflow, 'funnel_job': funnel_job, 'error': task_result.get('error') or 'Unable to launch Website Funnel Check'}, task_status
    task = task_result.get('task')
    mission_details = task.get('result_details') if task else None
    if isinstance(mission_details, str):
        try:
            mission_details = json.loads(mission_details)
        except Exception:
            mission_details = {}
    mission = task_mission_result_payload(task, mission_details) if task else None
    return {'ok': True, 'workflow': workflow, 'funnel_job': funnel_job, 'task': task, 'mission_result': mission}, task_status


def parse_sgt_datetime(value):
    if isinstance(value, datetime):
        dt = value
    elif value:
        try:
            dt = datetime.fromisoformat(str(value).replace('Z', '+00:00'))
        except Exception:
            dt = datetime.now(SGT)
    else:
        dt = datetime.now(SGT)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=SGT)
    return dt.astimezone(SGT)


def markdown_section_for_heading(markdown, heading_tokens):
    tokens = [t.lower() for t in heading_tokens if t]
    lines = markdown.splitlines()
    start = None
    for idx, line in enumerate(lines):
        stripped = line.strip()
        if not stripped.startswith('## '):
            continue
        lowered = stripped.lstrip('#').strip().lower()
        if all(token in lowered for token in tokens):
            start = idx + 1
            break
    if start is None:
        return ''
    end = len(lines)
    for idx in range(start, len(lines)):
        stripped = lines[idx].strip()
        if stripped.startswith('## '):
            end = idx
            break
    return '\n'.join(lines[start:end])


def checkbox_counts(markdown):
    checked = len(re.findall(r'^\s*-\s*\[[xX]\]\s+', markdown, flags=re.MULTILINE))
    unchecked = len(re.findall(r'^\s*-\s*\[\s\]\s+', markdown, flags=re.MULTILINE))
    return checked, unchecked


def linkedin_daily_block_state(block, iso_day, todo_path, now_sgt=None):
    now = parse_sgt_datetime(now_sgt)
    try:
        day = datetime.strptime(iso_day, '%Y-%m-%d').replace(tzinfo=SGT)
    except Exception:
        day = now.replace(hour=0, minute=0, second=0, microsecond=0)
    path = Path(todo_path)
    if not path.exists():
        if day.date() < now.date():
            return {'status': 'blocked', 'reason': f'{path} is missing and {iso_day} is already past.', 'checked': 0, 'unchecked': 0}
        return {'status': 'todo', 'reason': f'{path} has not been created yet.', 'checked': 0, 'unchecked': 0}
    text = path.read_text(errors='replace')
    if block == 'planner':
        checked, unchecked = checkbox_counts(text)
        if text.strip():
            return {'status': 'done', 'reason': 'Daily to-do source file exists and is populated.', 'checked': checked, 'unchecked': unchecked}
    section_tokens = {
        'morning': ['morning', 'block'],
        'content': ['content', 'block'],
        'midday': ['midday', 'block'],
        'afternoon': ['afternoon', 'block'],
        'evening': ['evening', 'block'],
    }.get(block, [block])
    section = markdown_section_for_heading(text, section_tokens)
    checked, unchecked = checkbox_counts(section)
    if checked > 0 and unchecked == 0:
        return {'status': 'done', 'reason': f'{block.title()} section has all checklist items checked.', 'checked': checked, 'unchecked': unchecked}
    deadlines = {
        'planner': (23, 59),
        'morning': (11, 30),
        'content': (12, 0),
        'midday': (14, 30),
        'afternoon': (17, 30),
        'evening': (21, 0),
    }
    hour, minute = deadlines.get(block, (23, 59))
    deadline = day.replace(hour=hour, minute=minute, second=0, microsecond=0)
    if day.date() < now.date() or now >= deadline:
        reason = f'{block.title()} block is incomplete and its operating window has passed.'
        if not section.strip():
            reason = f'{block.title()} section was not found in {path} and its operating window has passed.'
        return {'status': 'blocked', 'reason': reason, 'checked': checked, 'unchecked': unchecked}
    return {'status': 'todo', 'reason': f'{block.title()} block is not complete yet, but its operating window has not passed.', 'checked': checked, 'unchecked': unchecked}


def linkedin_daily_block_task_specs(workflow, payload=None):
    payload = payload or {}
    now_sgt = parse_sgt_datetime(payload.get('now_sgt'))
    today = payload.get('today') or now_sgt.strftime('%d%m%Y')
    iso_day = payload.get('iso_day') or now_sgt.strftime('%Y-%m-%d')
    todo_path = payload.get('todo_path') or f"/root/.hermes/skills/linkedin-daily-planner/to-do_{today}.md"
    blocks = [
        ('planner', 'Daily planner / task materialization', 'Generate or read today\'s LinkedIn to-do and turn the block plan into Task Board cards.', 78),
        ('morning', 'Morning block', 'Execute pending setup, warm-up, and morning engagement tasks from today\'s to-do.', 72),
        ('content', 'Content block', 'Execute pending content drafting, scheduling, or publishing tasks with approval and live-action verification.', 75),
        ('midday', 'Midday block', 'Execute midday engagement/follow-up tasks from today\'s to-do and update logs.', 68),
        ('afternoon', 'Afternoon block', 'Execute afternoon ICP/prospect/comment tasks from today\'s to-do and update logs.', 68),
        ('evening', 'Evening block / final audit', 'Reconcile completed/blocked work, update shared logs, and carry unresolved items forward.', 70),
    ]
    skills = workflow.get('skills') or ['linkedin-daily-planner']
    tasks = []
    for block, label, summary, priority in blocks:
        task_id = safe_id(f"linkedin-daily-{iso_day}-{block}")
        state = linkedin_daily_block_state(block, iso_day, todo_path, now_sgt)
        status = state.get('status') or 'queued'
        result_details = {
            'status': status,
            'summary': state.get('reason') or f"LinkedIn daily workflow block task for {iso_day}: {label}.",
            'artifacts': [{'id': f'{task_id}-todo', 'kind': 'file', 'title': f'Today LinkedIn to-do · {today}', 'summary': 'Daily planner file is the source of truth for block execution.', 'path': todo_path, 'createdAt': iso(time.time()), 'createdBy': 'linkedin-daily-planner'}],
            'evidence': [workflow_evidence_record(task_id, 'source', 'Task materialized from LinkedIn daily operating workflow', f'{label} task created under workflow_template_id=linkedin-daily-operating-workflow.')],
            'approval_gates': workflow.get('approvalGates') or [],
            'next_actions': ['Move card to running when the block routine starts', 'Update to done when block tasks and logs are complete', 'Move to blocked with evidence if auth, limits, approval, or submit-path verification blocks execution'],
            'verification': {'workflow': workflow.get('id'), 'block': block, 'sourceOfTruth': todo_path, 'statusFlow': 'todo → running → done/blocked', 'checkedItems': state.get('checked', 0), 'uncheckedItems': state.get('unchecked', 0), 'reconciledAt': iso(time.time())},
        }
        if status == 'done':
            result_details['next_actions'] = []
        elif status == 'blocked':
            result_details['blockers'] = [state.get('reason') or 'Block window passed before completion.']
            result_details['next_actions'] = ['Carry any still-valid work into the next daily plan; do not execute this previous/expired block late.']
        tasks.append({
            'id': task_id,
            'title': f"LinkedIn {label} · {iso_day}",
            'body': '\n\n'.join([
                f"Workflow: {workflow.get('name')} ({workflow.get('id')})",
                f"Block: {label}",
                f"Source of truth: {todo_path}",
                summary,
                'Status discipline: keep this card moving todo → running → done or blocked in real time during the LinkedIn block.',
            ]),
            'assignee': 'linkedin-growth',
            'status': status,
            'priority': priority,
            'tenant': 'melverick-command-center',
            'project_id': 'melverick-command-center',
            'created_by': 'workflow-template',
            'workflow_template_id': workflow.get('id'),
            'current_step_key': block,
            'skills': skills,
            'result': json.dumps(result_details),
        })
    return tasks


def record_linkedin_materializer_block_event(task_id, reason):
    tid = safe_id(task_id)
    if not tid:
        return
    now = int(time.time())
    con = ensure_kanban_tables()
    try:
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)',
                    (tid, None, 'blocked', json.dumps({'reason': reason or 'LinkedIn block window passed before completion.', 'source': 'linkedin-daily-materializer'}, ensure_ascii=False), now))
        con.commit()
    finally:
        con.close()


def linkedin_task_payload_summary(task_payload):
    try:
        return (json.loads(task_payload.get('result') or '{}') or {}).get('summary')
    except Exception:
        return ''


def launch_linkedin_daily_workflow(workflow, payload, identity=None):
    created, existing, errors = [], [], []
    for task_payload in linkedin_daily_block_task_specs(workflow, payload):
        if identity and not is_admin_identity(identity):
            result, status = create_workspace_task(identity, task_payload)
        else:
            result, status = create_task(task_payload)
        if status == 409:
            update_payload = {k: task_payload[k] for k in ('title', 'body', 'assignee', 'status', 'priority', 'tenant', 'result') if k in task_payload}
            updated, update_status = update_task(task_payload['id'], update_payload)
            if update_status < 400:
                if task_payload.get('status') == 'blocked':
                    record_linkedin_materializer_block_event(task_payload['id'], linkedin_task_payload_summary(task_payload))
                existing.append(updated.get('task') or {'id': task_payload['id']})
            else:
                errors.append({'id': task_payload['id'], 'error': updated.get('error'), 'status': update_status})
        elif status >= 400:
            errors.append({'id': task_payload['id'], 'error': result.get('error'), 'status': status})
        else:
            if task_payload.get('status') == 'blocked':
                record_linkedin_materializer_block_event(task_payload['id'], linkedin_task_payload_summary(task_payload))
            created.append(result.get('task'))
    status_code = 207 if errors else 201 if created else 200
    all_tasks = [t for t in created + existing if t]
    return {
        'ok': not errors,
        'workflow': workflow,
        'tasks': all_tasks,
        'task': all_tasks[0] if all_tasks else None,
        'created': len(created),
        'updated_existing': len(existing),
        'errors': errors,
        'summary': f"Materialized {len(all_tasks)} LinkedIn daily workflow block tasks for Task Board.",
    }, status_code


def launch_packaged_workflow(workflow_id, payload, identity=None):
    workflow_id = safe_id(workflow_id)
    if workflow_id == 'linkedin-content-operating-loop':
        workflow_id = 'linkedin-daily-operating-workflow'
    workflow = next((w for w in packaged_sme_workflows(identity) if w.get('id') == workflow_id), None)
    if not workflow:
        return {'ok': False, 'error': 'workflow not found'}, 404
    if workflow_id == 'linkedin-daily-operating-workflow':
        return launch_linkedin_daily_workflow(workflow, payload, identity)
    if workflow_id == 'website-funnel-check':
        if str(payload.get('runMode') or payload.get('run_mode') or '').lower() in ('schedule', 'routine', 'scheduled'):
            return launch_website_funnel_schedule(workflow, payload, identity)
        return launch_website_funnel_workflow(workflow, payload, identity)
    request_text = str(payload.get('request') or workflow.get('launchPrompt') or workflow.get('summary') or '').strip()
    launch_payload = {
        'request': request_text,
        'projectId': payload.get('projectId') or workflow.get('projectId'),
        'agentId': payload.get('agentId') or workflow.get('agentId'),
        'risk': workflow.get('risk') or 'external-facing',
        'title': payload.get('title') or workflow.get('name'),
    }
    planned, plan_status = delegate_work_plan_payload(launch_payload, identity)
    if plan_status >= 400:
        return planned, plan_status
    plan = planned.get('plan') or {}
    task_payload = {
        'title': launch_payload['title'],
        'body': '\n\n'.join(['Packaged SME workflow launched from Mission Control workflow library.', f"Workflow: {workflow.get('name')} ({workflow.get('id')})", plan.get('taskBody') or request_text]),
        'assignee': plan.get('agentId') or workflow.get('agentId'),
        'status': 'queued',
        'priority': 40,
        'tenant': plan.get('projectId') or workflow.get('projectId'),
        'project_id': plan.get('projectId') or workflow.get('projectId'),
        'skills': workflow.get('skills') or [],
        'created_by': 'workflow-template',
        'workflow_template_id': workflow.get('id'),
        'result': json.dumps({
            'status': 'draft',
            'summary': f"Workflow '{workflow.get('name')}' has been launched. Evidence requirements, artifacts, approval gates, and next actions are attached before execution.",
            'artifacts': workflow.get('artifacts') or [],
            'evidence': (workflow.get('evidence') or []) + (plan.get('evidence') or []),
            'approval_gates': workflow.get('approvalGates') or [],
            'next_actions': workflow.get('nextActions') or [],
        }),
    }
    if identity and not is_admin_identity(identity):
        task_result, task_status = create_workspace_task(identity, task_payload)
    else:
        task_result, task_status = create_task(task_payload)
    if task_status >= 400:
        return {'ok': False, 'workflow': workflow, 'plan': plan, 'error': task_result.get('error') or 'Unable to launch workflow'}, task_status
    task = task_result.get('task')
    mission = task_mission_result_payload(task, task.get('result_details')) if task else None
    return {'ok': True, 'workflow': workflow, 'plan': plan, 'task': task, 'mission_result': mission}, task_status


def canonical_task_project_slug(slug):
    value = project_slug(slug)
    if is_support_artifact_project(value):
        return None
    # Board tasks can carry workspace_path=/opt/hermes-mission-control/source.
    # Treat that implementation directory as part of the canonical HMC project
    # instead of surfacing a duplicate pseudo-project named "Source".
    if value in ('source', 'hermes-mission-control'):
        return 'mission-control'
    # LinkedIn daily planner is a reusable Workflow Library flow, not a
    # standalone Project. Its Task Board cards belong under Melverick Command
    # Center while workflow identity stays on /workflows.
    if value in ('linkedin-daily-planner', 'linkedin-daily-operating-workflow', 'linkedin-daily-operating-workflow-runner') or value.startswith('linkedin-daily-'):
        return 'melverick-command-center'
    if value in ('mission-control-admin-multi-runtime-design', 'hmc-admin-redesign') or value.startswith('hmc-admin-redesign'):
        return 'hmc-admin-redesign'
    if value.startswith('goal-devops-builder-') and 'mission-control' in value:
        return 'mission-control'
    if value.startswith('goal-melverick-personal-website') or value == 'melverick-site':
        return 'melverick-site'
    if value.startswith('goal-agentic-ai-course-') or value == 'nexius-leads':
        return 'nexius-academy-agentic-ai-course-growth'
    if 'agentic-ai-course' in value and any(x in value for x in ('leadgen', 'signup', 'sprint', 'interest')):
        return 'nexius-academy-agentic-ai-course-growth'
    return value


def list_projects(filters=None, identity=None):
    if identity and not is_admin_identity(identity):
        return list_workspace_projects(filters, identity)
    filters = filters or {}
    q = (filters.get('q') or [''])[0].strip().lower()
    cacheable = not q and PROJECTS_CACHE_TTL_SECONDS > 0
    if cacheable:
        now = time.time()
        with _PROJECTS_CACHE_LOCK:
            cached = _PROJECTS_CACHE.get('payload')
            if cached is not None and now < float(_PROJECTS_CACHE.get('expires_at') or 0):
                return copy.deepcopy(cached)
    projects = {}
    status_overrides = project_status_overrides()
    plan = APP_ROOT / 'source' / '.hermes' / 'plans' / '2026-05-30_233542-paperclip-functions-into-hermes-mission-control.md'
    if plan.exists():
        title, summary = md_title_and_summary(plan)
        proj = empty_project('mission-control', 'Hermes Mission Control', 'product', str(APP_ROOT), 'plan')
        proj['summary'] = summary or 'Hermes Mission Control migration and UI buildout.'
        proj['updated_at'] = iso(plan.stat().st_mtime)
        proj['knowledge'] = [{'title': title, 'path': str(plan), 'type': 'implementation plan', 'updated_at': iso(plan.stat().st_mtime)}]
        proj['tags'] = ['mission-control', 'hermes']; proj['health'] = 84
        add_project(projects, proj)
    second_brain = second_brain_project()
    if second_brain:
        add_project(projects, second_brain)
    kb_projects = SECOND_BRAIN_WIKI / 'projects'
    if kb_projects.exists():
        for md in sorted(kb_projects.glob('*.md'), key=lambda x: x.stat().st_mtime, reverse=True)[:80]:
            title, summary = md_title_and_summary(md); slug = project_slug(md.stem)
            proj = empty_project(slug, title, 'knowledge', str(md), 'second-brain')
            proj['summary'] = summary; proj['updated_at'] = iso(md.stat().st_mtime)
            proj['knowledge'] = [{'title': title, 'path': str(md), 'type': 'wiki project', 'updated_at': iso(md.stat().st_mtime)}]
            proj['tags'] = ['second-brain']; add_project(projects, proj)
    workspace_roots = [HERMES_HOME / 'workspace', HOME / '.openclaw' / 'workspace', APP_ROOT]
    for root in workspace_roots:
        if not root.exists() or not root.is_dir(): continue
        candidates = [root] if root == APP_ROOT else [x for x in root.iterdir() if x.is_dir() and not x.name.startswith('.')]
        for d in sorted(candidates, key=lambda x: x.stat().st_mtime, reverse=True)[:30]:
            if d.name in ('node_modules','dist','sharepoint-oauth-venv') or d == SECOND_BRAIN_ROOT: continue
            add_project(projects, project_from_path(d, 'workspace', 'filesystem'))
    task_idx = project_task_index()
    canonical_tasks = {}
    for raw_slug, bucket in task_idx.items():
        slug = canonical_task_project_slug(raw_slug)
        if not slug:
            continue
        merged = canonical_tasks.setdefault(slug, {'actions': {'open': 0, 'running': 0, 'blocked': 0, 'done': 0}, 'tasks': []})
        for key in ('open','running','blocked','done'):
            merged['actions'][key] += bucket['actions'].get(key, 0)
        merged['tasks'].extend(bucket.get('tasks') or [])
    for slug, bucket in canonical_tasks.items():
        target = projects.get(slug)
        if target is None:
            target = add_project(projects, empty_project(slug, slug.replace('-', ' ').title(), 'workspace', '', 'kanban'))
        for key in ('open','running','blocked','done'):
            target.setdefault('actions', {}).setdefault(key, 0)
            target['actions'][key] += bucket['actions'].get(key, 0)
        target['activity'].extend([{'kind': 'task', 'title': t['title'], 'status': t['status'], 'at': t['updated_at'], 'id': t['id']} for t in bucket['tasks'][:8]])
    for canonical_id, meta in CANONICAL_PROJECTS.items():
        if canonical_id in projects:
            continue
        path = meta.get('path') or ''
        project = empty_project(canonical_id, meta.get('name') or canonical_id.replace('-', ' ').title(), meta.get('kind') or 'project', path, 'canonical')
        project['summary'] = meta.get('summary') or project.get('summary') or ''
        project['tags'] = list(meta.get('tags') or [])
        project['portfolio_group'] = meta.get('portfolio_group') or infer_project_group(project)
        if path:
            try:
                project['updated_at'] = iso(Path(path).stat().st_mtime)
            except Exception:
                pass
        add_project(projects, project)
    for pid in list(projects.keys()):
        apply_canonical_project(projects[pid])
    session_index_for_projects = project_session_text_index(limit=80)
    canonical_session_links = canonical_project_session_links(session_ids=set(session_index_for_projects.keys()), limit=200)
    linked_session_ids = set()
    for link in canonical_session_links:
        linked_session_ids.add(link.get('id'))
        target = projects.get(link.get('project_id'))
        if not target:
            continue
        if is_human_chat_trace(link):
            target.setdefault('sessions', [])
            if len(target['sessions']) < 12:
                target['sessions'].append({k: v for k, v in link.items() if k != '_transcript'})
            if len(target.setdefault('activity', [])) < 12:
                target['activity'].append({'kind': 'chat', 'title': link.get('title'), 'status': link.get('relationship_type') or link.get('origin'), 'at': link.get('started_at'), 'id': link.get('id')})
        else:
            if len(target.setdefault('activity', [])) < 12:
                target['activity'].append({'kind': link.get('run_type') or 'run', 'title': link.get('title'), 'status': link.get('run_type_label') or link.get('source'), 'at': link.get('started_at'), 'id': link.get('id')})
    sessions = [{k: v for k, v in session.items() if not k.startswith('_')} for sid, session in session_index_for_projects.items() if sid not in linked_session_ids and is_human_chat_trace(session)]
    visible_project_rows = [{'id': p.get('id'), 'name': p.get('name'), 'sessions': 0, '_raw': p} for p in projects.values()]
    for session in sessions:
        suggestions = session_project_suggestions(session, visible_project_rows)
        for suggestion in suggestions[:3]:
            best_key = suggestion.get('project_id')
            if best_key and best_key in projects:
                target = projects[best_key]
                enriched_session = {**session, 'project_id': target.get('id'), 'project_name': target.get('name'), 'relationship_type': 'discussion', 'summary': '', 'linked_by': 'deterministic-classifier', 'linked_at': '', 'link_source': 'suggested', 'project_score': suggestion.get('score', 0), 'confidence': suggestion.get('confidence', 0)}
                target.setdefault('sessions', [])
                if len(target['sessions']) < 12:
                    target['sessions'].append(enriched_session)
                if len(target.setdefault('activity', [])) < 12:
                    target['activity'].append({'kind': 'chat', 'title': session['title'], 'status': session.get('origin') or session['source'], 'at': session['started_at'], 'id': session['id']})
    for proj in projects.values():
        apply_canonical_project(proj)
        if not proj.get('guard_policy'):
            proj['guard_policy'] = hmc_guard_policy(proj.get('id'), {'tenant': proj.get('id'), 'workspace_path': proj.get('path'), 'title': proj.get('name')})
        open_count = proj['actions']['open'] + proj['actions']['running'] + proj['actions']['blocked']; total_actions = open_count + proj['actions']['done']
        proj['progress'] = int((proj['actions']['done'] / total_actions) * 100) if total_actions else min(95, 35 + len(proj.get('knowledge', []))*10 + len(proj.get('artifacts', []))*2)
        if total_actions and open_count == 0 and proj['actions']['done']:
            proj['status'] = 'done'
        override = status_overrides.get(project_slug(proj.get('id') or ''))
        if override:
            proj['status'] = override.get('status') or proj.get('status')
            proj['status_updated_by'] = override.get('updated_by') or ''
            proj['status_updated_at'] = iso(override.get('updated_at'))
        proj['health'] = max(35, min(98, 82 - proj['actions']['blocked']*12 + proj['actions']['done']*2))
        if proj['actions']['blocked']:
            proj['risks'].append({'label': 'Blocked actions', 'severity': 'high', 'count': proj['actions']['blocked']})
        proj['workspace_count'] = len(proj.get('workspaces', [])) + (1 if proj.get('path') else 0)
    enrich_projects_with_operating_links(projects)
    rows = [p for p in projects.values() if should_show_project(p)]
    if q:
        rows = [x for x in rows if q in ' '.join([x.get('name',''), x.get('summary',''), x.get('path',''), x.get('source',''), ' '.join(x.get('tags') or [])]).lower()]
    group_order = {'Core Operating System': 0, 'Nexius Growth': 1, 'Web Presence': 2, 'Knowledge Systems': 3, 'Operations': 4}
    rows.sort(key=lambda x: (group_order.get(x.get('portfolio_group') or 'Operations', 9), x.get('status') != 'active', x.get('updated_at') == '—', x.get('name','').lower()))
    payload = {'projects': rows, 'summary': {'total': len(rows), 'active': sum(1 for x in rows if x.get('status') == 'active'), 'open_actions': sum(x['actions']['open'] + x['actions']['running'] for x in rows), 'blocked': sum(x['actions']['blocked'] for x in rows), 'knowledge': sum(len(x.get('knowledge') or []) for x in rows), 'workspaces': sum(1 for x in rows if x.get('path'))}, 'kinds': sorted({x.get('kind') or 'workspace' for x in rows}), 'project_areas': [], 'sources': []}
    if cacheable:
        with _PROJECTS_CACHE_LOCK:
            _PROJECTS_CACHE['payload'] = copy.deepcopy(payload)
            _PROJECTS_CACHE['expires_at'] = time.time() + PROJECTS_CACHE_TTL_SECONDS
    return payload

def get_logs(kind='gateway', lines=80):
    safe = {'gateway': 'gateway.log', 'agent': 'agent.log', 'errors': 'errors.log'}
    path = LOG_DIR / safe.get(kind, 'gateway.log')
    if not path.exists():
        return []
    try:
        return path.read_text(errors='replace').splitlines()[-lines:]
    except Exception as e:
        return [str(e)]



