def configured_env_keys():
    env_lines = ENV_FILE.read_text(errors='ignore').splitlines() if ENV_FILE.exists() else []
    env_keys = set(os.environ.keys())
    for raw in env_lines:
        if '=' in raw and not raw.lstrip().startswith('#'):
            env_keys.add(raw.split('=', 1)[0].strip())
    return env_keys


def configured_env_value(name):
    key = re.sub(r'[^A-Z0-9_]', '', str(name or '').upper())[:120]
    if not key:
        return ''
    if os.environ.get(key):
        return os.environ.get(key) or ''
    if ENV_FILE.exists():
        for raw in ENV_FILE.read_text(errors='ignore').splitlines():
            if '=' not in raw or raw.lstrip().startswith('#'):
                continue
            env_key, env_value = raw.split('=', 1)
            if env_key.strip() == key:
                return env_value.strip().strip('"').strip("'")
    return ''


def read_model_router_config():
    cfg = default_model_router_config()
    if MODEL_ROUTER_FILE.exists():
        try:
            loaded = json.loads(MODEL_ROUTER_FILE.read_text(errors='replace') or '{}')
            if isinstance(loaded, dict):
                cfg.update({k: loaded[k] for k in loaded.keys() if k in ('enabled', 'updated_at', 'policy', 'models')})
        except Exception as e:
            cfg['error'] = str(e)
    env_keys = configured_env_keys()
    cli_settings = hermes_cli_settings()
    auth_provider_set = set(cli_settings.get('auth_providers') or [])
    for model in cfg.get('models', []):
        provider = str(model.get('provider') or '').strip()
        env_name = str(model.get('credential_env') or provider_credential_env(provider) or '').strip()
        model['credential_env'] = env_name
        model['authorized'] = bool((env_name and env_name in env_keys) or (provider and provider in auth_provider_set))
        if model['authorized'] and provider in auth_provider_set and not (env_name and env_name in env_keys):
            model['secret_status'] = 'configured via Hermes auth'
        else:
            model['secret_status'] = 'configured' if model['authorized'] else 'missing'
    cfg['hermes_settings'] = cli_settings
    cfg['summary'] = {
        'total': len(cfg.get('models', [])),
        'enabled': sum(1 for m in cfg.get('models', []) if m.get('enabled')),
        'authorized': sum(1 for m in cfg.get('models', []) if m.get('authorized')),
        'frontier': sum(1 for m in cfg.get('models', []) if m.get('tier') == 'frontier'),
    }
    return cfg


def write_model_router_config(payload):
    current = read_model_router_config()
    cfg = {
        'enabled': bool(payload.get('enabled', current.get('enabled', True))),
        'policy': payload.get('policy') if isinstance(payload.get('policy'), dict) else current.get('policy', {}),
        'models': payload.get('models') if isinstance(payload.get('models'), list) else current.get('models', []),
        'updated_at': datetime.now(SGT).strftime('%Y-%m-%d %H:%M:%S SGT'),
    }
    sanitized = []
    seen = set()
    for idx, item in enumerate(cfg['models']):
        if not isinstance(item, dict):
            continue
        mid = safe_id(item.get('id') or item.get('model') or f'model-{idx}') or f'model-{idx}'
        if mid in seen:
            mid = f'{mid}-{idx}'
        seen.add(mid)
        provider = str(item.get('provider') or 'custom')[:80]
        sanitized.append({
            'id': mid,
            'label': str(item.get('label') or item.get('model') or mid)[:120],
            'provider': provider,
            'model': str(item.get('model') or mid)[:160],
            'tier': str(item.get('tier') or 'economy')[:40],
            'enabled': bool(item.get('enabled', True)),
            'authorized': False,
            'credential_env': re.sub(r'[^A-Z0-9_]', '', str(item.get('credential_env') or provider_credential_env(provider) or '').upper())[:80],
            'cost_weight': max(1, min(100, int(item.get('cost_weight') or 1))),
            'best_for': [str(x)[:80] for x in (item.get('best_for') or []) if str(x).strip()][:12],
            'notes': str(item.get('notes') or '')[:800],
        })
    cfg['models'] = sanitized
    MODEL_ROUTER_FILE.parent.mkdir(parents=True, exist_ok=True)
    MODEL_ROUTER_FILE.write_text(json.dumps(cfg, indent=2), encoding='utf-8')
    try:
        os.chmod(MODEL_ROUTER_FILE, 0o600)
    except Exception:
        pass
    return read_model_router_config(), 200


