def account_with_status(account, env_keys=None, auth_credentials=None):
    env_keys = env_keys or configured_env_keys()
    auth_credentials = auth_credentials if auth_credentials is not None else hermes_auth_credentials()
    credential_env = account.get('credential_env') or ''
    provider = str(account.get('provider') or '').strip()
    label = str(account.get('label') or '').strip().lower()
    matched_credential = next(
        (
            c for c in auth_credentials
            if c.get('provider') == provider and str(c.get('label') or '').strip().lower() == label
        ),
        None,
    )
    configured = bool((credential_env and credential_env in env_keys) or matched_credential)
    return {
        **account,
        'configured': configured,
        'secret_status': 'configured via Hermes auth' if matched_credential else ('configured' if credential_env and credential_env in env_keys else 'missing'),
        'auth_label': matched_credential.get('label') if matched_credential else '',
        'auth_type': matched_credential.get('auth_type') if matched_credential else '',
        'auth_source': matched_credential.get('source') if matched_credential else '',
        'auth_active': bool(matched_credential.get('active')) if matched_credential else False,
        'auth_status': matched_credential.get('status') if matched_credential else '',
    }


