def default_approval_governance_policy():
    return {
        'require_approval_for': list(HERMES_V016_APPROVAL_GOVERNANCE_ACTIONS),
        'source': 'hermes-v0.16-governance-defaults',
    }


def evaluate_approval_policy(identity=None, request=None):
    request = request or {}
    action = safe_id(request.get('action') or request.get('category') or '').lower()
    policy = request.get('platform_policy') if isinstance(request.get('platform_policy'), dict) else default_approval_governance_policy()
    required = policy.get('require_approval_for') or policy.get('approval_required_actions') or []
    required = [safe_id(item).lower() for item in required]
    if action in required:
        return {
            'ok': True,
            'decision': 'approval_required',
            'matched_level': 'platform',
            'action': action,
            'reason': f'{action} requires approval under platform governance policy.',
            'policy': policy,
        }
    role = ((identity or {}).get('user') or {}).get('role') or (identity or {}).get('role') or ''
    return {
        'ok': True,
        'decision': 'allowed' if role == 'admin' else 'allowed',
        'matched_level': 'default',
        'action': action,
        'reason': 'No approval policy rule matched.',
        'policy': policy,
    }


ARTIFACT_SECRET_QUERY_KEYS = {'token', 'access_token', 'refresh_token', 'secret', 'signature', 'sig', 'key', 'api_key', 'apikey', 'password', 'auth', 'authorization', 'credential', 'credentials'}
SAFE_ARTIFACT_PATH_PREFIXES = ('/runtime/', '/workspace/', '/outputs/', '/artifacts/')


def sanitize_artifact_url(value):
    if not value:
        return None, False, 'missing'
    raw = str(value).strip()
    try:
        parsed = urlsplit(raw)
    except Exception:
        return None, True, 'invalid-url'
    if parsed.scheme not in ('http', 'https') or not parsed.netloc:
        return None, True, 'unsafe-url-scheme'
    query_pairs = parse_qs(parsed.query, keep_blank_values=True)
    redacted = False
    safe_pairs = []
    for key, values in query_pairs.items():
        if key.lower() in ARTIFACT_SECRET_QUERY_KEYS or any(marker in key.lower() for marker in ('token', 'secret', 'signature', 'password')):
            redacted = True
            continue
        for item in values:
            safe_pairs.append((key, item))
    safe_query = urlencode(safe_pairs, doseq=True)
    return urlunsplit((parsed.scheme, parsed.netloc, parsed.path, safe_query, '')), redacted, 'redacted' if redacted else 'safe'


def sanitize_artifact_path(value, kind):
    if not value:
        return None, False, 'missing'
    raw = str(value).strip()
    if kind == 'runtime_file':
        if raw.startswith(SAFE_ARTIFACT_PATH_PREFIXES) and '..' not in Path(raw).parts:
            return raw, False, 'safe'
        return None, True, 'unsafe-runtime-path'
    if kind == 'local_path':
        # Local filesystem paths can reveal profile homes, usernames, or secrets.
        # Surface only the basename as metadata while keeping the clickable path hidden.
        return None, True, 'local-path-hidden'
    return raw, False, 'safe'


def normalize_artifact_locator(artifact, runtime_id=None, profile_id=None):
    artifact = artifact if isinstance(artifact, dict) else {}
    raw_kind = safe_id(artifact.get('kind') or artifact.get('locator_kind') or artifact.get('locatorKind') or '').lower()
    raw_url = artifact.get('url') or artifact.get('external_url') or artifact.get('externalUrl')
    raw_download_url = artifact.get('download_url') or artifact.get('downloadUrl')
    raw_path = artifact.get('path')
    rid = safe_id(artifact.get('runtime_id') or artifact.get('runtimeId') or runtime_id or '') or None
    pid = safe_id(artifact.get('profile_id') or artifact.get('profileId') or profile_id or '') or None
    allowed_kinds = {'local_path', 'hermes_managed_file', 'runtime_file', 'external_url'}
    if raw_kind in allowed_kinds:
        kind = raw_kind
    elif raw_url and not raw_path:
        kind = 'external_url'
    elif raw_download_url and rid:
        kind = 'hermes_managed_file'
    elif rid and raw_path:
        kind = 'runtime_file'
    else:
        kind = 'local_path'
    metadata = {k: v for k, v in artifact.items() if k not in {
        'kind', 'locator_kind', 'locatorKind', 'runtime_id', 'runtimeId', 'profile_id', 'profileId',
        'download_url', 'downloadUrl', 'path', 'url', 'external_url', 'externalUrl',
        'evidence_hash', 'evidenceHash', 'redaction_status', 'redactionStatus', 'metadata',
    }}
    if isinstance(artifact.get('metadata'), dict):
        metadata.update(artifact.get('metadata'))
    safe_url, url_redacted, url_status = sanitize_artifact_url(raw_url)
    safe_download_url, download_redacted, download_status = sanitize_artifact_url(raw_download_url)
    safe_path, path_redacted, path_status = sanitize_artifact_path(raw_path, kind)
    if raw_path and path_redacted:
        metadata.setdefault('filename', Path(str(raw_path)).name)
    redaction_status = artifact.get('redaction_status') or artifact.get('redactionStatus')
    if not redaction_status:
        redaction_status = 'redacted' if (url_redacted or download_redacted or path_redacted) else 'safe'
    metadata['locator_status'] = {
        'url': url_status,
        'download_url': download_status,
        'path': path_status,
    }
    return {
        'kind': kind,
        'runtime_id': rid,
        'profile_id': pid,
        'download_url': safe_download_url,
        'path': safe_path,
        'url': safe_url,
        'evidence_hash': artifact.get('evidence_hash') or artifact.get('evidenceHash'),
        'redaction_status': redaction_status,
        'metadata': metadata,
    }


def runtime_capability_flags(capabilities):
    if not isinstance(capabilities, dict):
        return []
    flags = []
    explicit_flags = capabilities.get('capability_flags') or capabilities.get('capabilities')
    if isinstance(explicit_flags, list):
        flags.extend(safe_id(str(item)).lower() for item in explicit_flags if safe_id(str(item)))
    for key in HERMES_V016_RUNTIME_CAPABILITIES:
        value = capabilities.get(key)
        if value is True or (isinstance(value, str) and value.lower() in ('true', 'enabled', 'yes')):
            flags.append(key)
    return sorted(dict.fromkeys(flags))


def normalize_dashboard_auth_mode(value):
    mode = safe_id(value or '').lower()
    return mode if mode in {'loopback', 'basic', 'oidc', 'portal', 'token', 'unknown'} else 'unknown'


CONNECTOR_SCOPES = {'platform', 'workspace', 'personal'}
CONNECTOR_ACTIONS = ['read', 'draft', 'write', 'delete', 'external_send']
PERSONAL_CONNECTOR_HINTS = ('personal', 'calendar', 'notes', 'mailbox')


def normalize_connector_scope(value):
    scope = safe_id(value or '').lower()
    return scope if scope in CONNECTOR_SCOPES else ''


def normalize_connector_type(value):
    return safe_id(value or 'custom').lower() or 'custom'


def default_connector_scope_for_type(connector_type):
    ctype = normalize_connector_type(connector_type)
    if ctype in WORKSPACE_TRANSACTION_DOMAINS:
        return 'workspace'
    if ctype.startswith('platform') or ctype in {'mission-control', 'runtime-admin', 'billing-admin'}:
        return 'platform'
    if ctype.startswith(PERSONAL_CONNECTOR_HINTS) or any(hint in ctype for hint in PERSONAL_CONNECTOR_HINTS):
        return 'personal'
    return 'workspace'


def merge_connector_policy(connector_type, scope, policy=None):
    ctype = normalize_connector_type(connector_type)
    scope = normalize_connector_scope(scope) or default_connector_scope_for_type(ctype)
    allowed_classes = {'platform': ['platform'], 'workspace': ['workspace'], 'personal': ['personal']}[scope]
    approval_required = []
    if scope == 'platform':
        approval_required = ['write', 'delete', 'external_send']
    elif ctype in WORKSPACE_TRANSACTION_DOMAINS:
        approval_required = ['write', 'delete', 'external_send']
    elif scope == 'personal':
        approval_required = ['external_send']
    merged = {
        'allowed_agent_classes': allowed_classes,
        'allowed_users': [],
        'allowed_roles': ['admin'] if scope == 'platform' else [],
        'allowed_actions': list(CONNECTOR_ACTIONS),
        'approval_required_for': approval_required,
        'quotas': {'daily_actions': 100 if scope == 'workspace' else 25},
    }
    if isinstance(policy, dict):
        for key in ('allowed_agent_classes', 'allowed_users', 'allowed_roles', 'allowed_actions', 'approval_required_for'):
            if isinstance(policy.get(key), list):
                merged[key] = [safe_id(str(item)).lower() for item in policy.get(key) if str(item).strip()]
        if isinstance(policy.get('quotas'), dict):
            merged['quotas'] = {**merged.get('quotas', {}), **policy.get('quotas')}
    merged['allowed_agent_classes'] = [c for c in merged['allowed_agent_classes'] if c in AGENT_CLASSES] or allowed_classes
    merged['allowed_actions'] = [a for a in merged['allowed_actions'] if a in CONNECTOR_ACTIONS] or ['read']
    merged['approval_required_for'] = [a for a in merged['approval_required_for'] if a in CONNECTOR_ACTIONS]
    return merged


def upsert_governed_connector(identity, payload):
    if not is_admin_identity(identity) and normalize_connector_scope((payload or {}).get('scope')) != 'personal':
        return {'ok': False, 'error': 'Admin permission required to create Platform or Workspace connectors.'}, 403
    payload = payload or {}
    ctype = normalize_connector_type(payload.get('connector_type') or payload.get('type'))
    scope = normalize_connector_scope(payload.get('scope')) or default_connector_scope_for_type(ctype)
    uid = identity_user_id(identity)
    wid = payload.get('workspace_id') or identity_workspace_id(identity)
    if scope == 'workspace' and not wid:
        return {'ok': False, 'error': 'Workspace connector requires workspace_id.'}, 400
    if scope == 'personal':
        if not uid:
            return {'ok': False, 'error': 'Personal connector requires an owner.'}, 400
        wid = identity_workspace_id(identity)
    cid = safe_id(payload.get('id') or payload.get('name') or ctype)[:100]
    if not cid:
        return {'ok': False, 'error': 'Connector id is required.'}, 400
    name = str(payload.get('name') or cid).strip()[:140]
    policy = merge_connector_policy(ctype, scope, payload.get('policy') if isinstance(payload.get('policy'), dict) else None)
    now = time.time()
    conn = runtime_connector_db()
    conn.execute("""
        INSERT INTO governed_connectors (id,name,connector_type,scope,workspace_id,owner_user_id,policy_json,status,created_at,updated_at)
        VALUES (?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(id) DO UPDATE SET name=excluded.name, connector_type=excluded.connector_type, scope=excluded.scope,
            workspace_id=excluded.workspace_id, owner_user_id=excluded.owner_user_id, policy_json=excluded.policy_json,
            status=excluded.status, updated_at=excluded.updated_at
    """, (cid, name, ctype, scope, wid if scope == 'workspace' else None, uid if scope == 'personal' else payload.get('owner_user_id'), json.dumps(policy), payload.get('status') or 'active', now, now))
    conn.commit()
    row = conn.execute('SELECT * FROM governed_connectors WHERE id=?', (cid,)).fetchone()
    connector = governed_connector_to_record(row, identity, include_private=True)
    conn.close()
    return {'ok': True, 'connector': connector}, 200


def governed_connector_to_record(row, identity=None, include_private=False):
    policy = parse_json_field(row['policy_json'], {})
    record = {
        'id': row['id'],
        'name': row['name'],
        'connector_type': row['connector_type'],
        'scope': row['scope'],
        'status': row['status'] or 'active',
        'policy': policy,
        'created_at': utc_iso(row['created_at']),
        'updated_at': utc_iso(row['updated_at']),
    }
    if include_private or is_admin_identity(identity):
        record['workspace_id'] = row['workspace_id']
        record['owner_user_id'] = row['owner_user_id']
    return record


def connector_visible_to_identity(identity, row):
    if not identity or (row['status'] or 'active') != 'active':
        return False
    scope = row['scope']
    if scope == 'platform':
        return is_admin_identity(identity)
    if scope == 'personal':
        return bool(row['owner_user_id'] and row['owner_user_id'] == identity_user_id(identity))
    if scope != 'workspace':
        return False
    if is_admin_identity(identity):
        return True
    if row['workspace_id'] != identity_workspace_id(identity):
        return False
    policy = parse_json_field(row['policy_json'], {})
    allowed_users = set(policy.get('allowed_users') or [])
    allowed_roles = set(policy.get('allowed_roles') or [])
    role = ((identity.get('user') or {}).get('role') or '').lower()
    uid = identity_user_id(identity)
    return (not allowed_users and not allowed_roles) or uid in allowed_users or role in allowed_roles


def list_governed_connectors(identity):
    conn = runtime_connector_db()
    rows = conn.execute('SELECT * FROM governed_connectors ORDER BY scope, name').fetchall()
    connectors = [governed_connector_to_record(row, identity) for row in rows if connector_visible_to_identity(identity, row)]
    conn.close()
    return {
        'connectors': connectors,
        'summary': {
            'total': len(connectors),
            'platform': sum(1 for c in connectors if c.get('scope') == 'platform'),
            'workspace': sum(1 for c in connectors if c.get('scope') == 'workspace'),
            'personal': sum(1 for c in connectors if c.get('scope') == 'personal'),
        },
    }


def governed_connector_row(conn, connector_id):
    cid = safe_id(connector_id)
    if not cid:
        return None
    return conn.execute('SELECT * FROM governed_connectors WHERE id=?', (cid,)).fetchone()


def authorize_connector_action(identity, connector_id, agent_id, action):
    action_id = safe_id(action).lower()
    if action_id not in CONNECTOR_ACTIONS:
        return {'ok': False, 'error': f'Connector action {action} is not allowed.'}, 403
    conn = runtime_connector_db()
    row = governed_connector_row(conn, connector_id)
    conn.close()
    if not row or not connector_visible_to_identity(identity, row):
        return {'ok': False, 'error': 'Connector not authorized for this user or workspace.'}, 403
    policy = parse_json_field(row['policy_json'], {})
    if action_id not in (policy.get('allowed_actions') or []):
        return {'ok': False, 'error': f'Connector action {action_id} is not allowed by policy.'}, 403
    aid = safe_id(agent_id)
    con = auth_db_connect()
    agent_row = con.execute('SELECT * FROM agent_directory WHERE id=? AND status="active"', (aid,)).fetchone()
    access = effective_agent_access_map(con, identity_user_id(identity), identity_workspace_id(identity), role=((identity or {}).get('user') or {}).get('role'), identity=identity) if identity else {}
    con.close()
    if not agent_row:
        return {'ok': False, 'error': 'Agent not found.'}, 404
    selected_agent = access.get(aid)
    agent = selected_agent or agent_directory_row(agent_row, None, identity)
    selected = bool(selected_agent or (is_personal_agent(agent) and agent.get('owner_user_id') == identity_user_id(identity)))
    if not can_user_run_agent(identity, agent, selected=selected):
        return {'ok': False, 'error': 'Agent is not authorized for this user or workspace.'}, 403
    agent_class = normalize_agent_class(agent.get('agent_class'))
    if agent_class == 'personal' and row['connector_type'] in WORKSPACE_TRANSACTION_DOMAINS:
        return {'ok': False, 'error': 'Personal agents cannot access company transaction connectors by default.'}, 403
    if agent_class not in (policy.get('allowed_agent_classes') or []):
        return {'ok': False, 'error': f'{agent_class} agents are not allowed to use this connector.'}, 403
    approval_required = action_id in (policy.get('approval_required_for') or [])
    return {'ok': True, 'connector_id': row['id'], 'agent_id': aid, 'action': action_id, 'approval_required': approval_required, 'quota': (policy.get('quotas') or {})}, 200


APPROVAL_POLICY_LEVELS = ('platform', 'workspace', 'role', 'user', 'agent', 'connector', 'action')


def approval_action_id(value):
    return re.sub(r'[^a-z0-9_:-]+', '_', str(value or '').strip().lower()).strip('_')


def approval_policy_action_set(policy, *keys):
    if not isinstance(policy, dict):
        return set()
    actions = set()
    for key in keys:
        value = policy.get(key)
        if isinstance(value, str):
            value = [value]
        if isinstance(value, list):
            actions.update(approval_action_id(item) for item in value if str(item).strip())
    return {a for a in actions if a}


def evaluate_approval_policy(identity, context=None):
    """Evaluate hierarchical action policy before backend execution.

    Decision order is intentionally conservative: the first deny in the
    platform→workspace→role→user→agent→connector→action hierarchy blocks the
    action. If no deny matches, the first approval requirement pauses the action
    and creates an Approval Gate request. Otherwise the action is allowed.
    """
    context = context or {}
    action = approval_action_id(context.get('action') or context.get('action_id'))
    if not action:
        return {'ok': False, 'decision': 'denied', 'matched_level': 'action', 'reason': 'action is required'}
    for level in APPROVAL_POLICY_LEVELS:
        policy = context.get(f'{level}_policy') if isinstance(context.get(f'{level}_policy'), dict) else {}
        denied = approval_policy_action_set(policy, 'deny_actions', 'denied_actions', 'restricted_actions')
        if action in denied or '*' in denied:
            return {'ok': False, 'decision': 'denied', 'matched_level': level, 'reason': f'{action} denied by {level} policy'}
    for level in APPROVAL_POLICY_LEVELS:
        policy = context.get(f'{level}_policy') if isinstance(context.get(f'{level}_policy'), dict) else {}
        required = approval_policy_action_set(policy, 'require_approval_for', 'approval_required_for', 'requires_approval')
        if action in required or '*' in required:
            return {'ok': True, 'decision': 'approval_required', 'matched_level': level, 'reason': f'{action} requires approval by {level} policy'}
    return {'ok': True, 'decision': 'allowed', 'matched_level': None, 'reason': 'no approval policy matched'}


def record_approval_policy_audit(identity, action, context=None, extra=None):
    context = context or {}
    extra = extra or {}
    evidence = {
        'approval_policy': True,
        'action': context.get('action'),
        'agent_id': context.get('agent_id'),
        'connector_id': context.get('connector_id'),
        'decision': extra.get('decision'),
        'matched_level': extra.get('matched_level'),
        'approval_id': extra.get('approval_id'),
    }
    if context.get('browser_evidence'):
        evidence['browser_evidence'] = context.get('browser_evidence')
    evidence.update({k: v for k, v in extra.items() if k not in evidence and v is not None})
    resource_type = context.get('resource_type') or 'approval_policy_action'
    resource_id = context.get('resource_id') or context.get('connector_id') or context.get('action') or 'unknown'
    return record_workspace_audit_event(identity, action, resource_type, resource_id, evidence)


def create_approval_policy_request(identity, context, decision):
    now = int(time.time())
    action = approval_action_id(context.get('action'))
    resource_type = context.get('resource_type') or 'approval_policy_action'
    resource_id = context.get('resource_id') or context.get('connector_id') or action or 'unknown'
    agent_id = safe_id(context.get('agent_id') or 'agent') or 'agent'
    digest = hashlib.sha1(json.dumps({
        'workspace_id': identity_workspace_id(identity), 'user_id': identity_user_id(identity),
        'action': action, 'agent_id': agent_id, 'connector_id': context.get('connector_id'),
        'resource_type': resource_type, 'resource_id': resource_id, 'ts': now, 'nonce': time.time_ns(),
    }, sort_keys=True, default=str).encode()).hexdigest()[:16]
    item_id = f'approval-policy-{digest}'
    metadata = {
        'derived_from': 'approval_policy',
        'workspace_id': identity_workspace_id(identity),
        'user_id': identity_user_id(identity),
        'action': action,
        'agent_id': agent_id,
        'connector_id': context.get('connector_id'),
        'resource_type': resource_type,
        'resource_id': resource_id,
        'policy_decision': decision,
    }
    if context.get('browser_evidence'):
        metadata['browser_evidence'] = context.get('browser_evidence')
    title = f'Approve {action.replace("_", " ")} before execution'
    action_label = action.replace('_', ' ')
    resource_label = ' '.join(str(part).strip() for part in [resource_type, resource_id] if str(part or '').strip()) or 'the requested resource'
    connector_label = f' through connector {context.get("connector_id")}' if context.get('connector_id') else ''
    reason = decision.get('reason') or 'workspace policy requires a human decision before this action runs'
    description = (
        f'You are approving {agent_id} to {action_label} on {resource_label}{connector_label}. '
        f'Reason approval is required: {reason}. '
        'Approve records permission for this paused policy-gated action; Reject keeps it blocked.'
    )
    con = ensure_approvals_tables()
    con.execute("""
        INSERT INTO approvals (id,title,description,body,kind,status,risk,source,source_id,source_path,destination,agent_id,agent_name,created_at,updated_at,metadata)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    """, (item_id, title, description, description, 'approval_policy_action', 'drafted', 'high', 'approval_policy', resource_id, None, 'Mission Control Approval Gates', agent_id, agent_id, now, now, json.dumps(metadata)))
    con.commit()
    row = con.execute('SELECT * FROM approvals WHERE id=?', (item_id,)).fetchone()
    out = inbox_row(row)
    con.close()
    return out


def identity_from_approval_metadata(metadata):
    if not isinstance(metadata, dict):
        return None
    workspace_id = metadata.get('workspace_id')
    user_id = metadata.get('user_id')
    if not workspace_id:
        return None
    return {'workspace_id': workspace_id, 'user': {'id': user_id or 'approval-policy'}, 'workspace': {'id': workspace_id}, 'role': 'system'}


def run_policy_guarded_action(identity, context=None, executor=None):
    context = dict(context or {})
    action = approval_action_id(context.get('action'))
    context['action'] = action
    if context.get('connector_id'):
        auth, status = authorize_connector_action(identity, context.get('connector_id'), context.get('agent_id'), action)
        if status != 200 or not auth.get('ok'):
            record_approval_policy_audit(identity, 'approval_policy.action_denied', context, {'decision': 'denied', 'reason': auth.get('error') if isinstance(auth, dict) else None})
            return {'ok': False, 'status': 'blocked', 'error': auth.get('error') if isinstance(auth, dict) else 'connector action denied'}, status
        if auth.get('approval_required'):
            context['connector_policy'] = {**(context.get('connector_policy') or {}), 'require_approval_for': [action]}
    decision = evaluate_approval_policy(identity, context)
    if decision.get('decision') == 'denied':
        record_approval_policy_audit(identity, 'approval_policy.action_denied', context, decision)
        return {'ok': False, 'status': 'blocked', 'error': decision.get('reason'), 'policy': decision}, 403
    if decision.get('decision') == 'approval_required':
        request = create_approval_policy_request(identity, context, decision)
        record_approval_policy_audit(identity, 'approval_policy.request_created', context, {**decision, 'approval_id': request.get('id')})
        return {'ok': True, 'status': 'paused', 'approval_required': True, 'approval_request': request, 'policy': decision}, 202
    execution = executor() if callable(executor) else {'ok': True}
    record_approval_policy_audit(identity, 'approval_policy.action_executed', context, decision)
    return {'ok': True, 'status': 'executed', 'approval_required': False, 'execution': execution, 'policy': decision}, 200


ROUTINE_TYPES = {'platform', 'workspace', 'personal'}


def normalize_routine_type(value):
    routine_type = safe_id(value or '').lower()
    return routine_type if routine_type in ROUTINE_TYPES else 'workspace'


def normalize_routine_dependencies(value):
    if not isinstance(value, list):
        return []
    out = []
    for item in value[:12]:
        if not isinstance(item, dict):
            continue
        connector_id = safe_id(item.get('connector_id') or item.get('id'))
        action = safe_id(item.get('action') or 'read').lower() or 'read'
        if connector_id:
            out.append({'connector_id': connector_id, 'action': action})
    return out


def workflow_run_detail_url(run_id):
    rid = safe_id(run_id)
    return f'/app?view=audit&run={rid}' if rid else '/app?view=audit'


def usage_number(value, default=0.0):
    try:
        if value is None or value == '':
            return default
        return float(value)
    except Exception:
        return default


def usage_int(value, default=0):
    try:
        if value is None or value == '':
            return default
        return int(float(value))
    except Exception:
        return default


def workflow_usage_token_metrics(metadata=None):
    metadata = metadata or {}
    token_usage = metadata.get('token_usage') if isinstance(metadata.get('token_usage'), dict) else {}
    input_tokens = usage_int(token_usage.get('input_tokens', metadata.get('input_tokens')))
    output_tokens = usage_int(token_usage.get('output_tokens', metadata.get('output_tokens')))
    cache_read = usage_int(token_usage.get('cache_read_tokens', metadata.get('cache_read_tokens')))
    cache_write = usage_int(token_usage.get('cache_write_tokens', metadata.get('cache_write_tokens')))
    reasoning = usage_int(token_usage.get('reasoning_tokens', metadata.get('reasoning_tokens')))
    return {
        'input_tokens': input_tokens,
        'output_tokens': output_tokens,
        'cache_read_tokens': cache_read,
        'cache_write_tokens': cache_write,
        'reasoning_tokens': reasoning,
        'total_tokens': input_tokens + output_tokens + cache_read + cache_write + reasoning,
    }


def workflow_usage_browser_metrics(metadata=None):
    metadata = metadata or {}
    evidence = metadata.get('browser_evidence') if isinstance(metadata.get('browser_evidence'), dict) else {}
    sessions = evidence.get('sessions') if isinstance(evidence.get('sessions'), list) else []
    minutes = usage_number(metadata.get('browser_minutes'))
    actions = usage_int(metadata.get('browser_actions'))
    for session in sessions:
        if not isinstance(session, dict):
            continue
        minutes += usage_number(session.get('duration_minutes') or session.get('minutes'))
        actions += usage_int(session.get('actions') or session.get('action_count'))
    return {'browser_minutes': minutes, 'browser_actions': actions, 'browser_sessions': len(sessions)}


def workflow_usage_file_metrics(metadata=None):
    metadata = metadata or {}
    extraction = metadata.get('file_extraction') if isinstance(metadata.get('file_extraction'), dict) else {}
    return {
        'file_extraction_count': usage_int(extraction.get('count', metadata.get('file_extraction_count'))),
        'file_extraction_size_bytes': usage_int(extraction.get('size_bytes', metadata.get('file_extraction_size_bytes'))),
    }


def workflow_usage_research_depth(metadata=None):
    metadata = metadata or {}
    research = metadata.get('research_run') if isinstance(metadata.get('research_run'), dict) else {}
    return safe_id(metadata.get('research_depth') or research.get('depth') or research.get('mode') or '').lower()


def build_workflow_usage(row, identity=None, metadata=None):
    metadata = metadata or {}
    token_metrics = workflow_usage_token_metrics(metadata)
    browser_metrics = workflow_usage_browser_metrics(metadata)
    file_metrics = workflow_usage_file_metrics(metadata)
    run_type = safe_id(metadata.get('run_type') or ('research' if metadata.get('research_run') else 'routine')).lower() or 'routine'
    provider = safe_id(metadata.get('provider') or metadata.get('model_provider') or '').lower()
    model = str(metadata.get('model') or metadata.get('model_name') or '').strip()
    connector_id = safe_id(metadata.get('connector_id') or '') or None
    research_depth = workflow_usage_research_depth(metadata)
    attribution = {
        'workspace_id': row['workspace_id'] or identity_workspace_id(identity),
        'runtime_id': row['runtime_id'],
        'user_id': identity_user_id(identity) or row['owner_user_id'],
        'role_id': ((identity or {}).get('user') or {}).get('role') or (identity or {}).get('role'),
        'agent_id': row['agent_id'],
        'agent_class': normalize_agent_class(row['agent_class'] or row['routine_type']),
        'connector_id': connector_id,
        'routine_id': row['id'],
        'run_type': run_type,
        'model': model,
        'provider': provider,
        'routine_type': row['routine_type'],
        'owner_user_id': row['owner_user_id'],
        'research_depth': research_depth,
    }
    metrics = {
        **token_metrics,
        'estimated_cost_usd': usage_number(metadata.get('estimated_cost_usd') if 'estimated_cost_usd' in metadata else metadata.get('cost_usd')),
        **browser_metrics,
        **file_metrics,
    }
    return {'attribution': attribution, 'metrics': metrics}


def quota_limit_exceeded(limit, actual):
    if limit is None:
        return False
    try:
        return float(actual or 0) > float(limit)
    except Exception:
        return False


def quota_remaining_exceeded(value, actual=1):
    if value is None:
        return False
    try:
        return float(value) < float(actual or 1)
    except Exception:
        return False


def evaluate_usage_quota(identity, row, metadata=None, quota_policy=None):
    quota_policy = quota_policy if isinstance(quota_policy, dict) else {}
    usage = build_workflow_usage(row, identity, metadata)
    attribution = usage['attribution']
    metrics = usage['metrics']
    violations = []

    # Support both structured Phase 11 policies and legacy flat routine policies.
    for level in ('platform', 'workspace', 'user', 'agent', 'routine', 'connector', 'model_provider'):
        policy = quota_policy.get(level) if isinstance(quota_policy.get(level), dict) else {}
        if quota_remaining_exceeded(policy.get('remaining_runs')):
            violations.append({'level': level, 'metric': 'runs', 'limit': policy.get('remaining_runs'), 'actual': 1})
        if quota_limit_exceeded(policy.get('max_estimated_cost_usd'), metrics.get('estimated_cost_usd')):
            violations.append({'level': level, 'metric': 'estimated_cost_usd', 'limit': policy.get('max_estimated_cost_usd'), 'actual': metrics.get('estimated_cost_usd')})
        if quota_limit_exceeded(policy.get('max_tokens'), metrics.get('total_tokens')):
            violations.append({'level': level, 'metric': 'total_tokens', 'limit': policy.get('max_tokens'), 'actual': metrics.get('total_tokens')})
        if level == 'connector' and attribution.get('connector_id') and policy.get('blocked') is True:
            violations.append({'level': level, 'metric': 'connector', 'limit': 'allowed', 'actual': 'blocked'})

    research_policy = quota_policy.get('research_depth') if isinstance(quota_policy.get('research_depth'), dict) else {}
    depth = attribution.get('research_depth') or 'basic'
    depth_policy = research_policy.get(depth) if isinstance(research_policy.get(depth), dict) else {}
    if depth_policy:
        if quota_remaining_exceeded(depth_policy.get('remaining_runs')):
            violations.append({'level': 'research_depth', 'metric': f'{depth}_runs', 'limit': depth_policy.get('remaining_runs'), 'actual': 1})
        if quota_limit_exceeded(depth_policy.get('max_estimated_cost_usd'), metrics.get('estimated_cost_usd')):
            violations.append({'level': 'research_depth', 'metric': f'{depth}_estimated_cost_usd', 'limit': depth_policy.get('max_estimated_cost_usd'), 'actual': metrics.get('estimated_cost_usd')})

    browser_policy = quota_policy.get('browser') if isinstance(quota_policy.get('browser'), dict) else {}
    if quota_remaining_exceeded(browser_policy.get('remaining_minutes'), metrics.get('browser_minutes')):
        violations.append({'level': 'browser', 'metric': 'browser_minutes', 'limit': browser_policy.get('remaining_minutes'), 'actual': metrics.get('browser_minutes')})
    if quota_remaining_exceeded(browser_policy.get('remaining_actions'), metrics.get('browser_actions')):
        violations.append({'level': 'browser', 'metric': 'browser_actions', 'limit': browser_policy.get('remaining_actions'), 'actual': metrics.get('browser_actions')})

    file_policy = quota_policy.get('file_extraction') if isinstance(quota_policy.get('file_extraction'), dict) else {}
    if quota_limit_exceeded(file_policy.get('max_size_bytes'), metrics.get('file_extraction_size_bytes')):
        violations.append({'level': 'file_extraction', 'metric': 'size_bytes', 'limit': file_policy.get('max_size_bytes'), 'actual': metrics.get('file_extraction_size_bytes')})
    if quota_limit_exceeded(file_policy.get('max_count'), metrics.get('file_extraction_count')):
        violations.append({'level': 'file_extraction', 'metric': 'count', 'limit': file_policy.get('max_count'), 'actual': metrics.get('file_extraction_count')})

    legacy_reason = routine_quota_block_reason(quota_policy)
    if legacy_reason:
        violations.append({'level': 'routine', 'metric': 'legacy_policy', 'limit': 'allowed', 'actual': legacy_reason})

    if violations:
        return {'ok': False, 'decision': 'blocked', 'reason': 'Quota policy blocks execution before run start.', 'violations': violations, 'usage': usage}
    return {'ok': True, 'decision': 'allowed', 'reason': 'Usage is within configured quota.', 'violations': [], 'usage': usage}


def workflow_routine_run_to_record(row):
    if not row:
        return None
    metadata = parse_json_field(row['metadata_json'], {})
    usage = metadata.get('usage') if isinstance(metadata.get('usage'), dict) else None
    record = {
        'id': row['id'],
        'routine_id': row['routine_id'],
        'workspace_id': row['workspace_id'],
        'owner_user_id': row['owner_user_id'],
        'runtime_id': row['runtime_id'],
        'agent_id': row['agent_id'],
        'agent_class': row['agent_class'],
        'scope': row['agent_class'] if row['agent_class'] in ROUTINE_TYPES else ('personal' if row['owner_user_id'] else 'workspace'),
        'status': row['status'],
        'reason': row['reason'] or '',
        'approval_request_id': row['approval_request_id'],
        'browser_evidence': parse_json_field(row['browser_evidence_json'], {}),
        'research_run': parse_json_field(row['research_run_json'], {}),
        'metadata': metadata,
        'usage': usage or {},
        'artifacts': metadata.get('artifacts') if isinstance(metadata.get('artifacts'), list) else [],
        'started_at': utc_iso(row['started_at']),
        'completed_at': utc_iso(row['completed_at']) if row['completed_at'] else None,
        'run_detail_url': workflow_run_detail_url(row['id']),
    }
    return record


def workflow_routine_row_for_run(conn, run_row):
    if not run_row:
        return None
    return conn.execute('SELECT * FROM workflow_routines WHERE id=?', (run_row['routine_id'],)).fetchone()


def workflow_run_visible_to_identity(identity, run_row, routine_row=None):
    if not identity or not run_row:
        return False
    if routine_row is not None:
        return workflow_routine_visible_to_identity(identity, routine_row)
    if is_admin_identity(identity):
        return True
    if run_row['owner_user_id']:
        return run_row['owner_user_id'] == identity_user_id(identity)
    return bool(run_row['workspace_id'] and run_row['workspace_id'] == identity_workspace_id(identity))


def run_contextual_access_payload(run_record):
    browser_evidence = run_record.get('browser_evidence') if isinstance(run_record.get('browser_evidence'), dict) else {}
    research_run = run_record.get('research_run') if isinstance(run_record.get('research_run'), dict) else {}
    return {
        'surfaces': ['audit', 'approval', 'costs', 'quota', 'workspace-runtime-console'],
        'audit_url': run_record.get('run_detail_url') or workflow_run_detail_url(run_record.get('id')),
        'approval_request_id': run_record.get('approval_request_id'),
        'has_browser_evidence': bool(browser_evidence),
        'has_research_run': bool(research_run),
        'artifact_count': len(run_record.get('artifacts') or []),
        'note': 'Browser evidence and research details are contextual run evidence, not standalone Admin menu items.',
    }


def list_workspace_run_history(query=None, identity=None):
    query = query or {}
    conn = runtime_connector_db()
    rows = conn.execute('SELECT * FROM workflow_routine_runs ORDER BY started_at DESC LIMIT 200').fetchall()
    runs = []
    for row in rows:
        routine_row = workflow_routine_row_for_run(conn, row)
        if not workflow_run_visible_to_identity(identity, row, routine_row):
            continue
        record = workflow_routine_run_to_record(row)
        if routine_row:
            record['routine_name'] = routine_row['name']
            record['scope'] = routine_row['routine_type']
        record['contextual_access'] = run_contextual_access_payload(record)
        runs.append(record)
    conn.close()
    q = ''
    if isinstance(query, dict):
        q = (query.get('q') or [''])[0] if isinstance(query.get('q'), list) else query.get('q') or ''
    q = str(q or '').strip().lower()
    if q:
        runs = [r for r in runs if q in ' '.join(str(r.get(k) or '') for k in ('id', 'routine_id', 'routine_name', 'status', 'agent_id', 'scope')).lower()]
    return {
        'ok': True,
        'runs': runs,
        'summary': {
            'total': len(runs),
            'browser_evidence': sum(1 for r in runs if r.get('contextual_access', {}).get('has_browser_evidence')),
            'research_runs': sum(1 for r in runs if r.get('contextual_access', {}).get('has_research_run')),
            'artifacts': sum(len(r.get('artifacts') or []) for r in runs),
        },
        'contextual_access': {'surfaces': ['audit', 'approval', 'costs', 'quota', 'workspace-runtime-console']},
    }


def workspace_run_detail(identity, run_id):
    rid = safe_id(run_id)
    conn = runtime_connector_db()
    row = conn.execute('SELECT * FROM workflow_routine_runs WHERE id=?', (rid,)).fetchone()
    routine_row = workflow_routine_row_for_run(conn, row)
    if not row or not workflow_run_visible_to_identity(identity, row, routine_row):
        conn.close()
        return {'ok': False, 'error': 'run not found'}, 404
    run = workflow_routine_run_to_record(row)
    if routine_row:
        run['routine_name'] = routine_row['name']
        run['scope'] = routine_row['routine_type']
        run['routine'] = workflow_routine_to_record(routine_row, identity, include_private=is_admin_identity(identity))
    run['contextual_access'] = run_contextual_access_payload(run)
    conn.close()
    return {'ok': True, 'run': run, 'contextual_access': run['contextual_access']}, 200


def evaluate_research_policy(identity, request=None):
    request = request or {}
    mode = safe_id(request.get('mode') or request.get('research_type') or 'basic').lower() or 'basic'
    quota = request.get('quota') if isinstance(request.get('quota'), dict) else {}
    role = ((identity or {}).get('user') or {}).get('role') or (identity or {}).get('role') or ''
    allowed_internal_roles = set(request.get('internal_doc_roles') or ['admin'])
    if request.get('use_internal_docs') and role not in allowed_internal_roles:
        return {'ok': False, 'decision': 'blocked', 'mode': mode, 'reason': 'Internal docs require role-controlled access.'}
    if mode in ('download', 'extract', 'extract-files', 'download-files') or request.get('download') or request.get('extract_files'):
        if request.get('approval') is True or request.get('permission') in ('approved', 'allowed') or role == 'admin':
            return {'ok': True, 'decision': 'allowed', 'mode': mode, 'reason': 'Download/extract action permitted by approval or admin role.'}
        return {'ok': False, 'decision': 'blocked', 'mode': mode, 'reason': 'Download / extract files is restricted without approval or permission.'}
    if mode in ('deep', 'deep-research'):
        remaining = quota.get('remaining_deep_runs', quota.get('remaining_runs', quota.get('deep_remaining')))
        try:
            if remaining is not None and float(remaining) <= 0:
                return {'ok': False, 'decision': 'blocked', 'mode': mode, 'reason': 'Deep research quota exceeded.'}
        except Exception:
            pass
        return {'ok': True, 'decision': 'allowed', 'mode': mode, 'reason': 'Deep research is within quota.'}
    if mode in ('browser', 'browser-research'):
        if request.get('approval') is True or request.get('approval_status') == 'approved':
            return {'ok': True, 'decision': 'allowed', 'mode': mode, 'reason': 'Browser research approved.'}
        remaining = quota.get('remaining_browser_runs', quota.get('remaining_runs', quota.get('browser_remaining')))
        try:
            if remaining is not None and float(remaining) <= 0:
                return {'ok': False, 'decision': 'blocked', 'mode': mode, 'reason': 'Browser research quota exceeded.'}
        except Exception:
            pass
        return {'ok': True, 'decision': 'approval_required', 'mode': mode, 'reason': 'Browser research requires approval unless an explicit quota/approval policy allows execution.'}
    return {'ok': True, 'decision': 'allowed', 'mode': 'basic', 'reason': 'Basic research is allowed.'}


def workflow_routine_to_record(row, identity=None, include_private=False):
    if not row:
        return None
    last_run = None
    if row['last_run_id']:
        conn = runtime_connector_db()
        run_row = conn.execute('SELECT * FROM workflow_routine_runs WHERE id=?', (row['last_run_id'],)).fetchone()
        conn.close()
        last_run = workflow_routine_run_to_record(run_row)
    record = {
        'id': row['id'],
        'name': row['name'],
        'routine_type': row['routine_type'],
        'workspace_id': row['workspace_id'] if include_private or is_admin_identity(identity) or row['routine_type'] == 'workspace' else row['workspace_id'],
        'runtime_id': row['runtime_id'],
        'profile_id': row['profile_id'],
        'agent_id': row['agent_id'],
        'agent_class': row['agent_class'],
        'scheduler_source': row['scheduler_source'] or 'mission_control',
        'hermes_cron_job_id': row['hermes_cron_job_id'],
        'delivery_target': row['delivery_target'] or '',
        'duplicate_execution_guard': row['duplicate_execution_guard'] or '',
        'last_run_evidence': parse_json_field(row['last_run_evidence_json'], {}),
        'schedule': row['schedule'] or '',
        'trigger_status': row['trigger_status'] or 'enabled',
        'connector_dependencies': parse_json_field(row['connector_dependencies_json'], []),
        'approval_policy_dependency': parse_json_field(row['approval_policy_json'], {}),
        'quota_impact': parse_json_field(row['quota_impact_json'], {}),
        'quota_policy': parse_json_field(row['quota_policy_json'], {}) if (include_private or is_admin_identity(identity)) else {},
        'last_run': last_run,
        'next_run_at': utc_iso(row['next_run_at']) if row['next_run_at'] else None,
        'run_status': row['run_status'] or 'idle',
        'status': row['status'] or 'active',
        'created_at': utc_iso(row['created_at']),
        'updated_at': utc_iso(row['updated_at']),
        'run_detail_url': workflow_run_detail_url(row['last_run_id']) if row['last_run_id'] else None,
    }
    if include_private or is_admin_identity(identity):
        record['owner_user_id'] = row['owner_user_id']
    return record


def workflow_routine_visible_to_identity(identity, row):
    if not identity or not row or (row['status'] or 'active') != 'active':
        return False
    routine_type = row['routine_type']
    if routine_type == 'platform':
        return is_admin_identity(identity)
    if routine_type == 'personal':
        return bool(row['owner_user_id'] and row['owner_user_id'] == identity_user_id(identity))
    if routine_type == 'workspace':
        return is_admin_identity(identity) or (row['workspace_id'] and row['workspace_id'] == identity_workspace_id(identity))
    return False


def workflow_routine_manage_allowed(identity, routine_type, workspace_id=None, owner_user_id=None):
    if not identity:
        return False, 'Authentication required.'
    if routine_type == 'platform':
        return is_admin_identity(identity), 'Admin permission required to manage Platform routines.'
    if routine_type == 'personal':
        return bool(owner_user_id == identity_user_id(identity)), 'Personal routine is private to its owner.'
    if is_admin_identity(identity):
        return True, ''
    if workspace_id and workspace_id == identity_workspace_id(identity):
        return True, ''
    return False, 'Routine is outside this workspace.'


def upsert_workflow_routine(identity, payload, routine_id=None):
    payload = payload or {}
    rid = safe_id(routine_id or payload.get('id') or payload.get('name'))[:100]
    if not rid:
        return {'ok': False, 'error': 'Routine id is required.'}, 400
    conn = runtime_connector_db()
    existing = conn.execute('SELECT * FROM workflow_routines WHERE id=?', (rid,)).fetchone()
    existing_type = existing['routine_type'] if existing else None
    routine_type = normalize_routine_type(payload.get('routine_type') or payload.get('type') or existing_type)
    workspace_id = payload.get('workspace_id') or (existing['workspace_id'] if existing else None) or (identity_workspace_id(identity) if routine_type == 'workspace' else None)
    owner_user_id = payload.get('owner_user_id') or (existing['owner_user_id'] if existing else None) or (identity_user_id(identity) if routine_type == 'personal' else None)
    allowed, reason = workflow_routine_manage_allowed(identity, routine_type, workspace_id, owner_user_id)
    if not allowed:
        conn.close()
        return {'ok': False, 'error': reason}, 403
    if routine_type == 'workspace' and not workspace_id:
        conn.close()
        return {'ok': False, 'error': 'Workspace routine requires workspace_id.'}, 400
    if routine_type == 'personal' and not owner_user_id:
        conn.close()
        return {'ok': False, 'error': 'Personal routine requires owner_user_id.'}, 400
    name = str(payload.get('name') or (existing['name'] if existing else rid)).strip()[:160] or rid
    agent_class = normalize_agent_class(payload.get('agent_class') or (existing['agent_class'] if existing else routine_type))
    if routine_type == 'platform':
        agent_class = 'platform'
    elif routine_type == 'personal':
        agent_class = 'personal'
    runtime_id = safe_id(payload.get('runtime_id') or (existing['runtime_id'] if existing else '') or '') or None
    profile_id = safe_id(payload.get('profile_id') or payload.get('profileId') or (existing['profile_id'] if existing else '') or '') or None
    scheduler_source = safe_id(payload.get('scheduler_source') or payload.get('schedulerSource') or (existing['scheduler_source'] if existing else '') or 'mission_control') or 'mission_control'
    hermes_cron_job_id = safe_id(payload.get('hermes_cron_job_id') or payload.get('hermesCronJobId') or (existing['hermes_cron_job_id'] if existing else '') or '') or None
    delivery_target = str(payload.get('delivery_target') or payload.get('deliveryTarget') or (existing['delivery_target'] if existing else '') or '')[:300]
    duplicate_execution_guard = str(payload.get('duplicate_execution_guard') or payload.get('duplicateExecutionGuard') or (existing['duplicate_execution_guard'] if existing else '') or '')[:300]
    if duplicate_execution_guard:
        duplicate = conn.execute('SELECT id FROM workflow_routines WHERE duplicate_execution_guard=? AND id != ? AND coalesce(status,\'active\') != \'archived\'', (duplicate_execution_guard, rid)).fetchone()
        if duplicate:
            conn.close()
            return {'ok': False, 'error': 'Duplicate routine execution guard already exists.', 'duplicate_id': duplicate['id']}, 409
    last_run_evidence = payload.get('last_run_evidence') if isinstance(payload.get('last_run_evidence'), dict) else parse_json_field(existing['last_run_evidence_json'], {}) if existing else {}
    agent_id = safe_id(payload.get('agent_id') or (existing['agent_id'] if existing else '') or 'devops') or 'devops'
    dependencies = normalize_routine_dependencies(payload.get('connector_dependencies') if 'connector_dependencies' in payload else parse_json_field(existing['connector_dependencies_json'], []) if existing else [])
    approval_policy = payload.get('approval_policy_dependency') if isinstance(payload.get('approval_policy_dependency'), dict) else parse_json_field(existing['approval_policy_json'], {}) if existing else {}
    quota_impact = payload.get('quota_impact') if isinstance(payload.get('quota_impact'), dict) else parse_json_field(existing['quota_impact_json'], {}) if existing else {}
    quota_policy = payload.get('quota_policy') if isinstance(payload.get('quota_policy'), dict) else parse_json_field(existing['quota_policy_json'], {}) if existing else {}
    now = time.time()
    conn.execute("""
        INSERT INTO workflow_routines (id,name,routine_type,workspace_id,owner_user_id,runtime_id,profile_id,agent_id,agent_class,schedule,trigger_status,connector_dependencies_json,approval_policy_json,quota_impact_json,quota_policy_json,last_run_id,next_run_at,run_status,status,created_at,updated_at,scheduler_source,hermes_cron_job_id,delivery_target,duplicate_execution_guard,last_run_evidence_json)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(id) DO UPDATE SET name=excluded.name, routine_type=excluded.routine_type, workspace_id=excluded.workspace_id,
            owner_user_id=excluded.owner_user_id, runtime_id=excluded.runtime_id, profile_id=excluded.profile_id, agent_id=excluded.agent_id, agent_class=excluded.agent_class,
            schedule=excluded.schedule, trigger_status=excluded.trigger_status, connector_dependencies_json=excluded.connector_dependencies_json,
            approval_policy_json=excluded.approval_policy_json, quota_impact_json=excluded.quota_impact_json, quota_policy_json=excluded.quota_policy_json,
            next_run_at=excluded.next_run_at, status=excluded.status, updated_at=excluded.updated_at, scheduler_source=excluded.scheduler_source,
            hermes_cron_job_id=excluded.hermes_cron_job_id, delivery_target=excluded.delivery_target,
            duplicate_execution_guard=excluded.duplicate_execution_guard, last_run_evidence_json=excluded.last_run_evidence_json
    """, (
        rid, name, routine_type, workspace_id if routine_type == 'workspace' else None,
        owner_user_id if routine_type == 'personal' else None, runtime_id, profile_id, agent_id, agent_class,
        str(payload.get('schedule') or (existing['schedule'] if existing else '') or ''),
        safe_id(payload.get('trigger_status') or (existing['trigger_status'] if existing else '') or 'enabled') or 'enabled',
        json.dumps(dependencies), json.dumps(approval_policy), json.dumps(quota_impact), json.dumps(quota_policy),
        existing['last_run_id'] if existing else None,
        float(payload.get('next_run_at')) if str(payload.get('next_run_at') or '').replace('.', '', 1).isdigit() else (existing['next_run_at'] if existing else None),
        existing['run_status'] if existing else 'idle', payload.get('status') or (existing['status'] if existing else 'active'),
        existing['created_at'] if existing else now, now,
        scheduler_source, hermes_cron_job_id, delivery_target, duplicate_execution_guard, json.dumps(last_run_evidence),
    ))
    conn.commit()
    row = conn.execute('SELECT * FROM workflow_routines WHERE id=?', (rid,)).fetchone()
    record = workflow_routine_to_record(row, identity, include_private=True)
    conn.close()
    record_workspace_audit_event(identity, 'workflow_routine.upserted', 'workflow_routine', rid, {'routine_type': routine_type, 'workspace_id': workspace_id, 'agent_id': agent_id})
    return {'ok': True, 'routine': record}, 200


def list_workflow_routines(identity=None, query=None):
    conn = runtime_connector_db()
    rows = conn.execute('SELECT * FROM workflow_routines ORDER BY routine_type, name').fetchall()
    routines = [workflow_routine_to_record(row, identity) for row in rows if workflow_routine_visible_to_identity(identity, row)]
    conn.close()
    q = ''
    if isinstance(query, dict):
        q = (query.get('q') or [''])[0] if isinstance(query.get('q'), list) else query.get('q') or ''
    q = str(q or '').strip().lower()
    if q:
        routines = [r for r in routines if q in ' '.join(str(r.get(k) or '') for k in ('id', 'name', 'routine_type', 'runtime_id', 'agent_id', 'agent_class', 'run_status')).lower()]
    return {
        'ok': True,
        'routines': routines,
        'summary': {
            'total': len(routines),
            'platform': sum(1 for r in routines if r.get('routine_type') == 'platform'),
            'workspace': sum(1 for r in routines if r.get('routine_type') == 'workspace'),
            'personal': sum(1 for r in routines if r.get('routine_type') == 'personal'),
            'blocked': sum(1 for r in routines if r.get('run_status') == 'blocked'),
            'paused': sum(1 for r in routines if r.get('run_status') == 'paused'),
        },
    }


def record_workflow_routine_run(conn, row, status, reason='', approval_request_id=None, metadata=None, completed=True, identity=None):
    now = time.time()
    run_id = 'routine-run-' + hashlib.sha1(f"{row['id']}:{now}:{time.time_ns()}".encode()).hexdigest()[:16]
    metadata = metadata or {}
    if not isinstance(metadata.get('usage'), dict):
        metadata = {**metadata, 'usage': build_workflow_usage(row, identity, metadata)}
    conn.execute("""
        INSERT INTO workflow_routine_runs (id,routine_id,workspace_id,owner_user_id,runtime_id,agent_id,agent_class,status,reason,approval_request_id,browser_evidence_json,research_run_json,metadata_json,started_at,completed_at)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    """, (
        run_id, row['id'], row['workspace_id'], row['owner_user_id'], row['runtime_id'], row['agent_id'], row['agent_class'],
        status, reason or '', approval_request_id, json.dumps(metadata.get('browser_evidence') or {}), json.dumps(metadata.get('research_run') or {}),
        json.dumps({k: v for k, v in metadata.items() if k not in ('browser_evidence', 'research_run')}), now, now if completed else None,
    ))
    conn.execute('UPDATE workflow_routines SET last_run_id=?, run_status=?, updated_at=? WHERE id=?', (run_id, status, now, row['id']))
    conn.commit()
    run_row = conn.execute('SELECT * FROM workflow_routine_runs WHERE id=?', (run_id,)).fetchone()
    return workflow_routine_run_to_record(run_row)


def routine_quota_block_reason(quota_policy):
    if not isinstance(quota_policy, dict):
        return ''
    for key in ('remaining_runs', 'remaining_executions'):
        if key in quota_policy:
            try:
                if float(quota_policy.get(key)) <= 0:
                    return 'Routine quota policy blocks execution: no remaining runs.'
            except Exception:
                pass
    if quota_policy.get('blocked') is True or quota_policy.get('status') == 'blocked':
        return str(quota_policy.get('reason') or 'Routine quota policy blocks execution.')
    return ''


def execute_workflow_routine(identity, routine_id, metadata=None):
    metadata = metadata or {}
    rid = safe_id(routine_id)
    conn = runtime_connector_db()
    row = conn.execute('SELECT * FROM workflow_routines WHERE id=?', (rid,)).fetchone()
    if not row or not workflow_routine_visible_to_identity(identity, row):
        conn.close()
        return {'ok': False, 'error': 'Routine not authorized for this user or workspace.'}, 403
    if (row['trigger_status'] or 'enabled') not in ('enabled', 'ready', 'scheduled'):
        run = record_workflow_routine_run(conn, row, 'blocked', 'Routine trigger is disabled.', metadata=metadata, identity=identity)
        conn.close()
        return {'ok': False, 'status': 'blocked', 'error': 'Routine trigger is disabled.', 'run': run}, 403
    quota_policy = parse_json_field(row['quota_policy_json'], {})
    quota_check = evaluate_usage_quota(identity, row, {**parse_json_field(row['quota_impact_json'], {}), **metadata}, quota_policy)
    if quota_check.get('decision') == 'blocked':
        quota_reason = quota_check.get('reason') or 'Quota policy blocks execution before run start.'
        run = record_workflow_routine_run(conn, row, 'blocked', quota_reason, metadata={**metadata, 'quota_policy': quota_policy, 'quota': quota_check, 'usage': quota_check.get('usage')}, identity=identity)
        conn.close()
        record_workspace_audit_event(identity, 'quota.execution_blocked', 'workflow_routine', rid, {'reason': quota_reason, 'quota': quota_check, 'usage': quota_check.get('usage'), 'policy': 'quota'})
        return {'ok': False, 'status': 'blocked', 'error': quota_reason, 'quota': quota_check, 'run': run}, 403
    dependencies = parse_json_field(row['connector_dependencies_json'], [])
    for dep in dependencies:
        auth, status = authorize_connector_action(identity, dep.get('connector_id'), row['agent_id'], dep.get('action') or 'read')
        if status != 200 or not auth.get('ok'):
            reason = auth.get('error') if isinstance(auth, dict) else 'Connector dependency blocks routine execution.'
            run = record_workflow_routine_run(conn, row, 'blocked', reason, metadata={**metadata, 'connector_dependency': dep}, identity=identity)
            conn.close()
            record_workspace_audit_event(identity, 'workflow_routine.execution_blocked', 'workflow_routine', rid, {'reason': reason, 'policy': 'connector', 'dependency': dep})
            return {'ok': False, 'status': 'blocked', 'error': reason, 'run': run}, status
        if auth.get('approval_required'):
            decision = {'ok': True, 'decision': 'approval_required', 'matched_level': 'connector', 'reason': f"Routine connector dependency {dep.get('connector_id')} requires approval."}
            context = {'action': 'routine_execute', 'agent_id': row['agent_id'], 'connector_id': dep.get('connector_id'), 'resource_type': 'workflow_routine', 'resource_id': rid, 'browser_evidence': metadata.get('browser_evidence')}
            request = create_approval_policy_request(identity, context, decision)
            run = record_workflow_routine_run(conn, row, 'paused', decision['reason'], approval_request_id=request.get('id'), metadata={**metadata, 'approval_policy': decision}, identity=identity)
            conn.close()
            record_workspace_audit_event(identity, 'workflow_routine.execution_paused', 'workflow_routine', rid, {'approval_id': request.get('id'), 'policy': 'connector'})
            return {'ok': True, 'status': 'paused', 'approval_required': True, 'approval_request': request, 'run': run}, 202
    approval_policy = parse_json_field(row['approval_policy_json'], {})
    decision = evaluate_approval_policy(identity, {'action': 'routine_execute', 'agent_id': row['agent_id'], 'resource_type': 'workflow_routine', 'resource_id': rid, 'action_policy': approval_policy, 'browser_evidence': metadata.get('browser_evidence')})
    if decision.get('decision') == 'denied':
        run = record_workflow_routine_run(conn, row, 'blocked', decision.get('reason'), metadata={**metadata, 'approval_policy': decision}, identity=identity)
        conn.close()
        record_workspace_audit_event(identity, 'workflow_routine.execution_blocked', 'workflow_routine', rid, {'reason': decision.get('reason'), 'policy': 'approval'})
        return {'ok': False, 'status': 'blocked', 'error': decision.get('reason'), 'run': run}, 403
    if decision.get('decision') == 'approval_required':
        request = create_approval_policy_request(identity, {'action': 'routine_execute', 'agent_id': row['agent_id'], 'resource_type': 'workflow_routine', 'resource_id': rid, 'browser_evidence': metadata.get('browser_evidence')}, decision)
        run = record_workflow_routine_run(conn, row, 'paused', decision.get('reason'), approval_request_id=request.get('id'), metadata={**metadata, 'approval_policy': decision}, identity=identity)
        conn.close()
        record_workspace_audit_event(identity, 'workflow_routine.execution_paused', 'workflow_routine', rid, {'approval_id': request.get('id'), 'policy': 'approval'})
        return {'ok': True, 'status': 'paused', 'approval_required': True, 'approval_request': request, 'run': run}, 202
    run = record_workflow_routine_run(conn, row, 'executed', 'Routine execution passed connector, approval, and quota policy gates.', metadata=metadata, identity=identity)
    conn.close()
    record_workspace_audit_event(identity, 'workflow_routine.executed', 'workflow_routine', rid, {'run_id': run.get('id'), 'routine_type': row['routine_type'], 'quota_impact': parse_json_field(row['quota_impact_json'], {})})
    return {'ok': True, 'status': 'executed', 'run': run}, 200


def connector_governance_summary(identity):
    data = list_governed_connectors(identity)
    return {
        **data.get('summary', {}),
        'policy_dimensions': ['allowed_agent_classes', 'allowed_users', 'allowed_roles', 'allowed_actions', 'approval_required_for', 'quotas'],
        'company_transaction_domains': WORKSPACE_TRANSACTION_DOMAINS,
    }


def external_runtime_to_record(row):
    last_seen = row['last_seen_at'] or row['updated_at']
    capabilities = parse_json_field(row['capabilities_json'], {})
    evidence = parse_json_field(row['evidence_json'], {})
    now = time.time()
    stale = (now - float(last_seen or 0)) > 180
    status = row['status'] or 'degraded'
    if stale:
        status = 'offline'
    elif status not in ('online', 'degraded', 'offline'):
        status = 'degraded'
    actions = ['heartbeat', 'send_event', 'revoke_connector']
    native_console_url = row['native_console_url'] or (evidence.get('native_console_url') if isinstance(evidence, dict) else None)
    remote_gateway_url = row['remote_gateway_url'] or row['endpoint'] or (evidence.get('remote_gateway_url') if isinstance(evidence, dict) else None)
    dashboard_auth_mode = normalize_dashboard_auth_mode(row['dashboard_auth_mode'] or (evidence.get('dashboard_auth_mode') if isinstance(evidence, dict) else None) or 'unknown')
    hermes_release_date = evidence.get('hermes_release_date') if isinstance(evidence, dict) else None
    console_mode_policy = evidence.get('console_mode_policy') if isinstance(evidence, dict) else None
    capability_flags = runtime_capability_flags(capabilities)
    if native_console_url:
        actions.append('open_native_console')
    if isinstance(capabilities, dict) and capabilities.get('controllable') is True:
        actions.append('route_task_with_approval')
    return {
        'id': f"remote-{row['id']}",
        'name': row['name'],
        'type': f"remote_{row['framework']}",
        'status': status,
        'summary': f"Remote {row['framework']} runtime connected via Runtime Connector V2. Last heartbeat {rel_time(last_seen)}.",
        'readiness': {'representable': True, 'monitorable': bool(last_seen), 'controllable': bool(isinstance(capabilities, dict) and capabilities.get('controllable') is True)},
        'native_console_url': native_console_url,
        'remote_gateway_url': remote_gateway_url,
        'dashboard_auth_mode': dashboard_auth_mode,
        'hermes_version': row['version'] or 'unknown',
        'hermes_release_date': hermes_release_date,
        'profile_id': row['profile_id'] or (evidence.get('profile_id') if isinstance(evidence, dict) else None),
        'profile_name': row['profile_name'] or (evidence.get('profile_name') if isinstance(evidence, dict) else None),
        'console_mode_policy': console_mode_policy,
        'capabilities': capability_flags,
        'capability_flags': capability_flags,
        'adapter': {'name': 'HermesRuntimeAdapter', 'version': 'v0.16-compat', 'capabilities': capability_flags},
        'evidence': {**(evidence if isinstance(evidence, dict) else {}), 'connector': 'runtime-connector-v2', 'runtime_id': row['runtime_id'], 'framework': row['framework'], 'version': row['version'] or 'unknown', 'owner': row['owner'] or 'external', 'endpoint_present': bool(row['endpoint']), 'last_seen_at': utc_iso(last_seen) if last_seen else None, 'capabilities': capabilities if isinstance(capabilities, dict) else {}},
        'safe_actions': actions,
        'updated_at': datetime.fromtimestamp(row['updated_at'], SGT).strftime('%Y-%m-%d %H:%M:%S SGT'),
    }


def connected_runtime_records(query=None):
    conn = runtime_connector_db()
    rows = conn.execute('SELECT * FROM external_runtimes ORDER BY updated_at DESC').fetchall()
    conn.close()
    records = [external_runtime_to_record(r) for r in rows]
    q = (query or '').strip().lower()
    if q:
        records = [r for r in records if q in ' '.join([r.get('id',''), r.get('name',''), r.get('type',''), r.get('status',''), r.get('summary','')]).lower()]
    return records


def list_runtime_connectors(headers=None):
    conn = runtime_connector_db()
    tokens = []
    for row in conn.execute('SELECT * FROM runtime_tokens ORDER BY created_at DESC').fetchall():
        tokens.append({'id': row['id'], 'label': row['label'], 'allowed_types': [x for x in (row['allowed_types'] or '').split(',') if x], 'status': 'revoked' if row['revoked_at'] else row['status'], 'created_at': datetime.fromtimestamp(row['created_at'], SGT).strftime('%Y-%m-%d %H:%M:%S SGT'), 'last_used_at': datetime.fromtimestamp(row['last_used_at'], SGT).strftime('%Y-%m-%d %H:%M:%S SGT') if row['last_used_at'] else None, 'expires_at': datetime.fromtimestamp(row['expires_at'], SGT).strftime('%Y-%m-%d %H:%M:%S SGT') if row['expires_at'] else None})
    runtimes = [external_runtime_to_record(r) for r in conn.execute('SELECT * FROM external_runtimes ORDER BY updated_at DESC').fetchall()]
    events = []
    for row in conn.execute('SELECT * FROM runtime_events ORDER BY created_at DESC LIMIT 40').fetchall():
        events.append({'id': row['id'], 'external_runtime_id': row['external_runtime_id'], 'kind': row['kind'], 'severity': row['severity'], 'title': row['title'], 'body': row['body'] or '', 'payload': parse_json_field(row['payload_json'], {}), 'created_at': datetime.fromtimestamp(row['created_at'], SGT).strftime('%Y-%m-%d %H:%M:%S SGT')})
    conn.close()
    origin = connector_public_origin(headers)
    identity = current_identity_from_cookie(headers.get('Cookie', '')) if headers else None
    curl_example = "curl -H Authorization:[REDACTED] -H Content-Type:application/json -d [REDACTED] " + f'{origin}/api/runtime-connect/register'
    return {'tokens': tokens, 'runtimes': runtimes, 'events': events, 'connect': {'register_url': f'{origin}/api/runtime-connect/register', 'heartbeat_url': f'{origin}/api/runtime-connect/heartbeat', 'events_url': f'{origin}/api/runtime-connect/events', 'curl_example': curl_example}, 'governance': connector_governance_summary(identity), 'summary': {'tokens': len(tokens), 'active_tokens': sum(1 for t in tokens if t['status'] == 'active'), 'connected': len(runtimes), 'online': sum(1 for r in runtimes if r['status'] == 'online')}}

def create_runtime_connector_token(payload, headers=None):
    label = str((payload or {}).get('label') or 'External runtime connector').strip()[:100]
    allowed = payload.get('allowed_types') if isinstance(payload, dict) else None
    if isinstance(allowed, list):
        allowed_types = ','.join(safe_id(str(x)).lower() for x in allowed if str(x).strip()) or 'custom'
    else:
        allowed_types = 'openclaw,nanoclaw,nemoclaw,codex,claude-code,custom'
    token_id = f'rtok-{secrets.token_hex(5)}'
    secret = 'hmc_rt_' + secrets.token_urlsafe(32)
    now = time.time()
    conn = runtime_connector_db()
    conn.execute('INSERT INTO runtime_tokens (id,label,allowed_types,token_hash,status,created_at) VALUES (?,?,?,?,?,?)', (token_id, label, allowed_types, hash_runtime_token(secret), 'active', now))
    conn.commit(); conn.close()
    origin = connector_public_origin(headers)
    return {'ok': True, 'token': {'id': token_id, 'label': label, 'allowed_types': allowed_types.split(','), 'status': 'active', 'created_at': datetime.fromtimestamp(now, SGT).strftime('%Y-%m-%d %H:%M:%S SGT')}, 'secret': secret, 'connect': {'register_url': f'{origin}/api/runtime-connect/register', 'heartbeat_url': f'{origin}/api/runtime-connect/heartbeat', 'events_url': f'{origin}/api/runtime-connect/events'}, 'warning': 'Copy this connector token now. Mission Control stores only its hash and cannot show it again.'}, 201


def revoke_runtime_connector_token(token_id):
    tid = safe_id(token_id)
    conn = runtime_connector_db()
    cur = conn.execute('UPDATE runtime_tokens SET status=?, revoked_at=? WHERE id=?', ('revoked', time.time(), tid))
    conn.commit(); conn.close()
    if cur.rowcount:
        return {'ok': True, 'id': tid, 'status': 'revoked'}, 200
    return {'error': 'connector token not found'}, 404


def runtime_connect_register(payload, headers):
    conn, token_row, err, status = validate_runtime_token(headers)
    if err:
        return err, status
    try:
        framework = safe_id(str(payload.get('framework') or payload.get('type') or 'custom')).lower() or 'custom'
        allowed = {x for x in (token_row['allowed_types'] or '').split(',') if x}
        if allowed and framework not in allowed and 'custom' not in allowed:
            return {'error': f'framework {framework} is not allowed for this token'}, 403
        runtime_slug = safe_id(str(payload.get('runtime_id') or payload.get('id') or framework)).lower() or framework
        ext_id = safe_id(f"{framework}-{runtime_slug}-{token_row['id']}").lower()
        name = str(payload.get('name') or f'{framework} runtime').strip()[:120]
        version = str(payload.get('version') or '')[:80]
        owner = str(payload.get('owner') or '')[:120]
        endpoint = str(payload.get('endpoint') or payload.get('remote_gateway_url') or payload.get('remoteGatewayUrl') or '')[:300]
        native_console_url = str(payload.get('native_console_url') or payload.get('nativeConsoleUrl') or '')[:300]
        remote_gateway_url = str(payload.get('remote_gateway_url') or payload.get('remoteGatewayUrl') or endpoint or '')[:300]
        dashboard_auth_mode = normalize_dashboard_auth_mode(payload.get('dashboard_auth_mode') or payload.get('dashboardAuthMode') or 'unknown')
        profile_id = safe_id(payload.get('profile_id') or payload.get('profileId') or '') or None
        profile_name = str(payload.get('profile_name') or payload.get('profileName') or profile_id or '')[:120] or None
        capabilities = payload.get('capabilities') if isinstance(payload.get('capabilities'), dict) else {}
        evidence = payload.get('evidence') if isinstance(payload.get('evidence'), dict) else {}
        hermes_release_date = str(payload.get('hermes_release_date') or payload.get('hermesReleaseDate') or '')[:40]
        console_mode_policy = safe_id(payload.get('console_mode_policy') or payload.get('consoleModePolicy') or '') or None
        if hermes_release_date:
            evidence = {**evidence, 'hermes_release_date': hermes_release_date}
        if console_mode_policy:
            evidence = {**evidence, 'console_mode_policy': console_mode_policy}
        now = time.time()
        conn.execute("""INSERT INTO external_runtimes (id, token_id, runtime_id, name, framework, version, owner, endpoint, status, capabilities_json, evidence_json, last_seen_at, created_at, updated_at, native_console_url, remote_gateway_url, dashboard_auth_mode, profile_id, profile_name)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(id) DO UPDATE SET name=excluded.name, framework=excluded.framework, version=excluded.version, owner=excluded.owner, endpoint=excluded.endpoint, status=excluded.status, capabilities_json=excluded.capabilities_json, evidence_json=excluded.evidence_json, last_seen_at=excluded.last_seen_at, updated_at=excluded.updated_at, native_console_url=excluded.native_console_url, remote_gateway_url=excluded.remote_gateway_url, dashboard_auth_mode=excluded.dashboard_auth_mode, profile_id=excluded.profile_id, profile_name=excluded.profile_name""",
            (ext_id, token_row['id'], runtime_slug, name, framework, version, owner, endpoint, str(payload.get('status') or 'online')[:40], json.dumps(capabilities), json.dumps(evidence), now, now, now, native_console_url, remote_gateway_url, dashboard_auth_mode, profile_id, profile_name))
        conn.execute('INSERT INTO runtime_events (external_runtime_id,kind,severity,title,body,payload_json,created_at) VALUES (?,?,?,?,?,?,?)', (ext_id, 'register', 'info', f'{name} registered', '', json.dumps({'framework': framework, 'runtime_id': runtime_slug}), now))
        conn.commit()
        origin = connector_public_origin(headers)
        return {'ok': True, 'runtime_id': ext_id, 'display_id': f'remote-{ext_id}', 'heartbeat_url': f'{origin}/api/runtime-connect/heartbeat', 'events_url': f'{origin}/api/runtime-connect/events'}, 201
    finally:
        conn.close()


def runtime_connect_heartbeat(payload, headers):
    conn, token_row, err, status = validate_runtime_token(headers)
    if err:
        return err, status
    try:
        ext_id = safe_id(str(payload.get('runtime_id') or payload.get('id') or '')).lower()
        if ext_id.startswith('remote-'):
            ext_id = ext_id[7:]
        row = conn.execute('SELECT * FROM external_runtimes WHERE id=? AND token_id=?', (ext_id, token_row['id'])).fetchone()
        if not row:
            return {'error': 'runtime not registered for this connector token'}, 404
        capabilities = payload.get('capabilities') if isinstance(payload.get('capabilities'), dict) else parse_json_field(row['capabilities_json'], {})
        evidence = payload.get('evidence') if isinstance(payload.get('evidence'), dict) else parse_json_field(row['evidence_json'], {})
        status_value = str(payload.get('status') or 'online')[:40]
        native_console_url = str(payload.get('native_console_url') or payload.get('nativeConsoleUrl') or row['native_console_url'] or '')[:300]
        remote_gateway_url = str(payload.get('remote_gateway_url') or payload.get('remoteGatewayUrl') or row['remote_gateway_url'] or row['endpoint'] or '')[:300]
        dashboard_auth_mode = normalize_dashboard_auth_mode(payload.get('dashboard_auth_mode') or payload.get('dashboardAuthMode') or row['dashboard_auth_mode'] or 'unknown')
        profile_id = safe_id(payload.get('profile_id') or payload.get('profileId') or row['profile_id'] or '') or None
        profile_name = str(payload.get('profile_name') or payload.get('profileName') or row['profile_name'] or profile_id or '')[:120] or None
        hermes_release_date = str(payload.get('hermes_release_date') or payload.get('hermesReleaseDate') or '')[:40]
        console_mode_policy = safe_id(payload.get('console_mode_policy') or payload.get('consoleModePolicy') or '') or None
        if hermes_release_date:
            evidence = {**evidence, 'hermes_release_date': hermes_release_date}
        if console_mode_policy:
            evidence = {**evidence, 'console_mode_policy': console_mode_policy}
        now = time.time()
        conn.execute('UPDATE external_runtimes SET status=?, capabilities_json=?, evidence_json=?, last_seen_at=?, updated_at=?, native_console_url=?, remote_gateway_url=?, dashboard_auth_mode=?, profile_id=?, profile_name=? WHERE id=?', (status_value, json.dumps(capabilities), json.dumps(evidence), now, now, native_console_url, remote_gateway_url, dashboard_auth_mode, profile_id, profile_name, ext_id))
        conn.commit()
        return {'ok': True, 'runtime_id': ext_id, 'status': status_value, 'last_seen_at': utc_iso(now)}, 200
    finally:
        conn.close()


def runtime_connect_event(payload, headers):
    conn, token_row, err, status = validate_runtime_token(headers)
    if err:
        return err, status
    try:
        ext_id = safe_id(str(payload.get('runtime_id') or payload.get('id') or '')).lower()
        if ext_id.startswith('remote-'):
            ext_id = ext_id[7:]
        row = conn.execute('SELECT id FROM external_runtimes WHERE id=? AND token_id=?', (ext_id, token_row['id'])).fetchone()
        if not row:
            return {'error': 'runtime not registered for this connector token'}, 404
        kind = safe_id(str(payload.get('kind') or 'event')).lower()[:40] or 'event'
        severity = safe_id(str(payload.get('severity') or 'info')).lower()[:20] or 'info'
        title = str(payload.get('title') or kind).strip()[:180]
        body = str(payload.get('body') or '')[:2000]
        event_payload = payload.get('payload') if isinstance(payload.get('payload'), dict) else {}
        now = time.time()
        conn.execute('INSERT INTO runtime_events (external_runtime_id,kind,severity,title,body,payload_json,created_at) VALUES (?,?,?,?,?,?,?)', (ext_id, kind, severity, title, body, json.dumps(event_payload), now))
        conn.execute('UPDATE external_runtimes SET updated_at=? WHERE id=?', (now, ext_id))
        conn.commit()
        return {'ok': True, 'runtime_id': ext_id, 'event': {'kind': kind, 'severity': severity, 'title': title, 'created_at': utc_iso(now)}}, 201
    finally:
        conn.close()

def list_runtimes(query=None):
    runtimes = [
        hermes_runtime_adapter(),
        openclaw_runtime_adapter(),
        cli_runtime_adapter('codex', 'Codex CLI / Codex App Projects', 'codex', '~/.codex/auth.json', 'codex', 'codex'),
        cli_runtime_adapter('claude-code', 'Claude Code / Claude Suite Projects', 'claude', '~/.claude', 'claude', 'claude'),
        placeholder_claw_runtime_adapter('nanoclaw', 'NanoClaw'),
        placeholder_claw_runtime_adapter('nemoclaw', 'NemoClaw'),
    ] + connected_runtime_records(query)
    q = (query or '').strip().lower()
    if q:
        runtimes = [r for r in runtimes if q in ' '.join([r.get('id',''), r.get('name',''), r.get('type',''), r.get('status',''), r.get('summary','')]).lower()]
    return {
        'runtimes': runtimes,
        'summary': {
            'total': len(runtimes),
            'online': sum(1 for r in runtimes if r['status'] == 'online'),
            'degraded': sum(1 for r in runtimes if r['status'] == 'degraded'),
            'offline': sum(1 for r in runtimes if r['status'] == 'offline'),
            'monitorable': sum(1 for r in runtimes if r['readiness']['monitorable']),
            'controllable': sum(1 for r in runtimes if r['readiness']['controllable']),
        },
        'updated_at': datetime.now(SGT).strftime('%Y-%m-%d %H:%M:%S SGT'),
    }


def runtime_detail(runtime_id):
    rid = safe_id(runtime_id)
    payload = list_runtimes()
    for runtime in payload['runtimes']:
        if runtime['id'] == rid:
            return {'runtime': runtime}, 200
    return {'error': 'runtime not found'}, 404


def safe_id(s):
    return re.sub(r'[^a-zA-Z0-9_.-]+', '-', (s or '').strip()).strip('-')[:80]


def rel_time(ts):
    if not ts:
        return '—'
    try:
        delta = max(0, time.time() - float(ts))
        if delta < 60:
            return 'just now'
        if delta < 3600:
            return f'{int(delta//60)}m ago'
        if delta < 86400:
            return f'{int(delta//3600)}h ago'
        return f'{int(delta//86400)}d ago'
    except Exception:
        return '—'


def config_kind(name):
    lower = name.lower()
    if lower == 'soul.md':
        return 'soul'
    if lower in ('identity.md', 'user.md'):
        return 'soul'
    if lower == 'memory.md':
        return 'memory'
    if lower == 'agents.md':
        return 'agents'
    if lower in ('claude.md', '.cursorrules'):
        return 'agents'
    if lower == 'config.yaml':
        return 'config'
    return 'other'


def redact_config(text):
    redacted = []
    for line in text.splitlines():
        if re.search(r'(api[_-]?key|token|secret|password|credential)', line, re.I) and ':' in line:
            k = line.split(':', 1)[0]
            redacted.append(f'{k}: <redacted>')
        else:
            redacted.append(line)
    return '\n'.join(redacted) + ('\n' if text.endswith('\n') else '')


def profile_root(profile_id):
    if profile_id in ('default', '', None):
        return HERMES_HOME
    pid = safe_id(profile_id)
    return HERMES_HOME / 'profiles' / pid


def workspace_agent_identity_path(identity, agent_id):
    """Workspace-scoped logical agent identity file.

    Normal Mission Control users select shared agent templates, but their
    custom identity/SOUL must belong to their own workspace profile instead
    of editing the admin-managed shared runtime profile.
    """
    if not identity:
        return None
    aid = safe_id(agent_id) or 'default'
    root = profile_root(workspace_profile_name(identity))
    return root / 'agents' / aid / 'SOUL.md'


def default_workspace_agent_soul(identity, agent_id, agent_name=''):
    workspace = (identity or {}).get('workspace') or {}
    name = agent_name or safe_id(agent_id) or 'Agent'
    return (
        f"# {name} SOUL.md\n\n"
        "This is the workspace-scoped identity file for this logical agent in Mission Control.\n"
        f"- Workspace: {workspace.get('name') or identity_workspace_id(identity) or 'workspace'}\n"
        f"- Agent template: {safe_id(agent_id) or 'default'}\n\n"
        "Edit this file to define the agent's operating identity, voice, boundaries, and role for this workspace.\n"
    )


def read_workspace_agent_soul(identity, agent_id):
    path = workspace_agent_identity_path(identity, agent_id)
    if not path or not path.exists() or not path.is_file():
        return ''
    try:
        return path.read_text(errors='replace')
    except Exception:
        return ''


def write_workspace_agent_soul(identity, agent_id, content):
    path = workspace_agent_identity_path(identity, agent_id)
    if not path:
        return {'ok': False, 'error': 'workspace identity required'}, 401
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(str(content or ''), encoding='utf-8')
    try:
        path.chmod(0o600)
    except Exception:
        pass
    return {'ok': True, 'path': str(path)}, 200


def state_db_for_profile(profile_id='default'):
    """Return the state database for a Hermes profile.

    Mission Control's Agent Chat roster can include isolated Hermes profiles
    (for example the DevOps/Andrej profile). Each profile has its own
    HERMES_HOME and state.db, so chat history/status must not always read the
    default profile's database.
    """
    return profile_root(profile_id) / 'state.db'


def read_config_files(profile_id='default', identity=None, agent_id=None, agent_name=''):
    root = profile_root(profile_id)
    candidates = [
        root / 'SOUL.md', root / 'IDENTITY.md', root / 'identity.md', root / 'USER.md', root / 'MEMORY.md', root / 'AGENTS.md',
        root / 'CLAUDE.md', root / '.cursorrules', root / 'config.yaml'
    ]
    files = []
    workspace_soul_path = workspace_agent_identity_path(identity, agent_id) if identity and agent_id else None
    if workspace_soul_path:
        if workspace_soul_path.exists():
            try:
                content = workspace_soul_path.read_text(errors='replace')
                st = workspace_soul_path.stat()
                size = st.st_size
                updated = rel_time(st.st_mtime)
            except Exception:
                content = default_workspace_agent_soul(identity, agent_id, agent_name)
                size = len(content.encode('utf-8'))
                updated = 'draft'
        else:
            content = default_workspace_agent_soul(identity, agent_id, agent_name)
            size = len(content.encode('utf-8'))
            updated = 'not saved'
        files.append({
            'name': 'SOUL.md',
            'label': 'workspace agent identity',
            'kind': 'soul',
            'content': content,
            'sizeBytes': size,
            'updatedAt': updated,
            'scope': 'workspace-agent',
            'editable': True,
        })

    for path in candidates:
        if workspace_soul_path and path.name == 'SOUL.md':
            continue
        if not path.exists() or not path.is_file():
            continue
        try:
            content = path.read_text(errors='replace')
        except Exception:
            continue
        if path.name == 'config.yaml':
            content = redact_config(content)
        st = path.stat()
        labels = {
            'SOUL.md': 'agent identity',
            'IDENTITY.md': 'agent identity',
            'identity.md': 'agent identity',
            'USER.md': 'user profile',
            'MEMORY.md': 'persistent memory',
            'AGENTS.md': 'agent/project rules',
            'CLAUDE.md': 'coding agent rules',
            '.cursorrules': 'editor agent rules',
            'config.yaml': 'runtime config',
        }
        files.append({
            'name': path.name,
            'label': labels.get(path.name, 'profile file'),
            'kind': config_kind(path.name),
            'content': content,
            'sizeBytes': st.st_size,
            'updatedAt': rel_time(st.st_mtime),
            'scope': 'profile',
            'editable': path.name in {'SOUL.md', 'IDENTITY.md', 'identity.md', 'USER.md', 'MEMORY.md', 'AGENTS.md', 'CLAUDE.md'} and not workspace_soul_path,
        })
    if not files:
        files.append({'name':'config.yaml','label':'runtime config','kind':'config','content':'# No readable config files found for this profile.\n','sizeBytes':0,'updatedAt':'—'})
    return files


def list_skills(profile_id='default', limit=None, platform=''):
    # Agent details should show the same enabled skill set Hermes would load for
    # this profile/channel: frontmatter names, category buckets, platform
    # overrides, disabled skills, platform compatibility, and external dirs.
    rows = iter_skill_rows(profile_id, platform=platform, include_disabled=False)
    slim = [
        {
            'id': row['id'],
            'name': row['name'],
            'category': row['category'],
            'source': row['source'],
        }
        for row in rows
    ]
    return slim[:limit] if limit else slim


def parse_frontmatter(text):
    meta = {}
    if not text.startswith('---'):
        return meta
    end = text.find('\n---', 3)
    if end == -1:
        return meta
    block = text[3:end].strip()
    for raw in block.splitlines():
        line = raw.strip()
        if not line or ':' not in line or line.startswith('-'):
            continue
        key, value = line.split(':', 1)
        value = value.strip().strip('\"\'')
        if value.startswith('[') and value.endswith(']'):
            value = [x.strip().strip('\"\'') for x in value[1:-1].split(',') if x.strip()]
        meta[key.strip()] = value
    return meta


def load_profile_config(profile_id='default'):
    path = profile_root(profile_id) / 'config.yaml'
    if not path.exists() and profile_id != 'default':
        path = HERMES_HOME / 'config.yaml'
    if not path.exists():
        return {}
    try:
        import yaml
        data = yaml.safe_load(path.read_text(errors='ignore'))
        return data if isinstance(data, dict) else {}
    except Exception:
        # Minimal fallback parser for the skills.disabled / platform_disabled
        # settings used by Hermes skill routing. It intentionally avoids trying
        # to parse the whole config if PyYAML is unavailable.
        cfg = {'skills': {}}
        current_platform = None
        in_skills = False
        in_platform_disabled = False
        for raw in path.read_text(errors='ignore').splitlines():
            stripped = raw.strip()
            if not stripped or stripped.startswith('#'):
                continue
            indent = len(raw) - len(raw.lstrip(' '))
            if indent == 0:
                in_skills = stripped == 'skills:'
                in_platform_disabled = False
                current_platform = None
                continue
            if not in_skills:
                continue
            if indent == 2 and stripped.startswith('disabled:'):
                cfg['skills']['disabled'] = parse_inline_list(stripped.split(':', 1)[1])
            elif indent == 2 and stripped == 'platform_disabled:':
                in_platform_disabled = True
                cfg['skills'].setdefault('platform_disabled', {})
            elif in_platform_disabled and indent == 4 and ':' in stripped:
                key, value = stripped.split(':', 1)
                current_platform = key.strip()
                cfg['skills']['platform_disabled'][current_platform] = parse_inline_list(value)
            elif in_platform_disabled and current_platform and indent >= 6 and stripped.startswith('- '):
                cfg['skills']['platform_disabled'].setdefault(current_platform, []).append(stripped[2:].strip().strip('"\''))
        return cfg


def parse_inline_list(value):
    value = (value or '').strip()
    if not value:
        return []
    if value.startswith('[') and value.endswith(']'):
        return [x.strip().strip('"\'') for x in value[1:-1].split(',') if x.strip()]
    return [value.strip('"\'')]


