def load_toolset_definitions():
    global _TOOLSET_CACHE
    if _TOOLSET_CACHE is not None:
        return _TOOLSET_CACHE
    for candidate in [HOME / 'hermes-agent' / 'toolsets.py', HERMES_HOME / 'hermes-agent' / 'toolsets.py']:
        if not candidate.exists():
            continue
        try:
            spec = importlib.util.spec_from_file_location('hmc_hermes_toolsets', candidate)
            module = importlib.util.module_from_spec(spec)
            spec.loader.exec_module(module)
            _TOOLSET_CACHE = getattr(module, 'TOOLSETS', {}) or {}
            return _TOOLSET_CACHE
        except Exception:
            continue
    _TOOLSET_CACHE = {}
    return _TOOLSET_CACHE


def resolve_toolset_tools(toolset_id, seen=None):
    seen = seen or set()
    if toolset_id in seen:
        return []
    seen.add(toolset_id)
    defs = load_toolset_definitions()
    spec = defs.get(toolset_id) if isinstance(defs, dict) else None
    if not isinstance(spec, dict):
        return []
    tools = list(spec.get('tools') or [])
    for inc in spec.get('includes') or []:
        tools.extend(resolve_toolset_tools(str(inc), seen))
    deduped = []
    for tool in tools:
        t = str(tool)
        if t and t not in deduped:
            deduped.append(t)
    return deduped


def tool_categories(tool_names):
    out = []
    names = [str(x) for x in tool_names if str(x).strip()]
    for cid, label, prefixes in _TOOL_CATEGORY_RULES:
        count = sum(1 for name in names if any(name == p or name.startswith(p) for p in prefixes))
        if count:
            out.append({'id': cid, 'name': label, 'count': count})
    return out


def tool_category(tool_name):
    name = str(tool_name or '')
    for cid, label, prefixes in _TOOL_CATEGORY_RULES:
        if any(name == p or name.startswith(p) for p in prefixes):
            return {'id': cid, 'name': label, 'count': 1}
    return {'id': 'other', 'name': 'Other', 'count': 1}


def human_tool_name(tool_name):
    raw = str(tool_name or '').strip()
    if not raw:
        return 'Unnamed tool'
    parts = raw.replace('-', '_').split('_')
    acronyms = {'api', 'url', 'tts', 'cdp'}
    return ' '.join((p.upper() if p in acronyms else p.capitalize()) for p in parts if p)


def tool_description(tool_name, parent_label='Hermes toolset'):
    raw = str(tool_name or '').strip()
    return _TOOL_DESCRIPTIONS.get(raw) or f'Executable Hermes CLI function from {parent_label}.'


def individual_tool_capabilities(toolset_id, tools, parent_label, source='config.yaml'):
    records = []
    for raw_tool in tools:
        name = str(raw_tool).strip()
        if not name:
            continue
        cat = tool_category(name)
        records.append({
            'id': f'tool:{name}',
            'name': human_tool_name(name),
            'kind': 'tool',
            'source': source,
            'enabled': True,
            'description': tool_description(name, parent_label),
            'toolCount': 1,
            'sampleTools': [name],
            'categories': [cat],
            'toolName': name,
            'parentToolsetId': toolset_id,
            'parentToolsetName': parent_label,
            'assignmentUnit': name,
        })
    return records


def agent_tool_capabilities(profile_id='default'):
    resolved_profile = 'default' if profile_id in ('terminal', 'telegram', 'dashboard', 'api', 'cli') else profile_id
    cfg = load_profile_config(resolved_profile)
    configured = cfg.get('toolsets') if isinstance(cfg.get('toolsets'), list) else []
    platform = skill_platform_for_agent(profile_id)
    if not configured:
        configured = ['hermes-api-server' if platform == 'api_server' else 'hermes-telegram' if platform == 'telegram' else 'hermes-cli']
    capabilities = []
    for raw in configured:
        tid = str(raw).strip()
        if not tid:
            continue
        tools = resolve_toolset_tools(tid)
        spec = load_toolset_definitions().get(tid, {}) if isinstance(load_toolset_definitions(), dict) else {}
        label = _TOOLSET_LABELS.get(tid) or tid.replace('-', ' ').replace('_', ' ').title()
        capabilities.append({
            'id': tid,
            'name': label,
            'kind': 'toolset',
            'source': 'config.yaml',
            'enabled': True,
            'description': str(spec.get('description') or 'Enabled Hermes toolset')[:220] if isinstance(spec, dict) else 'Enabled Hermes toolset',
            'toolCount': len(tools) if tools else None,
            'sampleTools': tools[:8],
            'categories': tool_categories(tools),
            'toolNames': tools,
            'assignmentUnit': tid,
        })
        capabilities.extend(individual_tool_capabilities(tid, tools, label))
    platforms = cfg.get('platforms') if isinstance(cfg.get('platforms'), dict) else {}
    for platform_id, pdata in platforms.items():
        if isinstance(pdata, dict) and pdata.get('enabled') is True:
            capabilities.append({
                'id': f'platform:{platform_id}',
                'name': f'{str(platform_id).replace("_", " ").title()} channel',
                'kind': 'platform',
                'source': 'config.yaml',
                'enabled': True,
                'description': 'Enabled Hermes gateway/API channel for this profile.',
                'toolCount': None,
                'sampleTools': [],
                'categories': [],
            })
    try:
        capabilities.extend(installed_tool_records())
    except Exception:
        pass
    if not capabilities:
        capabilities.append({'id': 'unknown', 'name': 'No enabled toolsets found', 'kind': 'toolset', 'source': 'config.yaml', 'enabled': False, 'description': 'Mission Control could not find toolset configuration for this profile.', 'toolCount': None, 'sampleTools': [], 'categories': []})
    return capabilities


def tools_hub_payload(identity=None):
    """Aggregate executable tool capabilities for the Tools Hub without loading chat transcripts."""
    shared_status = agent_list_status_payload()
    if identity and not is_admin_identity(identity):
        directory = list_agent_directory(identity)
        agent_refs = []
        for row in directory.get('agents', []):
            if not isinstance(row, dict):
                continue
            shared_ref = safe_id(row.get('shared_agent_ref') or row.get('id') or 'default') or 'default'
            agent_refs.append((shared_ref, row.get('name') or shared_ref))
    else:
        agent_refs = [(profile_id, '') for profile_id in agent_roster_profile_ids(include_default=True)]
    by_id = {}
    for profile_id, display_name in agent_refs:
        summary = agent_summary_payload(profile_id, st=shared_status)
        if display_name:
            summary['name'] = display_name
        for tool in agent_tool_capabilities(profile_id):
            tid = tool.get('id') or tool.get('name')
            if not tid:
                continue
            existing = by_id.get(tid)
            if existing:
                existing.setdefault('agents', []).append(summary)
                if tool.get('enabled') is not False:
                    existing['enabledAgents'] = int(existing.get('enabledAgents') or 0) + 1
                continue
            item = dict(tool)
            item['id'] = tid
            item['agents'] = [summary]
            item['enabledAgents'] = 0 if tool.get('enabled') is False else 1
            by_id[tid] = item
    tools = sorted(by_id.values(), key=lambda item: str(item.get('name') or item.get('id') or '').lower())
    return {'tools': tools, 'summary': {'total': len(tools), 'agents': len(agent_refs)}}


def skill_platform_for_agent(profile_id):
    if profile_id in ('terminal', 'cli'):
        return 'cli'
    if profile_id in ('telegram', 'telegram-bot'):
        return 'telegram'
    if profile_id in ('dashboard', 'api'):
        return 'api_server'
    return ''


def disabled_skill_names(profile_id='default', platform=''):
    cfg = load_profile_config(profile_id)
    skills_cfg = cfg.get('skills') if isinstance(cfg.get('skills'), dict) else {}
    if platform:
        platform_disabled = skills_cfg.get('platform_disabled')
        if isinstance(platform_disabled, dict) and platform in platform_disabled:
            value = platform_disabled.get(platform) or []
            return {str(x) for x in value if str(x).strip()}
    value = skills_cfg.get('disabled') or []
    return {str(x) for x in value if str(x).strip()}


def skill_matches_runtime_platform(meta):
    platforms = meta.get('platforms')
    if not platforms:
        return True
    if isinstance(platforms, str):
        platforms = parse_inline_list(platforms) if platforms.startswith('[') else [platforms]
    platform_set = {str(x).strip().lower() for x in platforms if str(x).strip()}
    if not platform_set:
        return True
    linux_names = {'linux'}
    return bool(platform_set & linux_names)


def _norm_path(path):
    try:
        return Path(path).resolve()
    except Exception:
        return Path(path)


def _path_within(path, root):
    try:
        _norm_path(path).relative_to(_norm_path(root))
        return True
    except Exception:
        return False


def _append_skill_root(roots, seen, path, source):
    try:
        path = _norm_path(Path(path))
    except Exception:
        return
    if not path.exists() or not path.is_dir():
        return
    if path in seen:
        return
    seen.add(path)
    roots.append((path, source))


def openclaw_skill_scan_roots():
    """Return curated OpenClaw skill roots for inventory display.

    The Skills Hub should display OpenClaw skills, but it must not blindly mount
    all of ~/.openclaw as a Hermes skill source. We include stable workspace and
    extension skill roots, and skip package internals such as node_modules plus
    tmp/scratch clones unless they are explicitly copied into shared-skills.
    """
    roots = []
    seen = set()
    workspace = OPENCLAW_HOME / 'workspace'
    _append_skill_root(roots, seen, workspace / 'shared-skills', 'Shared')
    _append_skill_root(roots, seen, workspace / 'skills', 'OpenClaw')

    # Workspace-local standalone skills, e.g. workspace/options-flow-tracker/SKILL.md.
    if workspace.exists():
        for child in sorted(workspace.iterdir()):
            if not child.is_dir():
                continue
            if child.name.startswith('tmp-') or child.name in {'node_modules', '.git'}:
                continue
            if (child / 'SKILL.md').exists():
                source = 'Shared' if child.parent.name == 'shared-skills' or 'shared-skills' in child.parts else 'OpenClaw'
                _append_skill_root(roots, seen, child, source)

    # Named OpenClaw workspaces such as workspace-webdev/skills and workspace-kronos/skills.
    if OPENCLAW_HOME.exists():
        for child in sorted(OPENCLAW_HOME.iterdir()):
            if not child.is_dir() or not child.name.startswith('workspace-'):
                continue
            if child.name.startswith('workspace-tmp') or child.name.startswith('workspace/tmp'):
                continue
            _append_skill_root(roots, seen, child / 'shared-skills', 'Shared')
            _append_skill_root(roots, seen, child / 'skills', 'OpenClaw')

    # OpenClaw extension-provided skills are OpenClaw-only runtime resources.
    deps = OPENCLAW_HOME / 'plugin-runtime-deps'
    if deps.exists():
        for md in sorted(deps.glob('*/dist/extensions/*/skills/*/SKILL.md')):
            if any(part in {'node_modules', '.git', '__pycache__'} for part in md.parts):
                continue
            _append_skill_root(roots, seen, md.parent, 'OpenClaw')

    return roots


def skill_scan_roots(profile_id='default'):
    root = profile_root(profile_id)
    roots = []
    seen = set()
    skills_dir = root / 'skills'
    if skills_dir.exists():
        _append_skill_root(roots, seen, skills_dir, 'Hermes')
    elif profile_id != 'default' and (HERMES_HOME / 'skills').exists():
        _append_skill_root(roots, seen, HERMES_HOME / 'skills', 'Hermes')
    elif (HERMES_HOME / 'skills').exists():
        _append_skill_root(roots, seen, HERMES_HOME / 'skills', 'Hermes')

    cfg = load_profile_config(profile_id)
    external = ((cfg.get('skills') or {}).get('external_dirs') or []) if isinstance(cfg.get('skills'), dict) else []
    if isinstance(external, str):
        external = [external]
    for item in external:
        try:
            path = Path(os.path.expanduser(os.path.expandvars(str(item))))
            if path.exists():
                source = 'Shared' if 'shared-skills' in path.parts or _path_within(path, OPENCLAW_HOME / 'workspace' / 'shared-skills') else 'Shared'
                _append_skill_root(roots, seen, path, source)
        except Exception:
            continue

    # Skills Hub is an inventory surface, so include OpenClaw-owned skills too.
    # Hermes runtime loading remains controlled by Hermes config external_dirs.
    if profile_id == 'default':
        for path, source in openclaw_skill_scan_roots():
            _append_skill_root(roots, seen, path, source)
    return roots


def iter_skill_rows(profile_id='default', *, platform='', include_disabled=False):
    disabled = disabled_skill_names(profile_id, platform) if not include_disabled else set()
    rows = []
    seen_ids = set()
    for skills_dir, source in skill_scan_roots(profile_id):
        for md in sorted(skills_dir.glob('**/SKILL.md')):
            if any(part in {'.trash', '.hub', '__pycache__', 'node_modules', '.git'} for part in md.parts):
                continue
            if any(str(part).startswith('tmp-') for part in md.parts) and source != 'Shared':
                continue
            try:
                text = md.read_text(errors='replace')
                st = md.stat()
                rel = md.parent.relative_to(skills_dir)
            except Exception:
                continue
            meta = parse_frontmatter(text)
            if not skill_matches_runtime_platform(meta):
                continue
            name = str(meta.get('name') or md.parent.name)[:64]
            if name in disabled:
                continue
            rel_id = str(rel) if str(rel) != '.' else md.parent.name
            if source != 'Hermes':
                rel_id = f"{source.lower()}:{str(md.parent.relative_to(OPENCLAW_HOME)) if _path_within(md.parent, OPENCLAW_HOME) else rel_id}"
            if rel_id in seen_ids:
                suffix = hashlib.sha1(str(md.parent).encode('utf-8')).hexdigest()[:8]
                rel_id = f"{rel_id}:{suffix}"
            seen_ids.add(rel_id)
            category = str(rel.parent) if str(rel.parent) != '.' else ('uncategorized' if source == 'Hermes' else source)
            tags = meta.get('tags') or []
            if isinstance(tags, str):
                tags = [x.strip() for x in re.split(r'[, ]+', tags) if x.strip()]
            related = meta.get('related_skills') or []
            if isinstance(related, str):
                related = [x.strip() for x in related.split(',') if x.strip()]
            rows.append({
                'id': rel_id,
                'name': name,
                'category': category,
                'description': skill_description(text, meta),
                'source': source,
                'editable': str(md).startswith(str(HERMES_HOME / 'skills')) or str(md).startswith(str(profile_root(profile_id) / 'skills')),
                'path': str(md),
                'skill_dir': str(md.parent),
                'profile': profile_id,
                'version': str(meta.get('version') or '—'),
                'author': str(meta.get('author') or '—'),
                'tags': tags[:12],
                'related_skills': related[:12],
                'updated_at': iso(st.st_mtime),
                'readiness': 'available',
                'model': str(meta.get('model') or meta.get('provider') or 'default'),
                'preview': preview_content(text, 1400),
            })
    return sorted(rows, key=lambda s: ((s.get('category') or ''), s.get('name') or ''))


def skill_description(text, meta):
    if meta.get('description'):
        return str(meta.get('description'))
    body = text
    if text.startswith('---'):
        end = text.find('\n---', 3)
        if end != -1:
            body = text[end + 4:]
    for raw in body.splitlines():
        line = raw.strip()
        if line and not line.startswith('#') and not line.startswith('---'):
            return trim(line, 240)
    return 'Reusable Hermes operating procedure.'


def read_skill_records_for_profile(profile_id='default'):
    return iter_skill_rows(profile_id, include_disabled=True)


def profile_labels_for_skill(skill_id):
    labels = []
    channel_labels = ['Terminal Chat', 'Telegram Bot Chat', 'Dashboard Chat']
    default_ids = {s['id'] for s in read_skill_records_for_profile('default')}
    if skill_id in default_ids:
        labels.extend(channel_labels)
    profiles = HERMES_HOME / 'profiles'
    if profiles.exists():
        for d in sorted([x for x in profiles.iterdir() if x.is_dir()]):
            if any(s['id'] == skill_id for s in read_skill_records_for_profile(d.name)):
                labels.append(d.name)
    return labels


def automation_skill_usage():
    usage = {}
    if not CRON_JOBS.exists():
        return usage
    try:
        jobs = json.loads(CRON_JOBS.read_text(errors='ignore')).get('jobs', [])
    except Exception:
        return usage
    for j in jobs:
        skills = j.get('skills') or ([] if not j.get('skill') else [j.get('skill')])
        for sid in skills:
            usage.setdefault(str(sid), []).append(j.get('name') or j.get('id') or str(sid))
    return usage


def task_skill_usage():
    usage = {}
    if not KANBAN_DB.exists():
        return usage
    try:
        con = sqlite3.connect(f'file:{KANBAN_DB}?mode=ro', uri=True, timeout=2)
        con.row_factory = sqlite3.Row
        rows = con.execute('SELECT id, title, skills FROM tasks WHERE skills IS NOT NULL AND trim(skills) != "" ORDER BY created_at DESC LIMIT 300').fetchall()
        con.close()
    except Exception:
        return usage
    for r in rows:
        try:
            skills = json.loads(r['skills'])
        except Exception:
            skills = []
        if not isinstance(skills, list):
            continue
        for sid in skills:
            usage.setdefault(str(sid), []).append(r['title'] or r['id'])
    return usage


_PLUGIN_HUB_CACHE = {'at': 0, 'payload': None}


def _plugin_category(name):
    name = str(name or '').strip()
    if '/' in name:
        return name.split('/', 1)[0] or 'general'
    if '-' in name:
        return name.split('-', 1)[0] or 'general'
    return 'general'


def _plugin_record(row):
    name = str(row.get('name') or '').strip()
    status = str(row.get('status') or '').strip() or 'unknown'
    enabled = status.lower() in ('enabled', 'active', 'loaded')
    return {
        'id': name or safe_id(row.get('description') or 'plugin'),
        'name': name or 'unnamed-plugin',
        'category': _plugin_category(name),
        'status': status,
        'enabled': enabled,
        'version': str(row.get('version') or '—'),
        'description': str(row.get('description') or '').strip(),
        'source': str(row.get('source') or 'bundled').strip() or 'bundled',
    }


def _base_plugin_hub_payload():
    cli = os.environ.get('HERMES_CLI') or shutil.which('hermes') or '/root/hermes-agent/venv/bin/hermes'
    try:
        proc = subprocess.run([cli, 'plugins', 'list', '--json'], capture_output=True, text=True, timeout=20, env=os.environ.copy())
    except Exception as exc:
        return {'plugins': [], 'summary': {'total': 0, 'enabled': 0, 'disabled': 0, 'bundled': 0, 'user': 0, 'categories': 0}, 'categories': [], 'sources': [], 'statuses': [], 'error': f'unable to run hermes plugins list: {exc}'}
    if proc.returncode != 0:
        err = (proc.stderr or proc.stdout or 'hermes plugins list failed').strip()[:500]
        return {'plugins': [], 'summary': {'total': 0, 'enabled': 0, 'disabled': 0, 'bundled': 0, 'user': 0, 'categories': 0}, 'categories': [], 'sources': [], 'statuses': [], 'error': err}
    try:
        raw = json.loads(proc.stdout or '[]')
    except Exception as exc:
        return {'plugins': [], 'summary': {'total': 0, 'enabled': 0, 'disabled': 0, 'bundled': 0, 'user': 0, 'categories': 0}, 'categories': [], 'sources': [], 'statuses': [], 'error': f'unable to parse plugin inventory: {exc}'}
    plugins = [_plugin_record(row) for row in raw if isinstance(row, dict)]
    plugins.sort(key=lambda p: (p['category'], p['name']))
    categories = sorted({p['category'] for p in plugins})
    sources = sorted({p['source'] for p in plugins})
    statuses = sorted({p['status'] for p in plugins})
    return {
        'plugins': plugins,
        'categories': categories,
        'sources': sources,
        'statuses': statuses,
        'summary': {
            'total': len(plugins),
            'enabled': sum(1 for p in plugins if p['enabled']),
            'disabled': sum(1 for p in plugins if not p['enabled']),
            'bundled': sum(1 for p in plugins if p['source'].lower() == 'bundled'),
            'user': sum(1 for p in plugins if p['source'].lower() != 'bundled'),
            'categories': len(categories),
        },
    }


def _cached_plugin_hub_payload(ttl=20):
    now = time.time()
    cached = _PLUGIN_HUB_CACHE.get('payload')
    if cached is not None and now - float(_PLUGIN_HUB_CACHE.get('at') or 0) < ttl:
        return cached
    payload = _base_plugin_hub_payload()
    _PLUGIN_HUB_CACHE['payload'] = payload
    _PLUGIN_HUB_CACHE['at'] = now
    return payload


def list_plugin_hub(filters=None):
    filters = filters or {}
    q = (filters.get('q') or [''])[0].strip().lower()
    category_filter = (filters.get('category') or [''])[0].strip().lower()
    source_filter = (filters.get('source') or [''])[0].strip().lower()
    status_filter = (filters.get('status') or [''])[0].strip().lower()
    base = _cached_plugin_hub_payload()
    filtered = []
    for plugin in base.get('plugins', []):
        haystack = ' '.join([plugin.get('id',''), plugin.get('name',''), plugin.get('category',''), plugin.get('status',''), plugin.get('source',''), plugin.get('version',''), plugin.get('description','')]).lower()
        if q and q not in haystack:
            continue
        if category_filter and plugin.get('category','').lower() != category_filter:
            continue
        if source_filter and plugin.get('source','').lower() != source_filter:
            continue
        if status_filter and plugin.get('status','').lower() != status_filter:
            continue
        filtered.append(plugin)
    categories = base.get('categories') or []
    summary = {
        'total': len(filtered),
        'enabled': sum(1 for p in filtered if p.get('enabled')),
        'disabled': sum(1 for p in filtered if not p.get('enabled')),
        'bundled': sum(1 for p in filtered if str(p.get('source','')).lower() == 'bundled'),
        'user': sum(1 for p in filtered if str(p.get('source','')).lower() != 'bundled'),
        'categories': len(categories),
    }
    result = {'plugins': filtered, 'summary': summary, 'categories': categories, 'sources': base.get('sources') or [], 'statuses': base.get('statuses') or []}
    if base.get('error'):
        result['error'] = base.get('error')
    return result


