def _memory_source_paths():
    candidates = [
        ('user', HERMES_HOME / 'memories' / 'USER.md', 'User profile'),
        ('memory', HERMES_HOME / 'memories' / 'MEMORY.md', 'Operational memory'),
        ('user', HERMES_HOME / 'USER.md', 'User profile'),
        ('memory', HERMES_HOME / 'MEMORY.md', 'Operational memory'),
    ]
    seen = set()
    result = []
    for scope, path, label in candidates:
        try:
            key = str(path.resolve())
        except Exception:
            key = str(path)
        if key in seen:
            continue
        seen.add(key)
        if path.exists():
            result.append((scope, path, label))
    return result


def _memory_category(text, scope):
    t = (text or '').lower()
    if re.search(r'linkedin|voice|tone|preference|expects|prefers|calls assistant|user is ', t):
        return 'identity-preferences'
    if re.search(r'credential|secret|token|api key|password|env|supabase|github wrapper|telegram target', t):
        return 'credentials-sensitive-context'
    if re.search(r'workflow|cron|routine|planner|ops|lead|classes|crm', t):
        return 'workflows-operations'
    if re.search(r'project|repo|source|mission control|tracker|workspace|kb|second brain|path', t):
        return 'projects-environment'
    if re.search(r'governance|audit|safety|verify|approval|human-in-the-loop', t):
        return 'governance-safety'
    return 'profile-fact' if scope == 'user' else 'environment-note'


def _memory_tags(text):
    tags = []
    lowered = (text or '').lower()
    topics = [
        ('Mission Control', 'mission control'), ('LinkedIn', 'linkedin'), ('Nexius', 'nexius'),
        ('Hermes', 'hermes'), ('GitHub', 'github'), ('Supabase', 'supabase'),
        ('Telegram', 'telegram'), ('Second brain', 'second brain'), ('SGQR', 'sgqr'),
        ('PayNow', 'paynow'), ('Net worth', 'net worth'), ('CRM', 'crm'),
    ]
    for label, needle in topics:
        if needle in lowered:
            tags.append(label)
    return tags[:8]


def _memory_title(text):
    clean = re.sub(r'\s+', ' ', str(text or '')).strip()
    if not clean:
        return 'Memory entry'
    if ':' in clean[:80]:
        head = clean.split(':', 1)[0].strip()
        if 3 <= len(head) <= 80:
            return head
    first = re.split(r'[.;]', clean, 1)[0].strip()
    return trim(first, 72) or 'Memory entry'


def _split_memory_entries(content):
    entries = []
    current = []
    start = 1
    for idx, line in enumerate(content.splitlines(), 1):
        if line.strip() == '§':
            text = '\n'.join(current).strip()
            if text:
                entries.append((start, text))
            current = []
            start = idx + 1
        else:
            if not current and line.strip():
                start = idx
            current.append(line)
    text = '\n'.join(current).strip()
    if text:
        entries.append((start, text))
    return entries


def memory_context_payload(filters=None):
    filters = filters or {}
    q = (filters.get('q') or [''])[0].strip().lower()
    scope_filter = (filters.get('scope') or [''])[0].strip().lower()
    category_filter = (filters.get('category') or [''])[0].strip().lower()
    entries = []
    for scope, path, source_label in _memory_source_paths():
        try:
            content = path.read_text(errors='replace')
            st = path.stat()
        except Exception as exc:
            entries.append({'id': f'{scope}-error', 'scope': scope, 'scope_label': source_label, 'category': 'read-error', 'title': 'Unable to read memory file', 'text': str(exc), 'raw': str(exc), 'source_path': str(path), 'source_label': source_label, 'line_start': 0, 'updated_at': '—', 'redacted': False, 'tags': []})
            continue
        for n, (line_start, raw_text) in enumerate(_split_memory_entries(content), 1):
            redacted_text = preview_content(raw_text, 5000)
            category = _memory_category(redacted_text, scope)
            entry = {
                'id': hashlib.sha1(f'{path}:{line_start}:{raw_text}'.encode('utf-8', errors='ignore')).hexdigest()[:16],
                'scope': scope,
                'scope_label': source_label,
                'category': category,
                'title': _memory_title(redacted_text),
                'text': redacted_text,
                'raw': redacted_text,
                'source_path': str(path),
                'source_label': f'{source_label} · {path.name}',
                'line_start': line_start,
                'updated_at': iso(st.st_mtime),
                'redacted': redacted_text != raw_text,
                'tags': _memory_tags(redacted_text),
            }
            entries.append(entry)
    filtered = []
    for entry in entries:
        haystack = text_blob(entry.get('title'), entry.get('text'), entry.get('scope_label'), entry.get('category'), ' '.join(entry.get('tags') or [])).lower()
        if q and q not in haystack:
            continue
        if scope_filter and entry.get('scope') != scope_filter:
            continue
        if category_filter and entry.get('category') != category_filter:
            continue
        filtered.append(entry)
    filtered.sort(key=lambda e: (e.get('scope') != 'user', e.get('category') or '', e.get('line_start') or 0))
    all_categories = sorted({e.get('category') for e in entries if e.get('category')})
    category_counts = []
    for cat in all_categories:
        category_counts.append({'category': cat, 'count': sum(1 for e in entries if e.get('category') == cat)})
    return {
        'entries': filtered,
        'summary': {
            'total': len(filtered),
            'user': sum(1 for e in filtered if e.get('scope') == 'user'),
            'memory': sum(1 for e in filtered if e.get('scope') == 'memory'),
            'redacted': sum(1 for e in filtered if e.get('redacted')),
            'categories': len(all_categories),
        },
        'categories': all_categories,
        'category_counts': category_counts,
        'sources': sorted({e.get('source_label') for e in entries if e.get('source_label')}),
        'policy': {
            'summary': 'Mission Control exposes durable Hermes memory as read-only evidence and applies best-effort redaction for likely secrets, tokens, passwords, and credential-like values before display.',
            'recommended_controls': ['Request correction', 'Request deletion', 'View source evidence', 'Audit future edits'],
        },
    }


