_SKILL_HUB_CACHE = {'at': 0, 'payload': None}


def _base_skill_hub_payload():
    # Build the skills inventory once per request/cache fill. The previous
    # implementation called profile_labels_for_skill() for every skill, and that
    # function rescanned every SKILL.md for every row. With ~133 skills, that
    # became tens of thousands of filesystem reads and made /api/skills take
    # 25-60s. This builds the same routing evidence in one pass.
    records = {}
    agent_usage = {}
    channel_labels = ['Terminal Chat', 'Telegram Bot Chat', 'Dashboard Chat']

    default_rows = read_skill_records_for_profile('default')
    for row in default_rows:
        records[row['id']] = row
        if row.get('source') == 'Hermes':
            agent_usage.setdefault(row['id'], set()).update(channel_labels)

    profiles = HERMES_HOME / 'profiles'
    if profiles.exists():
        for d in sorted([x for x in profiles.iterdir() if x.is_dir()]):
            profile_rows = read_skill_records_for_profile(d.name)
            for row in profile_rows:
                records.setdefault(row['id'], row)
                if row.get('source') == 'Hermes':
                    agent_usage.setdefault(row['id'], set()).add(d.name)

    auto_usage = automation_skill_usage()
    task_usage = task_skill_usage()
    skills = []
    for sid, row in records.items():
        agents = agent_usage.get(sid, set())
        automations = auto_usage.get(row['name'], []) + auto_usage.get(sid, [])
        task_refs = task_usage.get(row['name'], []) + task_usage.get(sid, [])
        source = row['source']
        used_count = len(set(agents)) + len(set(automations)) + len(set(task_refs))
        skills.append({
            **row,
            'source': source,
            'used_by_agents': sorted(set(agents)),
            'used_by_automations': sorted(set(automations))[:10],
            'used_by_tasks': sorted(set(task_refs))[:10],
            'used_by_count': used_count,
            'enabled': True,
        })

    skills.sort(key=lambda s: (s['category'], s['name']))
    return {
        'skills': skills,
        'categories': sorted({s['category'] for s in skills}),
        'sources': sorted({'Hermes', 'OpenClaw', 'Shared'} | {s['source'] for s in skills}),
        'summary': {
            'total': len(skills),
            'editable': sum(1 for s in skills if s['editable']),
            'hermes': sum(1 for s in skills if s['source'] == 'Hermes'),
            'openclaw': sum(1 for s in skills if s['source'] == 'OpenClaw'),
            'shared': sum(1 for s in skills if s['source'] == 'Shared'),
            # Backward-compatible fields for older bundles.
            'plugin': 0,
            'user': sum(1 for s in skills if s['source'] == 'Hermes'),
            'assigned': sum(1 for s in skills if s['used_by_count'] > 0),
        },
    }


def _cached_skill_hub_payload(ttl=20):
    now = time.time()
    cached = _SKILL_HUB_CACHE.get('payload')
    if cached is not None and now - float(_SKILL_HUB_CACHE.get('at') or 0) < ttl:
        return cached
    payload = _base_skill_hub_payload()
    _SKILL_HUB_CACHE['payload'] = payload
    _SKILL_HUB_CACHE['at'] = now
    return payload


def list_skill_hub(filters=None):
    filters = filters or {}
    q = (filters.get('q') or [''])[0].strip().lower()
    category_filter = (filters.get('category') or [''])[0].strip().lower()
    source_filter = (filters.get('source') or [''])[0].strip().lower()

    base = _cached_skill_hub_payload()
    filtered = []
    for skill in base['skills']:
        haystack = ' '.join([
            skill['id'], skill['name'], skill['category'], skill['description'],
            skill['source'], skill['model'], ' '.join(skill.get('tags') or [])
        ]).lower()
        if q and q not in haystack:
            continue
        if category_filter and skill['category'].lower() != category_filter:
            continue
        if source_filter and skill['source'].lower() != source_filter:
            continue
        filtered.append(skill)

    summary = {
        'total': len(filtered),
        'editable': sum(1 for s in filtered if s['editable']),
        'hermes': sum(1 for s in filtered if s['source'] == 'Hermes'),
        'openclaw': sum(1 for s in filtered if s['source'] == 'OpenClaw'),
        'shared': sum(1 for s in filtered if s['source'] == 'Shared'),
        # Backward-compatible fields for older bundles.
        'plugin': 0,
        'user': sum(1 for s in filtered if s['source'] == 'Hermes'),
        'assigned': sum(1 for s in filtered if s['used_by_count'] > 0),
    }
    return {
        'skills': filtered,
        'summary': summary,
        # Keep filter options stable across search/filter changes.
        'categories': base['categories'],
        'sources': base['sources'],
    }


def get_skill_file(skill_id):
    skill_id = unquote(str(skill_id or '')).strip()
    if not skill_id:
        return {'error': 'skill id required'}, 400
    base = _cached_skill_hub_payload()
    match = None
    for skill in base.get('skills', []):
        if skill.get('id') == skill_id or skill.get('name') == skill_id:
            match = skill
            break
    if not match:
        return {'error': 'skill not found'}, 404
    path = Path(match.get('path') or '')
    try:
        if path.name != 'SKILL.md' or not path.exists():
            return {'error': 'SKILL.md not found'}, 404
        content = path.read_text(errors='replace')
        st = path.stat()
    except Exception as exc:
        return {'error': f'unable to read SKILL.md: {exc}'}, 500
    return {
        'id': match.get('id'),
        'name': match.get('name'),
        'path': str(path),
        'skill_dir': str(path.parent),
        'content': content,
        'size': int(st.st_size),
        'updated_at': iso(st.st_mtime),
    }, 200



def _invalidate_skill_hub_cache():
    try:
        _SKILL_HUB_CACHE['payload'] = None
        _SKILL_HUB_CACHE['at'] = 0
    except Exception:
        pass


def install_slug(value, fallback='item'):
    slug = re.sub(r'[^a-z0-9._-]+', '-', str(value or '').strip().lower()).strip('.-_')
    return (slug or fallback)[:80]


def _safe_profile_for_install(payload):
    profile_id = str((payload or {}).get('profile') or 'default').strip() or 'default'
    if not re.match(r'^[A-Za-z0-9_.-]+$', profile_id):
        return None
    return profile_id


def install_skill_from_payload(payload, identity=None):
    profile_id = _safe_profile_for_install(payload)
    if not profile_id:
        return {'ok': False, 'error': 'invalid profile'}, 400
    name = str(payload.get('name') or '').strip()[:80]
    content = str(payload.get('content') or '').strip()
    description = str(payload.get('description') or '').strip()[:500]
    category = install_slug(payload.get('category') or 'user-installed', 'user-installed')
    if not name and not content:
        return {'ok': False, 'error': 'skill name or SKILL.md content required'}, 400
    if content and content.startswith('---'):
        meta = parse_frontmatter(content)
        name = name or str(meta.get('name') or '').strip()[:80]
        description = description or str(meta.get('description') or '').strip()[:500]
    if not name:
        name = install_slug(payload.get('id') or 'installed-skill', 'installed-skill')
    skill_slug = install_slug(payload.get('id') or name, 'installed-skill')
    if not content:
        safe_name = name.replace('"', '\\"')
        safe_desc = description.replace('"', '\\"') or 'User-installed Mission Control skill.'
        content = (
            '---\n'
            f'name: {safe_name}\n'
            f'description: "{safe_desc}"\n'
            'version: 1.0.0\n'
            'author: Mission Control\n'
            'platforms: [linux]\n'
            '---\n\n'
            f'# {name}\n\n'
            f"{description or 'Describe when to use this skill and the operating procedure.'}\n\n"
            '## When to Use\n\n'
            '- Add trigger conditions here.\n\n'
            '## Procedure\n\n'
            '1. Add the step-by-step workflow here.\n\n'
            '## Verification\n\n'
            '- Add checks that prove the skill worked.\n'
        )
    root = profile_root(profile_id) / 'skills' / category / skill_slug
    try:
        root.mkdir(parents=True, exist_ok=True)
        skill_path = root / 'SKILL.md'
        if skill_path.exists() and not payload.get('overwrite'):
            return {'ok': False, 'error': f'skill already exists at {skill_path}', 'path': str(skill_path)}, 409
        skill_path.write_text(content.rstrip() + '\n')
        _invalidate_skill_hub_cache()
        st = skill_path.stat()
        return {'ok': True, 'type': 'skill', 'name': name, 'id': f'{category}/{skill_slug}', 'path': str(skill_path), 'size': st.st_size, 'updated_at': iso(st.st_mtime)}, 201
    except Exception as exc:
        return {'ok': False, 'error': f'unable to install skill: {exc}'}, 500


def tool_installations_path():
    return APP_ROOT / 'tool_installations.json'


def read_tool_installations():
    path = tool_installations_path()
    try:
        data = json.loads(path.read_text(errors='ignore')) if path.exists() else {}
        items = data.get('items') if isinstance(data, dict) else []
        return items if isinstance(items, list) else []
    except Exception:
        return []


def write_tool_installations(items):
    path = tool_installations_path()
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps({'items': items}, indent=2, sort_keys=True) + '\n')


def load_raw_profile_config(profile_id='default'):
    path = profile_root(profile_id) / 'config.yaml'
    if not path.exists() and profile_id != 'default':
        path = HERMES_HOME / 'config.yaml'
    try:
        if path.exists() and yaml:
            data = yaml.safe_load(path.read_text(errors='ignore'))
            return (data if isinstance(data, dict) else {}, path)
    except Exception:
        pass
    return {}, path


def save_raw_profile_config(profile_id, cfg, path=None):
    path = path or (profile_root(profile_id) / 'config.yaml')
    path.parent.mkdir(parents=True, exist_ok=True)
    if yaml:
        path.write_text(yaml.safe_dump(cfg, sort_keys=False, allow_unicode=True))
    else:
        path.write_text(json.dumps(cfg, indent=2) + '\n')
    return path


def installed_tool_records():
    records = []
    for item in read_tool_installations():
        if not isinstance(item, dict):
            continue
        kind = str(item.get('kind') or 'cli')
        records.append({
            'id': item.get('id') or f"installed:{install_slug(item.get('name'), 'tool')}",
            'name': item.get('name') or item.get('id') or 'Installed tool',
            'kind': 'mcp-server' if kind == 'mcp' else 'cli-tool',
            'source': item.get('source') or ('config.yaml:mcp_servers' if kind == 'mcp' else 'Mission Control'),
            'enabled': item.get('enabled', True),
            'description': item.get('description') or item.get('summary') or 'User-installed Mission Control tool integration.',
            'toolCount': item.get('toolCount'),
            'sampleTools': item.get('sampleTools') or [],
            'categories': item.get('categories') or [{'id': kind, 'name': 'MCP server' if kind == 'mcp' else 'CLI tool', 'count': 1}],
            'assignmentUnit': item.get('assignmentUnit') or item.get('command') or item.get('url') or item.get('id'),
            'install': item,
        })
    return records


def install_tool_from_payload(payload, identity=None):
    kind = str(payload.get('kind') or payload.get('type') or 'mcp').strip().lower()
    if kind not in {'mcp', 'cli'}:
        return {'ok': False, 'error': 'kind must be mcp or cli'}, 400
    profile_id = _safe_profile_for_install(payload)
    if not profile_id:
        return {'ok': False, 'error': 'invalid profile'}, 400
    name = install_slug(payload.get('name') or payload.get('id') or ('mcp-server' if kind == 'mcp' else 'cli-tool'), 'tool')
    label = str(payload.get('label') or payload.get('displayName') or name).strip()[:100]
    now = iso(time.time())
    record = {'id': f'{kind}:{name}', 'kind': kind, 'name': label, 'serverName': name, 'profile': profile_id, 'enabled': True, 'created_at': now, 'updated_at': now}
    if kind == 'mcp':
        transport = str(payload.get('transport') or ('http' if payload.get('url') else 'stdio')).lower()
        server = {}
        if transport == 'http':
            url = str(payload.get('url') or '').strip()
            if not re.match(r'^https?://', url):
                return {'ok': False, 'error': 'HTTP MCP server requires http(s) url'}, 400
            server['url'] = url
            headers = payload.get('headers') if isinstance(payload.get('headers'), dict) else {}
            if headers:
                server['headers'] = {str(k): str(v) for k, v in headers.items() if str(k).strip()}
        else:
            command = str(payload.get('command') or '').strip()
            if not command or any(x in command for x in ['/', '\\', ';', '&', '|', '$', '`']):
                return {'ok': False, 'error': 'stdio MCP server requires a simple command name such as npx or uvx'}, 400
            args = payload.get('args') or []
            if isinstance(args, str):
                args = [x for x in re.split(r'\s+', args.strip()) if x]
            if not isinstance(args, list):
                return {'ok': False, 'error': 'args must be a list or whitespace-separated string'}, 400
            server['command'] = command
            server['args'] = [str(x) for x in args][:30]
            env = payload.get('env') if isinstance(payload.get('env'), dict) else {}
            if env:
                server['env'] = {str(k): str(v) for k, v in env.items() if re.match(r'^[A-Za-z_][A-Za-z0-9_]*$', str(k))}
        for key in ('timeout', 'connect_timeout'):
            if payload.get(key) not in (None, ''):
                try: server[key] = max(1, min(600, int(payload.get(key))))
                except Exception: pass
        cfg, cfg_path = load_raw_profile_config(profile_id)
        servers = cfg.get('mcp_servers') if isinstance(cfg.get('mcp_servers'), dict) else {}
        if name in servers and not payload.get('overwrite'):
            return {'ok': False, 'error': f'MCP server {name} already exists', 'restart_required': False}, 409
        servers[name] = server
        cfg['mcp_servers'] = servers
        cfg_path = save_raw_profile_config(profile_id, cfg, cfg_path)
        redacted = {k: ('[REDACTED]' if k in {'env', 'headers'} else v) for k, v in server.items()}
        record.update({'source': 'config.yaml:mcp_servers', 'description': f'MCP server configured in {cfg_path.name}. Restart Hermes to discover tools.', 'config': redacted, 'config_path': str(cfg_path), 'restart_required': True})
    else:
        command = str(payload.get('command') or '').strip()
        install_command = str(payload.get('installCommand') or payload.get('install_command') or '').strip()
        if not command:
            return {'ok': False, 'error': 'CLI tool command is required'}, 400
        if any(x in command for x in [';', '&', '|', '$', '`']):
            return {'ok': False, 'error': 'CLI command must be a simple executable/path, not a shell expression'}, 400
        record.update({'source': 'Mission Control CLI registry', 'command': command[:240], 'installCommand': install_command[:500], 'description': str(payload.get('description') or f'CLI tool available as {command}')[:500], 'restart_required': False})
    items = [x for x in read_tool_installations() if not (isinstance(x, dict) and x.get('id') == record['id'])]
    items.append(record)
    write_tool_installations(items)
    return {'ok': True, 'type': kind, 'tool': record, 'restart_required': bool(record.get('restart_required'))}, 201

def chat_source_for_agent(agent_id):
    mapping = {
        'terminal': 'cli',
        'cli': 'cli',
        'telegram': 'telegram',
        'telegram-bot': 'telegram',
        'dashboard': 'api_server',
        'api': 'api_server',
        'default': None,
    }
    return mapping.get(agent_id, agent_id if agent_id in ('cli', 'telegram', 'api_server') else None)


def source_stats(source=None, profile_id='default'):
    db_path = state_db_for_profile(profile_id)
    if not db_path.exists():
        return {'count': 0, 'last_ts': None, 'latest_id': None, 'latest_title': None, 'messages': 0}
    try:
        con = sqlite3.connect(f'file:{db_path}?mode=ro', uri=True, timeout=2)
        con.row_factory = sqlite3.Row
        if source:
            r = con.execute("""
                SELECT id, title, started_at, message_count FROM sessions
                WHERE source=? ORDER BY started_at DESC LIMIT 1
            """, (source,)).fetchone()
            count = con.execute('SELECT count(*) FROM sessions WHERE source=?', (source,)).fetchone()[0]
        else:
            r = con.execute("""
                SELECT id, title, started_at, message_count FROM sessions
                WHERE source IN ('cli','telegram','api_server') ORDER BY started_at DESC LIMIT 1
            """).fetchone()
            count = con.execute("SELECT count(*) FROM sessions WHERE source IN ('cli','telegram','api_server')").fetchone()[0]
        con.close()
        return {
            'count': int(count or 0),
            'last_ts': r['started_at'] if r else None,
            'latest_id': r['id'] if r else None,
            'latest_title': (r['title'] or r['id']) if r else None,
            'messages': int(r['message_count'] or 0) if r else 0,
        }
    except Exception:
        return {'count': 0, 'last_ts': None, 'latest_id': None, 'latest_title': None, 'messages': 0}


def display_source_label(source):
    return {
        'cli': 'Terminal',
        'telegram': 'Telegram',
        'api_server': 'Web UI',
    }.get(source or '', source or 'Hermes')


def strip_md_value(value):
    value = str(value or '').strip()
    value = re.sub(r'^[-*]\s*', '', value)
    value = re.sub(r'[_*`#]+', '', value).strip()
    value = value.strip(' :-–—')
    if not value or value.lower().startswith(('fill this', 'workspace-relative path')):
        return ''
    return value[:80]


def identity_candidates_for_profile(profile_id='default'):
    root = HERMES_HOME if profile_id == 'default' else profile_root(profile_id)
    candidates = []
    for name in ('identity.md', 'IDENTITY.md', 'SOUL.md'):
        candidates.append(root / name)
    return candidates


def parse_identity_name(text):
    # OpenClaw-style IDENTITY.md:
    # - **Name:**\n  Troas
    m = re.search(r'\*\*Name:\*\*\s*(?:\n\s*)?([^\n]+)', text, re.I)
    if m:
        value = strip_md_value(m.group(1))
        if value:
            return value
    m = re.search(r'^\s*Name\s*:\s*([^\n]+)', text, re.I | re.M)
    if m:
        value = strip_md_value(m.group(1))
        if value:
            return value
    # Hermes SOUL.md-style identity line.
    m = re.search(r'\bYour name is\s+([^,\.\n]+)', text, re.I)
    if m:
        value = strip_md_value(m.group(1))
        if value:
            return value
    return ''


def agent_identity(profile_id='default'):
    for path in identity_candidates_for_profile(profile_id):
        try:
            if path.exists() and path.is_file():
                name = parse_identity_name(path.read_text(errors='replace')[:6000])
                if name:
                    return {'name': name, 'path': str(path)}
        except Exception:
            continue
    return {'name': '', 'path': ''}


def initials_for_name(name, fallback='HA'):
    words = re.findall(r'[A-Za-z0-9]+', str(name or ''))
    if not words:
        return fallback
    if len(words) == 1:
        return words[0][:2].upper()
    return ''.join(w[0] for w in words[:2]).upper()


def real_chat_messages(source=None, limit=1000, profile_id='default', include_project_context=True):
    db_path = state_db_for_profile(profile_id)
    if not db_path.exists():
        return []
    try:
        con = sqlite3.connect(f'file:{db_path}?mode=ro', uri=True, timeout=2)
        con.row_factory = sqlite3.Row
        if source:
            # Source-specific channel views (especially Telegram) must show the
            # real cross-session transcript in timestamp order, not only the
            # latest session. Hermes may create a new session after compaction or
            # gateway restarts, while the Telegram chat is still one human thread.
            rows = con.execute("""
                SELECT m.id, m.session_id, s.source, s.title, m.role, m.content, m.tool_calls, m.tool_name, m.timestamp, m.platform_message_id
                FROM messages m
                JOIN sessions s ON s.id = m.session_id
                WHERE s.source=?
                  AND m.role IN ('user','assistant')
                  AND m.content IS NOT NULL AND trim(m.content) != ''
                ORDER BY m.timestamp DESC, m.id DESC LIMIT ?
            """, (source, limit)).fetchall()
        else:
            # Unified Hermes Agent view: show one chronological chat stream across
            # terminal CLI, Telegram gateway, and this Web UI/API channel instead
            # of making each communication surface look like a separate agent.
            rows = con.execute("""
                SELECT m.id, m.session_id, s.source, s.title, m.role, m.content, m.tool_calls, m.tool_name, m.timestamp, m.platform_message_id
                FROM messages m
                JOIN sessions s ON s.id = m.session_id
                WHERE s.source IN ('cli','telegram','api_server')
                  AND m.role IN ('user','assistant')
                  AND m.content IS NOT NULL AND trim(m.content) != ''
                ORDER BY m.timestamp DESC, m.id DESC LIMIT ?
            """, (limit,)).fetchall()
        con.close()
    except Exception:
        return []
    rows = list(reversed(rows))
    project_map = {}
    if rows and include_project_context:
        try:
            sessions = list(project_session_text_index({r['session_id'] for r in rows}).values())
            project_map, _ = session_project_assignments(sessions)
        except Exception:
            project_map = {}
    out = []
    last_session = None
    for r in rows:
        role = r['role']
        content = r['content'] or ''
        if role == 'user':
            content = visible_user_message_from_cli_prompt(content)
        source_label = display_source_label(r['source'])
        session_id = r['session_id']
        assigned = project_map.get(session_id) or {}
        project_id = assigned.get('project_id')
        project_name = assigned.get('project_name')
        if source is None and session_id != last_session:
            title = trim(r['title'] or session_id, 90)
            project_prefix = f"{project_name} · " if project_name else ''
            out.append({'id': f"session-{session_id}-{r['id']}", 'role': 'system', 'text': f"{project_prefix}{source_label} · {title}", 'at': rel_time(r['timestamp']), 'ts': float(r['timestamp'] or 0), 'source': r['source'], 'sessionId': session_id, 'projectId': project_id, 'projectName': project_name})
            last_session = session_id
        mid = f"db-{r['id']}"
        at = f"{source_label} · {rel_time(r['timestamp'])}" if source is None else rel_time(r['timestamp'])
        if role == 'tool':
            out.append({'id': mid, 'role': 'system', 'text': f"Tool result {r['tool_name'] or ''}: {trim(content, 900)}", 'at': at, 'ts': float(r['timestamp'] or 0), 'source': r['source'], 'sessionId': session_id, 'projectId': project_id, 'projectName': project_name})
        elif role == 'assistant' and (r['tool_calls'] or '').strip():
            # Tool-call assistant messages are usually short status text; keep
            # a guard here so a malformed tool-call row cannot dominate the
            # channel view.
            out.append({'id': mid, 'role': 'agent', 'text': trim(content, 3000) if content else 'Calling tool…', 'at': at, 'ts': float(r['timestamp'] or 0), 'source': r['source'], 'sessionId': session_id, 'projectId': project_id, 'projectName': project_name})
        else:
            # Chat history is the user's transcript, not a preview. Do not trim
            # normal user/assistant messages here; the React thread scrolls
            # internally and CSS wraps long content. Trimming made long answers
            # appear incomplete in Mission Control even though state.db held the
            # full response.
            out.append({'id': mid, 'role': 'agent' if role == 'assistant' else 'user', 'text': content, 'at': at, 'ts': float(r['timestamp'] or 0), 'source': r['source'], 'sessionId': session_id, 'projectId': project_id, 'projectName': project_name})
    if not out:
        st = source_stats(source, profile_id=profile_id)
        if st['latest_id']:
            out.append({'id': 'empty-session', 'role': 'system', 'text': f"Latest {source or 'Hermes'} session has no displayable user/assistant messages yet: {st['latest_id']}", 'at': 'now', 'ts': time.time(), 'source': source or 'hermes'})
    return out



def worker_transcript_messages(agent_id, limit=220):
    """Return an operator-safe worker log/transcript with tool-call rows.

    The normal Agent chat intentionally hides tool rows. This drawer endpoint is
    for progress inspection, so it includes user/assistant/tool/system-ish rows
    plus active in-process requests and recent Mission Control activity events.
    """
    aid = safe_id(agent_id) or 'default'
    source = chat_source_for_agent(aid)
    db_path = state_db_for_profile(aid)
    entries = []
    sessions_seen = {}
    if db_path.exists():
        try:
            con = sqlite3.connect(f'file:{db_path}?mode=ro', uri=True, timeout=2)
            con.row_factory = sqlite3.Row
            if source:
                rows = con.execute("""
                    SELECT m.id, m.session_id, s.source, s.title, s.model, m.role, m.content, m.tool_calls, m.tool_name, m.timestamp, m.token_count, m.finish_reason
                    FROM messages m
                    JOIN sessions s ON s.id = m.session_id
                    WHERE s.source=?
                    ORDER BY m.timestamp DESC, m.id DESC LIMIT ?
                """, (source, int(limit))).fetchall()
            else:
                rows = con.execute("""
                    SELECT m.id, m.session_id, s.source, s.title, s.model, m.role, m.content, m.tool_calls, m.tool_name, m.timestamp, m.token_count, m.finish_reason
                    FROM messages m
                    JOIN sessions s ON s.id = m.session_id
                    WHERE s.source IN ('cli','telegram','api_server')
                    ORDER BY m.timestamp DESC, m.id DESC LIMIT ?
                """, (int(limit),)).fetchall()
            con.close()
            for r in reversed(rows):
                ts = float(r['timestamp'] or 0)
                sid = r['session_id']
                sessions_seen.setdefault(sid, {'id': sid, 'title': r['title'] or sid, 'source': r['source'], 'model': r['model'], 'started_at': iso(ts)})
                role = r['role'] or 'system'
                text = r['content'] or ''
                tool_calls = []
                if r['tool_calls']:
                    try:
                        parsed = json.loads(r['tool_calls'])
                        if isinstance(parsed, list):
                            tool_calls = parsed[:8]
                    except Exception:
                        tool_calls = []
                if role == 'user':
                    text = visible_user_message_from_cli_prompt(text)
                entry_type = 'message'
                status = 'info'
                title = {'user': 'User message', 'assistant': 'Agent reply', 'tool': 'Tool result', 'system': 'System'}.get(role, role)
                if role == 'assistant' and tool_calls:
                    entry_type = 'tool-call'
                    names = []
                    for call in tool_calls:
                        fn = call.get('function') if isinstance(call, dict) else None
                        nm = (fn or {}).get('name') if isinstance(fn, dict) else None
                        if nm:
                            names.append(nm)
                    title = 'Tool call' + (': ' + ', '.join(names[:3]) if names else '')
                    status = 'requested'
                    if not text:
                        text = 'Agent requested tool execution.'
                elif role == 'tool' or r['tool_name']:
                    entry_type = 'tool-result'
                    title = f"Tool result{': ' + r['tool_name'] if r['tool_name'] else ''}"
                    status = 'done'
                elif role == 'assistant':
                    status = 'done'
                elif role == 'user':
                    status = 'queued'
                entries.append({
                    'id': f"db-{r['id']}",
                    'type': entry_type,
                    'role': 'agent' if role == 'assistant' else role,
                    'title': title,
                    'text': text,
                    'at': rel_time(ts),
                    'ts': ts,
                    'source': r['source'],
                    'sessionId': sid,
                    'sessionTitle': r['title'] or sid,
                    'toolName': r['tool_name'],
                    'toolCalls': tool_calls,
                    'tokens': r['token_count'],
                    'finishReason': r['finish_reason'],
                    'status': status,
                })
        except Exception as e:
            entries.append({'id': 'transcript-error', 'type': 'system', 'role': 'system', 'title': 'Transcript unavailable', 'text': str(e), 'at': 'now', 'ts': time.time(), 'source': 'mission-control', 'status': 'error'})

    for item in active_processing_items(aid):
        started = float(item.get('started_at') or time.time())
        entries.append({
            'id': f"active-{item.get('id')}",
            'type': 'processing',
            'role': 'system',
            'title': 'Worker request in progress',
            'text': f"Request {item.get('id')} is still running for this agent.",
            'at': rel_time(started),
            'ts': started,
            'source': 'mission-control-worker',
            'requestId': item.get('id'),
            'status': 'running',
        })

    for row in list_agent_activity(aid, limit=40):
        try:
            ts = datetime.fromisoformat(str(row.get('created_at')).replace('Z', '+00:00')).timestamp()
        except Exception:
            ts = time.time()
        entries.append({
            'id': row.get('id'),
            'type': 'activity',
            'role': 'system',
            'title': row.get('title') or row.get('action') or 'Activity',
            'text': row.get('detail') or '',
            'at': rel_time(ts),
            'ts': ts,
            'source': row.get('source') or 'mission-control-ui',
            'status': row.get('status') or 'info',
            'jobId': row.get('job_id'),
            'jobName': row.get('job_name'),
            'actor': row.get('actor'),
        })

    entries.sort(key=lambda item: (float(item.get('ts') or 0), str(item.get('id') or '')))
    active = [item for item in entries if item.get('status') == 'running' or item.get('type') == 'processing']
    return {
        'agentId': aid,
        'generatedAt': datetime.now(SGT).strftime('%Y-%m-%d %H:%M:%S SGT'),
        'active': active[-8:],
        'entries': entries[-int(limit):],
        'sessions': list(sessions_seen.values())[-20:],
        'summary': {
            'entries': len(entries[-int(limit):]),
            'active': len(active),
            'toolEvents': sum(1 for item in entries if item.get('type') in ('tool-call', 'tool-result')),
            'sessions': len(sessions_seen),
        },
    }

def load_ui_chat_overlays():
    try:
        if UI_CHAT_FILE.exists():
            data = json.loads(UI_CHAT_FILE.read_text(errors='replace'))
            if isinstance(data, dict):
                return data
    except Exception:
        pass
    return {}


def save_ui_chat_overlays(data):
    try:
        UI_CHAT_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = UI_CHAT_FILE.with_suffix('.tmp')
        tmp.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding='utf-8')
        tmp.replace(UI_CHAT_FILE)
        try:
            UI_CHAT_FILE.chmod(0o600)
        except Exception:
            pass
    except Exception:
        pass


def close_orphaned_ui_requests(agent_id, stale_after_seconds=30, existing_messages=None):
    """Close UI chat requests that survived a backend restart without a reply.

    Async Mission Control chat sends are persisted as a user row first, then a
    background worker appends an assistant/system completion. If the service is
    restarted between those two writes, the browser can keep polling forever for
    a request that no backend worker owns anymore. Reconcile that state on reads.

    Important: some workspace-routed replies are persisted by the Hermes runtime
    in state.db without the UI requestId. Treat any real assistant reply after the
    overlay user row as completion evidence; otherwise Mission Control can render
    a valid answer and a false red "no assistant reply" banner underneath it.
    """
    aid = safe_id(agent_id) or 'default'
    active_ids = {item.get('id') for item in active_processing_items(aid) if item.get('id')}
    now = time.time()
    data = load_ui_chat_overlays()
    rows = data.get(aid, [])
    if not isinstance(rows, list) or not rows:
        return
    db_agent_reply_ts = [
        float(item.get('ts') or 0)
        for item in (existing_messages or [])
        if isinstance(item, dict) and item.get('role') == 'agent' and str(item.get('text') or '').strip()
    ]
    by_request = {}
    for row in rows:
        rid = row.get('requestId') if isinstance(row, dict) else None
        if rid:
            by_request.setdefault(rid, []).append(row)
    changed = False
    for rid, items in by_request.items():
        if rid in active_ids:
            continue
        user_ts_values = [float(item.get('ts') or 0) for item in items if item.get('role') == 'user']
        has_user = bool(user_ts_values)
        user_ts = min(user_ts_values) if user_ts_values else 0
        has_overlay_agent = any(item.get('role') == 'agent' for item in items)
        has_real_reply = bool(user_ts and any(reply_ts >= user_ts - 2 for reply_ts in db_agent_reply_ts))
        has_completion = has_overlay_agent or has_real_reply or any(item.get('role') == 'system' for item in items)
        latest_ts = max(float(item.get('ts') or 0) for item in items)
        if has_user and not has_completion and now - latest_ts >= stale_after_seconds:
            rows.append({
                'id': f'ui-agent-error-{int(now * 1000)}-{safe_id(rid)[:20]}',
                'role': 'system',
                'text': 'Message processing failed: backend request is no longer active and no assistant reply was recorded. The Mission Control worker was likely interrupted or restarted; please resend if you still need this task run.',
                'at': 'now',
                'ts': now,
                'source': 'web-ui',
                'requestId': rid,
            })
            changed = True
    if changed:
        data[aid] = rows[-120:]
        save_ui_chat_overlays(data)


def ui_chat_messages(agent_id, existing_messages=None):
    aid = safe_id(agent_id) or 'default'
    close_orphaned_ui_requests(aid, existing_messages=existing_messages)
    data = load_ui_chat_overlays()
    rows = data.get(aid, [])
    if not isinstance(rows, list):
        return []
    cleaned = []
    for row in rows[-80:]:
        if isinstance(row, dict):
            row = {**row}
            row.setdefault('projectId', 'general-chat')
            row.setdefault('projectName', 'General chat')
            if row.get('role') == 'user':
                row['text'] = visible_user_message_from_cli_prompt(row.get('text') or '')
        cleaned.append(row)
    return cleaned


def dedupe_ui_overlay_against_db(messages, overlay):
    """Hide UI overlay rows once the same API-server reply is visible in state.db.

    Mission Control writes an overlay row immediately so browser refreshes keep a
    pending/completed Web UI request visible. The Hermes API server also persists
    the same user/assistant exchange into state.db after completion. Without this
    reconciliation, agent_payload() merges both sources and the same exchange is
    rendered twice.
    """
    if not overlay:
        return overlay
    db_agent_rows = []
    for msg in messages or []:
        if msg.get('role') != 'agent' or msg.get('source') not in ('api_server', 'cli'):
            continue
        text = str(msg.get('text') or '').strip()
        if text:
            db_agent_rows.append((text, float(msg.get('ts') or 0)))
    if not db_agent_rows:
        return overlay

    duplicate_request_ids = set()
    duplicate_overlay_ids = set()
    overlay_user_ts_by_request = {}
    for row in overlay:
        if isinstance(row, dict) and row.get('role') == 'user' and row.get('requestId'):
            overlay_user_ts_by_request[row.get('requestId')] = float(row.get('ts') or 0)
    db_reply_satisfied_request_ids = {
        rid
        for rid, user_ts in overlay_user_ts_by_request.items()
        if user_ts and any(db_ts >= user_ts - 2 for _, db_ts in db_agent_rows)
    }
    for row in overlay:
        if not isinstance(row, dict) or row.get('role') != 'agent':
            continue
        text = str(row.get('text') or '').strip()
        if not text:
            continue
        ots = float(row.get('ts') or 0)
        matched = any(db_text == text and (not ots or not db_ts or abs(db_ts - ots) <= 10) for db_text, db_ts in db_agent_rows)
        if not matched:
            continue
        rid = row.get('requestId')
        if rid:
            duplicate_request_ids.add(rid)
        else:
            duplicate_overlay_ids.add(row.get('id'))

    if not duplicate_request_ids and not duplicate_overlay_ids and not db_reply_satisfied_request_ids:
        return overlay
    return [
        row for row in overlay
        if not isinstance(row, dict)
        or (
            row.get('requestId') not in duplicate_request_ids
            and row.get('id') not in duplicate_overlay_ids
            and not (
                row.get('role') == 'system'
                and row.get('requestId') in db_reply_satisfied_request_ids
                and 'no assistant reply' in str(row.get('text') or '').lower()
            )
        )
    ]


def append_ui_chat_messages(agent_id, messages):
    aid = safe_id(agent_id) or 'default'
    data = load_ui_chat_overlays()
    current = data.get(aid, [])
    if not isinstance(current, list):
        current = []
    merged = current + list(messages or [])
    deduped = []
    seen = set()
    for row in reversed(merged):
        if isinstance(row, dict):
            key = row.get('id') or (row.get('requestId'), row.get('role'), str(row.get('text') or '').strip())
        else:
            key = repr(row)
        if key in seen:
            continue
        seen.add(key)
        deduped.append(row)
    deduped.reverse()
    data[aid] = deduped[-120:]
    save_ui_chat_overlays(data)


def sanitize_filename(name):
    base = Path(str(name or 'attachment')).name.strip() or 'attachment'
    base = re.sub(r'[^A-Za-z0-9._ -]+', '_', base).strip(' .') or 'attachment'
    if len(base) > 120:
        stem = Path(base).stem[:80] or 'attachment'
        suffix = Path(base).suffix[:16]
        base = stem + suffix
    return base


def attachment_public_url(agent_id, stored_name):
    return f"/api/attachments/{safe_id(agent_id) or 'default'}/{quote(str(stored_name))}"


def attachment_preview(path, mime):
    mt = (mime or '').lower()
    textual = mt.startswith('text/') or mt in {
        'application/json', 'application/xml', 'application/yaml', 'application/x-yaml',
        'application/javascript', 'application/typescript', 'text/markdown'
    }
    if not textual:
        return ''
    try:
        raw = Path(path).read_bytes()[:8192]
        return preview_content(raw.decode('utf-8', errors='replace'), 1200)
    except Exception:
        return ''


def save_attachment(agent_id, payload):
    aid = safe_id(agent_id) or 'default'
    filename = sanitize_filename(payload.get('filename'))
    mime = str(payload.get('mime') or mimetypes.guess_type(filename)[0] or 'application/octet-stream')[:160]
    declared_size = int(payload.get('sizeBytes') or payload.get('size') or 0)
    if declared_size and declared_size > MAX_ATTACHMENT_BYTES:
        return {'error': f'file exceeds {MAX_ATTACHMENT_BYTES // (1024 * 1024)} MB limit'}, 413
    data = str(payload.get('data') or '')
    if ',' in data and data[:40].startswith('data:'):
        data = data.split(',', 1)[1]
    try:
        content = base64.b64decode(data, validate=True)
    except Exception:
        return {'error': 'attachment data must be base64'}, 400
    if not content:
        return {'error': 'empty attachment'}, 400
    if len(content) > MAX_ATTACHMENT_BYTES:
        return {'error': f'file exceeds {MAX_ATTACHMENT_BYTES // (1024 * 1024)} MB limit'}, 413
    upload_root = (UPLOAD_DIR / aid).resolve()
    upload_root.mkdir(parents=True, exist_ok=True)
    stamp = datetime.now(tz=timezone.utc).strftime('%Y%m%dT%H%M%S')
    digest = hashlib.sha256(content).hexdigest()[:12]
    stored_name = f"{stamp}-{digest}-{filename}"
    path = (upload_root / stored_name).resolve()
    if not str(path).startswith(str(upload_root)):
        return {'error': 'invalid upload path'}, 400
    path.write_bytes(content)
    try:
        path.chmod(0o600)
    except Exception:
        pass
    attachment = {
        'id': digest,
        'filename': filename,
        'path': str(path),
        'mime': mime,
        'sizeBytes': len(content),
        'createdAt': iso(path.stat().st_mtime),
        'url': attachment_public_url(aid, stored_name),
    }
    preview = attachment_preview(path, mime)
    if preview:
        attachment['preview'] = preview
    return attachment, 201


def save_agent_attachment_for_identity(identity, agent_id, payload):
    route, route_status = resolve_agent_runtime_route(identity, agent_id, provision_runtime=True)
    if route_status != 200:
        return route, route_status
    return save_attachment(route.get('channel_id') or safe_id(agent_id) or 'default', payload)


def normalize_message_attachments(agent_id, attachments):
    aid = safe_id(agent_id) or 'default'
    out = []
    root = (UPLOAD_DIR / aid).resolve()
    for item in attachments if isinstance(attachments, list) else []:
        if not isinstance(item, dict):
            continue
        try:
            path = Path(str(item.get('path') or '')).resolve()
            if not str(path).startswith(str(root)) or not path.exists() or not path.is_file():
                continue
            st = path.stat()
            mime = str(item.get('mime') or mimetypes.guess_type(str(path))[0] or 'application/octet-stream')[:160]
            record = {
                'id': str(item.get('id') or hashlib.sha256(str(path).encode()).hexdigest()[:12]),
                'filename': sanitize_filename(item.get('filename') or path.name),
                'path': str(path),
                'mime': mime,
                'sizeBytes': st.st_size,
                'createdAt': item.get('createdAt') or iso(st.st_mtime),
                'url': item.get('url') or attachment_public_url(aid, path.name),
            }
            preview = item.get('preview') or attachment_preview(path, mime)
            if preview:
                record['preview'] = str(preview)[:1200]
            out.append(record)
        except Exception:
            continue
    return out[:8]


def attachment_prompt_block(attachments):
    if not attachments:
        return ''
    lines = ['Attached files available on the Mission Control server. Inspect/read them before answering when relevant:']
    for idx, a in enumerate(attachments, 1):
        lines.append(f"{idx}. {a['filename']} ({a['mime']}, {a['sizeBytes']} bytes) at {a['path']}")
        if (a.get('mime') or '').lower().startswith('image/'):
            lines.append('   This is an image. Use vision/image-reading tools against the local path if needed.')
        if a.get('preview'):
            lines.append('   Text preview:\n' + '\n'.join('   ' + x for x in str(a['preview']).splitlines()[:30]))
    return '\n'.join(lines)


def source_context_for_prompt(agent_id, limit=16):
    source = chat_source_for_agent(agent_id)
    messages = real_chat_messages(source, limit=limit, profile_id=agent_id)
    lines = []
    for m in messages[-limit:]:
        text = trim(m.get('text') or m.get('insight') or '', 700)
        if not text:
            continue
        role = 'assistant' if m.get('role') == 'agent' else m.get('role', 'user')
        lines.append(f"{role}: {text}")
    if not lines:
        return ''
    label = {'terminal': 'Terminal CLI', 'telegram': 'Telegram bot', 'dashboard': 'Dashboard'}.get(agent_id, agent_id)
    return f"Latest {label} conversation context shown in Mission Control:\n" + '\n'.join(lines)


def artifacts(limit=20, max_files=600):
    roots = [HERMES_HOME / 'workspace', HOME / '.openclaw' / 'workspace']
    out = []
    skipped_dirs = {'.git', '.hg', '.svn', '.venv', 'venv', 'node_modules', '__pycache__', 'dist', 'build', '.next', '.cache'}
    scanned = 0
    for root in roots:
        if not root.exists():
            continue
        for current, dirs, files in os.walk(root):
            dirs[:] = [d for d in dirs if d not in skipped_dirs and not d.startswith('.')]
            for name in files:
                if scanned >= max_files:
                    break
                path = Path(current) / name
                try:
                    st = path.stat()
                    scanned += 1
                    if st.st_size >= 5_000_000:
                        continue
                    out.append({'id': str(path), 'filename': path.name, 'path': str(path), 'mime': mimetypes.guess_type(str(path))[0] or 'application/octet-stream', 'sizeBytes': st.st_size, 'createdAt': rel_time(st.st_mtime), 'preview': str(path), '_mtime': st.st_mtime})
                except Exception:
                    continue
            if scanned >= max_files:
                break
    out.sort(key=lambda x: x.get('_mtime') or 0, reverse=True)
    for item in out:
        item.pop('_mtime', None)
    return out[:limit]


def tasks_from_cron():
    return [{'id': j['id'] or j['name'], 'title': j['name'], 'status': 'running' if j['enabled'] else 'queued', 'updatedAt': j.get('last_run_at') or '—'} for j in get_cron_jobs()]



def agent_list_status_payload():
    return {
        'now': datetime.now(SGT).strftime('%Y-%m-%d %H:%M:%S SGT'),
        'runtime': {'version': 'unknown', 'profiles': 0, 'profile_names': []},
        'api': {'base': API_BASE, 'health': {'ok': True, 'status': 'not-checked'}, 'models': ['hermes-agent'], 'error': None},
        'gateway': {'running': True, 'processes': []},
        'openwebui': '',
        'sessions': {},
        'cron': {'total': 0, 'enabled': 0, 'jobs': []},
    }


def base_agent_identity_fields(profile_id, st=None):
    st = st or agent_list_status_payload()
    api_ok = bool(st['api']['health'].get('ok'))
    if profile_id in ('terminal', 'cli'):
        name, squad, initials, color = 'Terminal Chat', 'CLI', 'TC', '#3b6fe0'
    elif profile_id in ('telegram', 'telegram-bot'):
        name, squad, initials, color = 'Telegram Bot Chat', 'Telegram', 'TG', '#0e8f84'
    elif profile_id in ('dashboard', 'api'):
        name, squad, initials, color = 'Dashboard Chat', 'API Server', 'DS', '#8b5cf6'
    elif profile_id in ('devops', 'dev-ops'):
        name, squad, initials, color = 'Andrej / DevOps Builder', 'DevOps', 'AB', '#f97316'
    else:
        identity_cfg = agent_identity(profile_id)
        identity_name = identity_cfg.get('name') or 'Hermes Agent'
        name, squad, initials, color = identity_name, 'All Channels', initials_for_name(identity_name, 'HA'), '#0e8f84'
    return {'name': name, 'squad': squad, 'initials': initials, 'color': color if api_ok else '#dc4040', 'api_ok': api_ok}


def agent_summary_payload(profile_id='default', st=None, chat_channel_id=None, identity=None, route=None):
    """Lightweight roster row for /api/agents.

    The full chat transcript, config files, artifact scan, cron task list, and
    runtime profile details are intentionally excluded here and loaded from
    /api/agents/<id> when the operator selects an agent.
    """
    st = st or agent_list_status_payload()
    chat_id = safe_id(chat_channel_id) if chat_channel_id else profile_id
    source = chat_source_for_agent(chat_id)
    fields = base_agent_identity_fields(profile_id, st)
    stats = source_stats(source, profile_id=chat_id)
    jobs = get_cron_jobs()
    resolution = agent_status_resolution(profile_id, st, source, jobs)
    status = resolution['status']
    activity = resolution['detail'] if status in ('active', 'degraded', 'offline') else f"Latest: {stats['latest_title'] or 'no session yet'}"
    return {
        'id': profile_id,
        'name': fields['name'],
        'squad': fields['squad'],
        'initials': fields['initials'],
        'color': fields['color'],
        'model': profile_config_model(profile_id, ', '.join(st['api']['models']) or 'hermes-agent'),
        'status': status,
        'availability': resolution['availability'],
        'activityState': resolution['activity_state'],
        'statusLabel': resolution['label'],
        'statusDetail': resolution['detail'],
        'statusEvidence': resolution['evidence'],
        'activity': activity,
        'lastActive': rel_time(stats['last_ts']) if stats['last_ts'] else st['now'],
        'profilePath': str(HERMES_HOME if profile_id == 'default' else profile_root(profile_id)),
        'uptime': 'systemd managed',
        'sessionCount': stats['count'],
        'skills': [],
        'tools': [],
        'files': [],
        'messages': [],
        'processingRequests': [item.get('id') for item in active_processing_items(chat_id) if item.get('id')],
        'processingRequestDetails': active_processing_items(chat_id),
        'artifacts': [],
        'tasks': [],
        'detailLoaded': False,
        'detailEndpoint': f'/api/agents/{quote(profile_id, safe="")}',
        'transcriptEndpoint': f'/api/agents/{quote(profile_id, safe="")}/worker-transcript',
        'insightSummary': f"{stats['count']} sessions · {stats['messages']} messages. Select agent to lazy-load transcript and runtime details.",
        'insightStatus': 'Operational' if fields['api_ok'] else (st['api'].get('error') or 'API unavailable'),
    }


def agent_payload(profile_id='default', st=None, include_artifacts=True, chat_channel_id=None, identity=None, route=None, message_limit=None, include_runtime_details=True, include_message_project_context=True):
    st = st or status_payload()
    chat_id = safe_id(chat_channel_id) if chat_channel_id else profile_id
    source = chat_source_for_agent(chat_id)
    fields = base_agent_identity_fields(profile_id, st)
    api_ok = fields['api_ok']
    name, squad, initials, color = fields['name'], fields['squad'], fields['initials'], fields['color']
    stats = source_stats(source, profile_id=chat_id)
    messages = real_chat_messages(source, profile_id=chat_id, limit=message_limit or 1000, include_project_context=include_message_project_context)
    overlay = dedupe_ui_overlay_against_db(messages, ui_chat_messages(chat_id, existing_messages=messages))
    if overlay:
        messages = messages + overlay
        messages.sort(key=lambda m: (float(m.get('ts') or 0), 0 if str(m.get('id') or '').startswith('session-') else 1, str(m.get('id') or '')))
    if message_limit is not None:
        try:
            messages = messages[-int(message_limit):]
        except Exception:
            pass
    jobs = get_cron_jobs()
    resolution = agent_status_resolution(profile_id, st, source, jobs)
    status = resolution['status']
    activity = resolution['detail'] if status in ('active', 'degraded', 'offline') else f"Latest: {stats['latest_title'] or 'no session yet'}"
    return {
        'id': profile_id,
        'name': name,
        'squad': squad,
        'initials': initials,
        'color': color if api_ok else '#dc4040',
        'model': profile_config_model(profile_id, ', '.join(st['api']['models']) or 'hermes-agent'),
        'status': status,
        'availability': resolution['availability'],
        'activityState': resolution['activity_state'],
        'statusLabel': resolution['label'],
        'statusDetail': resolution['detail'],
        'statusEvidence': resolution['evidence'],
        'activity': activity,
        'lastActive': rel_time(stats['last_ts']) if stats['last_ts'] else st['now'],
        'profilePath': str(HERMES_HOME if profile_id == 'default' else profile_root(profile_id)),
        'uptime': 'systemd managed',
        'sessionCount': stats['count'],
        'skills': list_skills(
            'default' if profile_id in ('terminal', 'telegram', 'dashboard', 'api', 'cli') else profile_id,
            platform=skill_platform_for_agent(profile_id),
        ) if include_runtime_details else [],
        'tools': agent_tool_capabilities(profile_id) if include_runtime_details else [],
        'files': read_config_files('default' if profile_id in ('terminal', 'telegram', 'dashboard', 'api', 'cli') else profile_id, identity=identity, agent_id=(route or {}).get('agent_id') if route else None, agent_name=(route or {}).get('agent_name') if route else '') if include_runtime_details else [],
        'messages': messages,
        'processingRequests': [item.get('id') for item in active_processing_items(chat_id) if item.get('id')],
        'processingRequestDetails': active_processing_items(chat_id),
        'artifacts': artifacts() if include_artifacts else [],
        'tasks': tasks_from_cron() if include_runtime_details else [],
        'detailLoaded': True,
        'profile_details': profile_runtime_details('default' if profile_id in ('terminal', 'telegram', 'dashboard', 'api', 'cli') else profile_id, automations=jobs) if include_runtime_details else None,
        'insightSummary': f"Showing real {'all-channel' if source is None else source} chat from state.db. Latest session: {stats['latest_id'] or 'none'} · {stats['messages']} messages.",
        'insightStatus': 'Operational' if api_ok else (st['api'].get('error') or 'API unavailable'),
    }


def configured_hermes_profile_ids(include_default=True):
    """Return Hermes profile directories present on disk.

    This is the raw backend inventory. UI rosters should usually use
    agent_roster_profile_ids() instead so workspace/admin/demo profile shells do
    not appear as coworker agents.
    """
    ids = ['default'] if include_default else []
    root = HERMES_HOME / 'profiles'
    try:
        for path in sorted(root.iterdir(), key=lambda p: p.name.lower()):
            if not path.is_dir():
                continue
            pid = safe_id(path.name)
            if pid and pid not in ids:
                ids.append(pid)
    except Exception:
        pass
    return ids


def agent_roster_profile_ids(include_default=True):
    """Profiles that should be shown as backend agent runtimes in HMC.

    HMC also creates mc-* user/admin/demo runtime profiles. Those are real
    backend profiles, but they are not digital coworker agents and should not
    clutter Agent Org/Agent Chat. The authoritative coworker mapping is the
    agent registry: role cards point at the Hermes profile that actually backs
    the workflow.
    """
    ids = ['default'] if include_default else []
    try:
        registry = load_agent_registry()
        for agent in registry.get('agents') or []:
            if not isinstance(agent, dict):
                continue
            profile_id = safe_id(agent.get('profile') or '')
            if not profile_id or profile_id == 'default' or profile_id in ids:
                continue
            if (agent.get('type') or '') not in ('runtime_agent', 'hermes_profile'):
                continue
            if profile_root(profile_id).exists():
                ids.append(profile_id)
    except Exception:
        pass
    return ids


def list_agents_payload(identity=None):
    if identity and not is_admin_identity(identity):
        directory = list_agent_directory(identity)
        runtime = workspace_runtime_profile_snapshot(identity)
        shared_status = agent_list_status_payload()
        enriched = []
        for row in directory.get('agents', []):
            try:
                agent_id = safe_id(row.get('id') or row.get('shared_agent_ref') or 'default') or 'default'
                shared_ref = safe_id(row.get('shared_agent_ref') or agent_id) or agent_id
                route = {
                    'ok': True,
                    'routing_model': 'workspace-profile',
                    'profile_name': runtime.get('profile_name'),
                    'profile_path': runtime.get('profile_path'),
                    'metadata_path': runtime.get('metadata_path'),
                    'workspace_id': identity_workspace_id(identity),
                    'workspace_slug': ((identity or {}).get('workspace') or {}).get('slug'),
                    'user_id': identity_user_id(identity),
                    'agent_id': agent_id,
                    'agent_class': row.get('agent_class'),
                    'shared_agent_ref': shared_ref,
                    'agent_name': row.get('name') or agent_id,
                }
                route['channel_id'] = runtime_agent_channel_id(route)
                payload = agent_summary_payload(shared_ref, st=shared_status, chat_channel_id=route.get('channel_id'), identity=identity, route=route)
                payload.update({'directory': row, 'selected': row.get('selected'), 'nickname': row.get('nickname'), 'capabilities': row.get('capabilities'), 'category': row.get('category')})
                enriched.append(payload)
            except Exception:
                enriched.append(row)
        return enriched
    # One Hermes agent can have many communication surfaces. Terminal,
    # Telegram, and Web UI messages are merged in agent_payload('default') so
    # Mission Control shows a single operator cockpit instead of three fake
    # agents. Separate Hermes profiles, however, are separate runtime agents and
    # should appear in Agent Chat when configured/running.
    shared_status = agent_list_status_payload()
    return [agent_summary_payload(profile_id, st=shared_status) for profile_id in agent_roster_profile_ids(include_default=True)]


def agent_activity_connect():
    AGENT_ACTIVITY_DB.parent.mkdir(parents=True, exist_ok=True)
    con = sqlite3.connect(AGENT_ACTIVITY_DB, timeout=5)
    con.row_factory = sqlite3.Row
    return con


def ensure_agent_activity_tables():
    con = agent_activity_connect()
    con.executescript('''
    CREATE TABLE IF NOT EXISTS agent_activity (
        id TEXT PRIMARY KEY,
        agent_id TEXT NOT NULL,
        agent_name TEXT,
        action TEXT NOT NULL,
        title TEXT NOT NULL,
        detail TEXT,
        status TEXT NOT NULL DEFAULT 'info',
        actor TEXT NOT NULL DEFAULT 'Mission Control',
        source TEXT NOT NULL DEFAULT 'mission-control-ui',
        job_id TEXT,
        job_name TEXT,
        created_at INTEGER NOT NULL,
        metadata TEXT
    );
    CREATE INDEX IF NOT EXISTS idx_agent_activity_agent_time ON agent_activity(agent_id, created_at DESC);
    ''')
    con.commit()
    return con


def record_agent_activity(agent_id, agent_name, action, title, detail='', status='info', actor='Melverick via Mission Control', source='mission-control-ui', job_id=None, job_name=None, metadata=None):
    now = int(time.time())
    base = f"{agent_id}:{action}:{job_id or ''}:{now}:{title}:{detail}"
    activity_id = 'agent-act-' + hashlib.sha1(base.encode('utf-8')).hexdigest()[:16]
    con = ensure_agent_activity_tables()
    con.execute('''
        INSERT OR REPLACE INTO agent_activity (id,agent_id,agent_name,action,title,detail,status,actor,source,job_id,job_name,created_at,metadata)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)
    ''', (activity_id, agent_id, agent_name or agent_id, action, title, preview_content(detail or '', 1600), status, actor, source, job_id, job_name, now, json.dumps(metadata or {})))
    con.commit()
    con.close()
    return activity_id


def activity_row(r):
    meta = {}
    try:
        meta = json.loads(r['metadata'] or '{}')
    except Exception:
        meta = {}
    return {
        'id': r['id'],
        'agent_id': r['agent_id'],
        'agent_name': r['agent_name'],
        'action': r['action'],
        'title': r['title'],
        'detail': r['detail'] or '',
        'status': r['status'] or 'info',
        'actor': r['actor'] or 'Mission Control',
        'source': r['source'] or 'mission-control-ui',
        'job_id': r['job_id'],
        'job_name': r['job_name'],
        'created_at': iso(r['created_at']),
        'metadata': meta,
    }


def list_agent_activity(agent_id=None, limit=200):
    con = ensure_agent_activity_tables()
    if agent_id:
        rows = con.execute('SELECT * FROM agent_activity WHERE agent_id=? ORDER BY created_at DESC LIMIT ?', (agent_id, limit)).fetchall()
    else:
        rows = con.execute('SELECT * FROM agent_activity ORDER BY created_at DESC LIMIT ?', (limit,)).fetchall()
    out = [activity_row(r) for r in rows]
    con.close()
    return out


