def ensure_agent_registry_file():
    if AGENT_REGISTRY_PATH.exists():
        return
    try:
        AGENT_REGISTRY_PATH.parent.mkdir(parents=True, exist_ok=True)
        if yaml:
            AGENT_REGISTRY_PATH.write_text(yaml.safe_dump({'agents': DEFAULT_AGENT_REGISTRY, 'flows': DEFAULT_AGENT_FLOWS}, sort_keys=False, allow_unicode=True), encoding='utf-8')
        else:
            AGENT_REGISTRY_PATH.write_text(json.dumps({'agents': DEFAULT_AGENT_REGISTRY, 'flows': DEFAULT_AGENT_FLOWS}, indent=2), encoding='utf-8')
        try:
            AGENT_REGISTRY_PATH.chmod(0o600)
        except Exception:
            pass
    except Exception:
        pass


def load_agent_registry():
    ensure_agent_registry_file()
    if AGENT_REGISTRY_PATH.exists():
        try:
            raw = AGENT_REGISTRY_PATH.read_text(errors='replace')
            if yaml:
                data = yaml.safe_load(raw) or {}
            else:
                data = json.loads(raw)
            agents = data.get('agents') if isinstance(data, dict) else None
            flows = data.get('flows') if isinstance(data, dict) else None
            if isinstance(agents, list):
                return {'agents': agents, 'flows': flows if isinstance(flows, list) else DEFAULT_AGENT_FLOWS}
        except Exception:
            pass
    return {'agents': DEFAULT_AGENT_REGISTRY, 'flows': DEFAULT_AGENT_FLOWS}


def save_agent_registry(registry):
    AGENT_REGISTRY_PATH.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        'agents': registry.get('agents') or [],
        'flows': registry.get('flows') or DEFAULT_AGENT_FLOWS,
    }
    if yaml:
        AGENT_REGISTRY_PATH.write_text(yaml.safe_dump(payload, sort_keys=False, allow_unicode=True), encoding='utf-8')
    else:
        AGENT_REGISTRY_PATH.write_text(json.dumps(payload, indent=2, ensure_ascii=False), encoding='utf-8')
    try:
        AGENT_REGISTRY_PATH.chmod(0o600)
    except Exception:
        pass


def goal_slug(text, prefix='goal'):
    base = safe_id(text or prefix).lower() if 'safe_id' in globals() else re.sub(r'[^a-zA-Z0-9_.-]+', '-', (text or prefix)).strip('-').lower()[:80]
    return (base or prefix)[:64]


