def browser_session_detail(session_id, headers=None):
    payload = browser_sessions_payload(headers)
    for session in payload.get('sessions', []):
        if session.get('id') == session_id:
            return session, 200
    return {'error': 'browser session not found'}, 404


def stop_browser_session(session_id):
    session_id = safe_id(session_id)
    controlled = append_browser_control_event(session_id, 'stop', 'Operator stop requested', 'Mission Control operator requested that the browser runtime stop this session.', 'stopped')
    if controlled:
        return {'ok': True, 'id': session_id, 'status': 'stopped'}, 200
    if session_id != 'browser-visibility-simulated':
        return {'ok': False, 'id': session_id, 'status': 'not_found', 'error': 'browser session not found'}, 404
    return {'ok': True, 'id': session_id, 'status': 'stopped'}, 200


def takeover_browser_session(session_id):
    session_id = safe_id(session_id)
    controlled = append_browser_control_event(session_id, 'takeover', 'Operator takeover requested', 'Mission Control operator requested takeover/control of this browser runtime session.', 'blocked')
    if controlled:
        return {
            'ok': True,
            'id': session_id,
            'status': 'takeover_ready',
            'instruction': 'Operator takeover requested. Pause agent browser actions and wait for human control/approval.',
        }, 200
    if session_id != 'browser-visibility-simulated':
        return {'ok': False, 'id': session_id, 'status': 'not_found', 'error': 'browser session not found'}, 404
    return {
        'ok': True,
        'id': session_id,
        'status': 'takeover_ready',
        'instruction': 'Operator takeover requested. Pause agent browser actions and wait for human control/approval.',
    }, 200


