def normalize_research_lane(item, index):
    item = item if isinstance(item, dict) else {'title': str(item)}
    title = str(item.get('title') or item.get('label') or f'Research lane {index + 1}').strip()[:140]
    lane_id = safe_id(item.get('id') or title or f'lane-{index + 1}') or f'lane-{index + 1}'
    agent_id = safe_id(item.get('agentId') or item.get('agent_id') or item.get('agent') or 'melkizac') or 'melkizac'
    agent_name = str(item.get('agentName') or item.get('agent_name') or agent_id).strip()[:100]
    focus = str(item.get('focus') or item.get('objective') or f'Complete the {title} lane and attach evidence for synthesis.').strip()[:900]
    requires_approval = bool(item.get('requiresApproval') or item.get('requires_approval'))
    return {'id': lane_id, 'title': title, 'agentId': agent_id, 'agentName': agent_name, 'focus': focus, 'requiresApproval': requires_approval}


def normalize_research_source(item, index, owner_lane_id=''):
    item = item if isinstance(item, dict) else {'label': str(item)}
    label = str(item.get('label') or item.get('title') or f'Research source {index + 1}').strip()[:160]
    source_id = safe_id(item.get('id') or label or f'source-{index + 1}') or f'source-{index + 1}'
    return {
        'id': source_id,
        'label': label,
        'kind': str(item.get('kind') or 'web')[:40],
        'status': 'queued',
        'url': item.get('url'),
        'ownerLaneId': safe_id(item.get('ownerLaneId') or item.get('owner_lane_id') or owner_lane_id) or None,
        'confidence': 'medium',
        'notes': str(item.get('notes') or item.get('description') or 'Queued for review and citation tracking.')[:700],
    }


def create_research_run(payload, headers=None, identity=None):
    title = str(payload.get('title') or payload.get('name') or '').strip()[:160]
    if not title:
        return {'ok': False, 'error': 'title required'}, 400
    raw_lanes = payload.get('lanes') if isinstance(payload.get('lanes'), list) else []
    if not raw_lanes:
        return {'ok': False, 'error': 'At least one research lane is required.'}, 400
    lanes = [normalize_research_lane(item, idx) for idx, item in enumerate(raw_lanes)]
    if not lanes:
        return {'ok': False, 'error': 'At least one research lane is required.'}, 400
    raw_sources = payload.get('sources') if isinstance(payload.get('sources'), list) else []
    sources = [normalize_research_source(item, idx, lanes[min(idx, len(lanes)-1)]['id'] if lanes else '') for idx, item in enumerate(raw_sources)]
    if not sources:
        sources = [normalize_research_source(item, idx, lanes[min(idx, len(lanes)-1)]['id']) for idx, item in enumerate(research_source_templates()[:max(1, min(3, len(lanes)))])]
    project_id = safe_id(payload.get('projectId') or payload.get('project_id') or 'research-runs') or 'research-runs'
    objective = str(payload.get('objective') or payload.get('summary') or f'Wide research run for {title}.').strip()[:1600]
    now_iso = iso(time.time())
    run_id = safe_id(payload.get('id') or f"research-{int(time.time())}-{title[:32]}")
    parent_result = {
        'status': 'draft',
        'summary': f'Research run created with {len(lanes)} parallel lanes and {len(sources)} tracked source groups. Synthesis evidence will roll up here as lane tasks complete.',
        'artifacts': [{'id': f'{run_id}-brief', 'kind': 'report', 'title': 'Research run brief', 'summary': objective, 'createdAt': now_iso, 'createdBy': 'research-runs'}],
        'evidence': [{'id': f'{run_id}-source-plan', 'kind': 'source', 'title': 'Source coverage plan', 'summary': ', '.join(s['label'] for s in sources[:6]), 'source': 'Research Runs', 'createdAt': now_iso, 'confidence': 'medium'}],
        'approval_gates': [{'id': f'{run_id}-browser-approval', 'title': 'Browser/action approval gate', 'risk': 'approval-required', 'status': 'pending' if any(l.get('requiresApproval') for l in lanes) or any(s.get('kind') == 'browser' for s in sources) else 'not-required', 'reason': 'Submit/post/send/purchase and account-sensitive browser actions remain approval-gated.', 'requestedBy': 'research-runs'}],
        'next_actions': ['Monitor lane tasks on the Task Board', 'Review source coverage gaps', 'Synthesize lane evidence before publishing, sending, or submitting anything externally'],
    }
    parent_payload = {
        'id': run_id,
        'title': title,
        'body': 'Wide research run parent task.\n\nObjective:\n' + objective + '\n\nLanes:\n' + '\n'.join(f"- {lane['title']} → {lane['agentName']}: {lane['focus']}" for lane in lanes) + '\n\nSources:\n' + '\n'.join(f"- {s['label']} ({s['kind']})" for s in sources),
        'assignee': 'Melkizac',
        'status': 'running',
        'priority': 45,
        'tenant': project_id,
        'project_id': project_id,
        'created_by': 'research-runs',
        'result': parent_result,
        'workflow_template_id': 'wide-research-run',
        'current_step_key': 'research-run-parent',
    }
    parent, parent_status = create_task(parent_payload)
    if parent_status >= 400:
        return parent, parent_status
    parent_id = parent['task']['id']
    tracked_ids = [parent_id]
    lane_payloads = []
    for idx, lane in enumerate(lanes):
        lane_sources = [s for s in sources if not s.get('ownerLaneId') or s.get('ownerLaneId') == lane['id']]
        if not lane_sources and sources:
            lane_sources = [sources[idx % len(sources)]]
        lane_task_id = safe_id(f'{parent_id}-{lane["id"]}')
        lane_result = {
            'status': 'draft',
            'summary': f"Research lane task for {lane['title']}. Attach citations, screenshots/link evidence, confidence notes, blockers, and source coverage updates before synthesis.",
            'artifacts': [{'id': f'{lane_task_id}-brief', 'kind': 'note', 'title': f"{lane['title']} lane brief", 'summary': lane['focus'], 'createdAt': now_iso, 'createdBy': 'research-runs'}],
            'evidence': [{'id': f'{lane_task_id}-sources', 'kind': 'source', 'title': 'Assigned source coverage', 'summary': ', '.join(s['label'] for s in lane_sources) or 'Source coverage to be attached by the lane agent.', 'source': 'Research Runs', 'createdAt': now_iso, 'confidence': 'medium'}],
            'approval_gates': [{'id': f'{lane_task_id}-approval', 'title': 'Lane approval gate', 'risk': 'approval-required' if lane.get('requiresApproval') else 'safe', 'status': 'pending' if lane.get('requiresApproval') else 'not-required', 'reason': 'Human approval is required before submit/post/send/purchase or account-sensitive browser actions.' if lane.get('requiresApproval') else 'No external action approval required for research-only review.', 'requestedBy': lane['agentName']}],
            'next_actions': ['Review assigned sources', 'Attach citations/screenshots/link evidence', 'Synthesize lane evidence', 'Synthesize lane evidence for the parent research run'],
        }
        lane_task = create_task({
            'id': lane_task_id,
            'title': f"{title} · {lane['title']}",
            'body': f"Research lane task.\n\nParent run: {title}\nLane focus: {lane['focus']}\n\nAssigned sources:\n" + '\n'.join(f"- {s['label']} ({s['kind']}): {s.get('notes') or ''}" for s in lane_sources),
            'assignee': lane['agentId'],
            'status': 'blocked' if lane.get('requiresApproval') else 'queued',
            'priority': 42 if lane.get('requiresApproval') else 35,
            'tenant': project_id,
            'project_id': project_id,
            'created_by': 'research-runs',
            'result': lane_result,
            'workflow_template_id': 'wide-research-run-lane',
            'current_step_key': lane['id'],
        })
        if lane_task[1] >= 400:
            return lane_task
        tracked_ids.append(lane_task_id)
        lane_payloads.append({**lane, 'taskId': lane_task_id, 'status': 'blocked' if lane.get('requiresApproval') else 'queued', 'currentStep': 'Task created and waiting for lane execution.', 'progress': 0, 'sourcesReviewed': 0, 'evidenceCount': 1, 'confidence': 'medium', 'blocker': 'Approval required before browser submit/post/send/purchase action.' if lane.get('requiresApproval') else None, 'updatedAt': now_iso})
    con = ensure_kanban_tables()
    try:
        for child_id in tracked_ids[1:]:
            con.execute('INSERT OR IGNORE INTO task_links(parent_id, child_id) VALUES (?, ?)', (parent_id, child_id))
            con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)', (child_id, None, 'research_run_linked', json.dumps({'parent_id': parent_id, 'run_id': run_id}), int(time.time())))
        con.execute('INSERT INTO task_events(task_id,run_id,kind,payload,created_at) VALUES (?,?,?,?,?)', (parent_id, None, 'research_run_created', json.dumps({'run_id': run_id, 'tracked_task_ids': tracked_ids, 'lane_count': len(lanes), 'source_count': len(sources)}), int(time.time())))
        con.commit()
    finally:
        con.close()
    run = {
        'id': run_id,
        'taskId': parent_id,
        'taskUrl': mission_control_action_link(headers, 'board', task=parent_id),
        'trackedTaskIds': tracked_ids,
        'title': title,
        'status': 'running',
        'summary': objective,
        'owner': 'Melkizac',
        'risk': 'approval-required' if any(l.get('requiresApproval') for l in lanes) else 'safe',
        'startedAt': now_iso,
        'updatedAt': now_iso,
        'lanes': lane_payloads,
        'sourceCoverage': sources,
        'synthesis': {'status': 'drafting', 'progress': 5, 'leadAgent': 'Melkizac', 'openQuestions': ['Which lane has enough evidence for synthesis?', 'Are any browser/form actions blocked on human approval?'], 'recommendation': 'Collect lane evidence before publishing, sending, submitting, or making an external-facing recommendation.', 'updatedAt': now_iso},
        'evidence': parent_result['evidence'],
        'finalArtifact': {'id': f'{run_id}-final-synthesis', 'kind': 'report', 'title': 'Final synthesis / recommendation evidence', 'summary': 'Final synthesis will roll up lane citations, screenshots, source coverage, confidence notes, and operator decisions.', 'createdAt': now_iso},
        'nextActions': parent_result['next_actions'],
    }
    return {'ok': True, 'run': run, 'task': parent['task'], 'trackedTaskIds': tracked_ids, 'taskUrl': run['taskUrl']}, 201


def research_run_from_task(task):
    details = task.get('result_details') or {}
    child_ids = task.get('children') or []
    now_iso = task.get('updated_at') or task.get('created_at') or iso(time.time())
    lanes = []
    for child_id in child_ids:
        lanes.append({'id': safe_id(child_id), 'taskId': child_id, 'agentId': '', 'agentName': 'Lane task', 'title': child_id, 'status': 'queued', 'focus': 'Open the linked task for lane details.', 'currentStep': 'Tracked task created.', 'progress': 0, 'sourcesReviewed': 0, 'evidenceCount': 0, 'confidence': 'medium', 'blocker': None, 'updatedAt': now_iso})
    return {
        'id': task.get('id'),
        'taskId': task.get('id'),
        'taskUrl': mission_control_action_link(None, 'board', task=task.get('id')),
        'trackedTaskIds': [task.get('id')] + child_ids,
        'title': task.get('title'),
        'status': task.get('status'),
        'summary': details.get('summary') or task.get('body') or '',
        'owner': task.get('assignee') or 'Melkizac',
        'risk': 'approval-required' if task.get('status') == 'blocked' else 'safe',
        'startedAt': task.get('started_at') or task.get('created_at') or now_iso,
        'updatedAt': now_iso,
        'lanes': lanes,
        'sourceCoverage': [],
        'synthesis': {'status': 'drafting', 'progress': 5, 'leadAgent': task.get('assignee') or 'Melkizac', 'openQuestions': [], 'recommendation': 'Open tracked lane tasks to collect evidence and synthesize the recommendation.', 'updatedAt': now_iso},
        'evidence': details.get('evidence') or [],
        'finalArtifact': {'id': f"{task.get('id')}-final-synthesis", 'kind': 'report', 'title': 'Final synthesis / recommendation evidence', 'summary': 'Final synthesis is linked from the parent research task.', 'createdAt': now_iso},
        'nextActions': details.get('next_actions') or ['Open tracked tasks', 'Review lane evidence', 'Complete synthesis'],
    }


