    def task(id, title, status, assignee, result=''):
        return {'id':id,'title':title,'body':'Dummy public demo task. This does not represent live work or real data.','assignee':assignee,'status':status,'raw_status':status,'priority':70,'priority_label':'high' if status in ('blocked','running') else 'medium','created_by':'demo','created_at':now,'updated_at':now,'started_at':now if status=='running' else None,'completed_at':now if status=='done' else None,'workspace_kind':'demo','workspace_path':'demo://workspace','branch_name':None,'tenant':'demo','result':result,'session_id':None,'current_run_id':None,'workflow_template_id':None,'current_step_key':None,'skills':['demo-skill'],'model_override':None,'consecutive_failures':0,'last_failure_error':'','comments':[{'id':1,'author':'Demo Operator','body':'Synthetic audit comment for public demo mode.','created_at':now}],'events':[{'id':1,'kind':'created','payload':{'demo':True},'created_at':now,'run_id':None}],'runs':[],'children':[],'parents':[]}
