        task('demo-task-1','Audit standing task statuses','running','melkizac'),
        task('demo-task-2','Prepare operator briefing','queued','melkizac'),
        task('demo-devops-1','Verify deployment health','blocked','devops-builder','Waiting on demo approval.'),
        task('demo-content-1','Draft LinkedIn post pack','done','content-ops','Dummy content pack created.'),
