def capability_query_filters(query):
    filters = {}
    for key, value in (query or {}).items():
        if isinstance(value, list):
            filters[key] = value[0] if value else ''
        else:
            filters[key] = value
    return filters


def capability_auth_required(identity):
    if not identity:
        return {'ok': False, 'error': 'Authentication required'}, 401
    return None, None


def capability_admin_required(identity):
    auth_error, auth_status = capability_auth_required(identity)
    if auth_error:
        return auth_error, auth_status
    if not is_admin_identity(identity):
        return {'ok': False, 'error': 'Admin permission required for capability registry mutations.'}, 403
    return None, None


def capability_workspace_id(identity):
    return identity_workspace_id(identity)


def capability_record_visible_to_identity(record, identity):
    if is_admin_identity(identity):
        return True
    if not identity or not record:
        return False
    if record.get('visibility') == 'admin-only' or record.get('ownerKind') == 'admin':
        return False
    workspace_id = capability_workspace_id(identity)
    record_workspace = record.get('workspaceId')
    allowed = ((record.get('governance') or {}).get('allowedWorkspaceIds') or [])
    if record_workspace:
        return record_workspace == workspace_id
    return record.get('visibility') in ('workspace', 'assigned-agents', 'personal') and (not allowed or workspace_id in allowed)


def capability_source_id(source_type, raw_id):
    return f"{source_type}:{str(raw_id or '').strip()}"


def _capability_now():
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace('+00:00', 'Z')


def _capability_assignment_from_hub_lists(*, agents=None, automations=None, tasks=None, unit='procedure', usage_count=0):
    assigned_agents = [{'id': str(agent), 'name': str(agent), 'enabled': True, 'reason': 'Loaded by profile/channel'} for agent in (agents or []) if str(agent or '').strip()]
    assigned_routines = [{'id': str(item), 'name': str(item), 'enabled': True} for item in (automations or []) if str(item or '').strip()]
    assigned_tasks = [{'id': str(item), 'title': str(item), 'status': 'linked'} for item in (tasks or []) if str(item or '').strip()]
    return {
        'assignmentUnit': unit,
        'assignedAgents': assigned_agents,
        'assignedRoutines': assigned_routines,
        'assignedTasks': assigned_tasks,
        'suggestedAgents': [],
        'usageCount': int(usage_count or 0),
    }


def normalize_skill_capability_source(skill):
    raw_id = str(skill.get('id') or skill.get('name') or '').strip()
    now = skill.get('updated_at') or _capability_now()
    return {
        'id': capability_source_id('skill', raw_id),
        'type': 'skill',
        'name': skill.get('name') or raw_id,
        'displayName': skill.get('name') or raw_id,
        'description': skill.get('description') or '',
        'category': skill.get('category') or '',
        'tags': skill.get('tags') or [],
        'status': 'enabled' if skill.get('enabled', True) else 'disabled',
        'sourceUri': skill.get('path') or skill.get('skill_dir'),
        'sourceRef': skill.get('version') or raw_id,
        'sourceLabel': skill.get('source') or 'Skills Hub',
        'workspaceId': None,
        'runtimeId': None,
        'profileId': skill.get('profile'),
        'ownerKind': 'workspace' if skill.get('editable') else 'system',
        'visibility': 'admin-only',
        'editable': bool(skill.get('editable')),
        'enabled': bool(skill.get('enabled', True)),
        'installMethod': {'kind': 'skill-file', 'configPath': skill.get('path') or skill.get('skill_dir'), 'requiresRestart': False, 'requiredSecrets': [], 'requiredPermissions': [], 'wrapperType': 'skill'},
        'governance': {'riskLevels': ['read-only'], 'approvalStatus': 'not-required', 'approvalGateIds': [], 'policySummary': 'Imported from existing Skills Hub inventory.', 'allowedAgentClasses': ['platform', 'workspace', 'personal'], 'allowedWorkspaceIds': [], 'blockedActions': [], 'dataBoundary': 'local-only'},
        'permissions': [],
        'health': {'state': 'passing', 'checkSummary': 'SKILL.md inventory parsed', 'evidenceIds': []},
        'evidence': [{'id': f"ev-{capability_source_id('skill', raw_id)}", 'kind': 'source', 'title': 'Skills Hub record', 'summary': f"{skill.get('source') or 'Skills Hub'} · {skill.get('category') or 'uncategorized'}", 'path': skill.get('path'), 'createdAt': now, 'redacted': True}],
        'assignment': _capability_assignment_from_hub_lists(agents=skill.get('used_by_agents'), automations=skill.get('used_by_automations'), tasks=skill.get('used_by_tasks'), usage_count=skill.get('used_by_count'), unit='procedure'),
        'rollback': {'supported': True, 'disableSteps': ['Disable or remove the skill from the target profile configuration.'], 'uninstallSteps': ['Remove the SKILL.md directory after approval.'], 'restartRequired': False},
        'audit': [],
        'createdAt': now,
        'updatedAt': now,
        'createdBy': 'skills-hub',
        'updatedBy': None,
    }


def normalize_tool_capability_source(tool):
    raw_id = str(tool.get('id') or tool.get('name') or tool.get('assignmentUnit') or '').strip()
    source_type = 'mcp-server' if tool.get('kind') == 'mcp-server' else 'cli-tool'
    unit = 'mcp-server' if source_type == 'mcp-server' else 'tool'
    install_kind = 'mcp-config' if source_type == 'mcp-server' else 'cli-registry'
    now = tool.get('updated_at') or tool.get('created_at') or _capability_now()
    tool_count = tool.get('toolCount')
    sample_tools = tool.get('sampleTools') or []
