def owned_app_capability_records():
    return [networth_tracker_owned_app_capability()]


def capability_hub_source_records():
    records = []
    records.extend(owned_app_capability_records())
    try:
        for skill in list_skill_hub({}).get('skills', []):
            if isinstance(skill, dict):
                records.append(normalize_skill_capability_source(skill))
    except Exception:
        pass
    try:
        for tool in installed_tool_records():
            if isinstance(tool, dict):
                records.append(normalize_tool_capability_source(tool))
    except Exception:
        pass
    try:
        for plugin in list_plugin_hub({}).get('plugins', []):
            if isinstance(plugin, dict):
                records.append(normalize_plugin_capability_source(plugin))
    except Exception:
        pass
    return records


def capability_record_matches_filters(record, filters):
    filters = filters or {}
    q = str(filters.get('q') or '').strip().lower()
    source_type = str(filters.get('type') or '').strip()
    if source_type in {'owned-app', 'ownedapp', 'first-party-app', 'first_party_app'}:
        source_type = 'owned_app'
    status = str(filters.get('status') or '').strip()
    risk = str(filters.get('risk') or '').strip()
    workspace = str(filters.get('workspace') or filters.get('workspace_id') or '').strip()
    health = str(filters.get('health') or '').strip()
    category = str(filters.get('category') or '').strip()
    assigned = str(filters.get('assigned') or '').strip().lower()
    if q and q not in text_blob(record.get('id'), record.get('name'), record.get('displayName'), record.get('description'), record.get('sourceLabel')).lower():
        return False
    if source_type and record.get('type') != source_type:
        return False
    if category and (record.get('category') or '') != category:
        return False
    if status and record.get('status') != status:
        return False
    if workspace and (record.get('workspaceId') or '') != workspace:
        return False
    if health and (record.get('health') or {}).get('state') != health:
        return False
    if risk and risk not in ((record.get('governance') or {}).get('riskLevels') or []):
        return False
    assignment_count = capability_assignment_count(record.get('assignment'))
    if assigned in {'true', '1', 'yes'} and assignment_count == 0:
        return False
    if assigned in {'false', '0', 'no'} and assignment_count > 0:
        return False
    return True


def merge_capability_hub_records(payload, filters=None):
    capabilities = list(payload.get('capabilities') or [])
    existing_ids = {record.get('id') for record in capabilities if record.get('id')}
    for record in capability_hub_source_records():
        if record.get('id') in existing_ids:
            continue
        if not capability_record_matches_filters(record, filters):
            continue
        capabilities.append(record)
        existing_ids.add(record.get('id'))
    return {**payload, 'capabilities': capabilities}


def capability_visible_payload(payload, identity):
    records = [capability_record_with_policy_evidence(r) for r in payload.get('capabilities', []) if capability_record_visible_to_identity(r, identity)]
    return {
        **payload,
        'capabilities': records,
        'summary': {
            'total': len(records),
            'enabled': sum(1 for r in records if r.get('enabled')),
            'assigned': sum(1 for r in records if capability_assignment_count(r.get('assignment')) > 0),
            'awaitingApproval': sum(1 for r in records if r.get('status') == 'awaiting-approval' or (r.get('governance') or {}).get('approvalStatus') == 'pending'),
            'degraded': sum(1 for r in records if r.get('status') in {'degraded', 'broken'} or (r.get('health') or {}).get('state') in {'warning', 'failing', 'stale'}),
            'requiringSecrets': sum(1 for r in records if bool(((r.get('installMethod') or {}).get('requiredSecrets')) or 'requires-secret' in ((r.get('governance') or {}).get('riskLevels') or []) or 'secret-access' in ((r.get('governance') or {}).get('riskLevels') or []))),
        },
    }


def capability_assignment_count(assignment):
    if not isinstance(assignment, dict):
        return 0
    return sum(len(assignment.get(key) or []) for key in ('assignedAgents', 'assignedRoutines', 'assignedTasks')) or int(assignment.get('usageCount') or 0)


def capability_registry_list_payload(query, identity):
    auth_error, auth_status = capability_auth_required(identity)
    if auth_error:
        return auth_error, auth_status
    import capability_registry
    filters = capability_query_filters(query)
    payload = capability_registry.list_capability_records(filters)
    payload = merge_capability_hub_records(payload, filters)
    payload = {**payload, 'capabilities': [r for r in (payload.get('capabilities') or []) if capability_record_matches_filters(r, filters)]}
    return capability_visible_payload(payload, identity), 200


def capability_registry_detail_payload(capability_id, identity):
    auth_error, auth_status = capability_auth_required(identity)
    if auth_error:
        return auth_error, auth_status
    import capability_registry
    payload = capability_registry.list_capability_records({'q': capability_id})
    record = next((r for r in payload.get('capabilities', []) if r.get('id') == capability_id), None)
    if not record or not capability_record_visible_to_identity(record, identity):
        return {'ok': False, 'error': 'capability not found'}, 404
    return {'ok': True, 'capability': capability_record_with_policy_evidence(record)}, 200


def capability_registry_sources_payload(query, identity):
    payload, status = capability_registry_list_payload(query, identity)
    if status != 200:
        return payload, status
    records = payload.get('capabilities', [])
    return {'ok': True, 'sources': sorted({r.get('sourceLabel') or r.get('type') for r in records if r.get('sourceLabel') or r.get('type')}), 'types': sorted({r.get('type') for r in records if r.get('type')}), 'summary': payload.get('summary', {})}, 200


def _capability_ref_for_matrix(record, source='registry', assigned=False, assignment_ref=None, assignment_scope=None):
    governance = record.get('governance') or {}
    health = record.get('health') or {}
    assignment = record.get('assignment') or {}
    return {
        'id': record.get('id'),
        'type': record.get('type'),
        'name': record.get('displayName') or record.get('name') or record.get('id'),
        'displayName': record.get('displayName') or record.get('name') or record.get('id'),
        'description': record.get('description') or '',
        'source': source,
        'sourceLabel': record.get('sourceLabel') or source,
        'status': record.get('status') or ('enabled' if record.get('enabled') else 'registered'),
        'enabled': bool(record.get('enabled', True)),
        'assigned': bool(assigned),
        'inherited': False,
        'assignmentScope': assignment_scope or ('assigned' if assigned else 'available'),
        'assignmentRef': assignment_ref or {},
        'assignmentUnit': assignment.get('assignmentUnit') or (record.get('installMethod') or {}).get('wrapperType') or record.get('type'),
        'riskLevels': governance.get('riskLevels') or [],
        'approvalRequired': bool(governance.get('approvalRequired')),
        'approvalStatus': governance.get('approvalStatus') or 'not-required',
        'approvalAuthority': governance.get('approvalAuthority'),
        'policyGate': governance.get('policyGate'),
        'actionableBlocker': governance.get('actionableBlocker'),
        'healthState': health.get('state') or 'unknown',
        'healthSummary': health.get('checkSummary') or '',
    }


